// Virtualize every non-trivial column. Idle keeps a tight window; drag widens only
// the active/hovered column. Other fat columns stay virtualized + static cards.
const COLUMN_LIST_GAP_PX = 9;
const COLUMN_VIRTUAL_THRESHOLD = 1; // always window long columns (Inbox, Contato, …)
const FUNNEL_CARD_ESTIMATE_PX = 152;
const LICITACAO_CARD_ESTIMATE_PX = 168;

/** Track vertical overflow + expose up/down scroll helpers (replaces scrollbars with chevrons). */
function useVerticalScrollArrows(scrollRef, remeasureKey = null) {
  const [canScrollUp, setCanScrollUp] = useState(false);
  const [canScrollDown, setCanScrollDown] = useState(false);
  const [hasOverflow, setHasOverflow] = useState(false);

  const updateMetrics = useCallback(() => {
    const el = scrollRef.current;
    if (!el) {
      setCanScrollUp(false);
      setCanScrollDown(false);
      setHasOverflow(false);
      return;
    }
    const max = el.scrollHeight - el.clientHeight;
    const overflow = max > 2;
    setHasOverflow(overflow);
    setCanScrollUp(overflow && el.scrollTop > 2);
    setCanScrollDown(overflow && el.scrollTop < max - 2);
  }, [scrollRef]);

  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return undefined;

    updateMetrics();
    el.addEventListener('scroll', updateMetrics, { passive: true });
    const ro = typeof ResizeObserver !== 'undefined' ? new ResizeObserver(updateMetrics) : null;
    ro?.observe(el);
    // Content size changes (virtualized rows, list growth) also need a remeasure.
    const mo = typeof MutationObserver !== 'undefined'
      ? new MutationObserver(() => {
          window.requestAnimationFrame(updateMetrics);
        })
      : null;
    mo?.observe(el, { childList: true, subtree: true, characterData: true });

    return () => {
      el.removeEventListener('scroll', updateMetrics);
      ro?.disconnect();
      mo?.disconnect();
    };
  }, [scrollRef, updateMetrics, remeasureKey]);

  const scrollByDir = useCallback((direction) => {
    const el = scrollRef.current;
    if (!el) return;
    const delta = Math.max(el.clientHeight * 0.78, 140) * direction;
    el.scrollBy({ top: delta, behavior: 'smooth' });
  }, [scrollRef]);

  return { canScrollUp, canScrollDown, hasOverflow, scrollByDir, updateMetrics };
}

/**
 * Custom horizontal board scroller — pure track + thumb (no native OS scrollbar).
 * Avoids Windows/Chromium end-cap arrows and keeps perfect vertical alignment
 * with the circular edge buttons.
 */
const KANBAN_HSCROLL_THUMB_MIN_PX = 48;

const KanbanHScrollBar = memo(function KanbanHScrollBar({
  scrollWidth,
  clientWidth,
  scrollLeft,
  onScrollLeft,
}) {
  const trackRef = useRef(null);
  const dragRef = useRef(null);
  const [trackWidth, setTrackWidth] = useState(0);

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return undefined;
    const measure = () => setTrackWidth(track.clientWidth);
    measure();
    if (typeof ResizeObserver === 'undefined') {
      window.addEventListener('resize', measure);
      return () => window.removeEventListener('resize', measure);
    }
    const ro = new ResizeObserver(measure);
    ro.observe(track);
    return () => ro.disconnect();
  }, []);

  const maxScroll = Math.max(0, scrollWidth - clientWidth);
  const ratio = scrollWidth > 0 ? clientWidth / scrollWidth : 1;
  const thumbW = trackWidth > 0
    ? Math.min(trackWidth, Math.max(trackWidth * ratio, KANBAN_HSCROLL_THUMB_MIN_PX))
    : KANBAN_HSCROLL_THUMB_MIN_PX;
  const travel = Math.max(trackWidth - thumbW, 1);
  const thumbLeft = maxScroll > 0 ? (scrollLeft / maxScroll) * travel : 0;

  const setFromClientX = useCallback(
    (clientX, { centerThumb = true } = {}) => {
      const track = trackRef.current;
      if (!track || maxScroll <= 0) return;
      const rect = track.getBoundingClientRect();
      if (rect.width <= 0) return;
      const localThumbW = Math.min(
        rect.width,
        Math.max(rect.width * (clientWidth / Math.max(scrollWidth, 1)), KANBAN_HSCROLL_THUMB_MIN_PX)
      );
      const localTravel = Math.max(rect.width - localThumbW, 1);
      let x = clientX - rect.left;
      if (centerThumb) x -= localThumbW / 2;
      const next = Math.max(0, Math.min(maxScroll, (x / localTravel) * maxScroll));
      onScrollLeft(next);
    },
    [clientWidth, maxScroll, onScrollLeft, scrollWidth]
  );

  const onTrackPointerDown = useCallback(
    (event) => {
      if (event.target.closest?.('.kanban-hscroll-thumb')) return;
      event.preventDefault();
      setFromClientX(event.clientX, { centerThumb: true });
    },
    [setFromClientX]
  );

  const onThumbPointerDown = useCallback(
    (event) => {
      event.preventDefault();
      event.stopPropagation();
      const track = trackRef.current;
      if (!track || maxScroll <= 0) return;
      const rect = track.getBoundingClientRect();
      const localThumbW = Math.min(
        rect.width,
        Math.max(rect.width * (clientWidth / Math.max(scrollWidth, 1)), KANBAN_HSCROLL_THUMB_MIN_PX)
      );
      const localTravel = Math.max(rect.width - localThumbW, 1);
      dragRef.current = {
        pointerId: event.pointerId,
        startX: event.clientX,
        startLeft: scrollLeft,
        travel: localTravel,
        maxScroll,
      };
      event.currentTarget.setPointerCapture?.(event.pointerId);
    },
    [clientWidth, maxScroll, scrollLeft, scrollWidth]
  );

  const onThumbPointerMove = useCallback(
    (event) => {
      const drag = dragRef.current;
      if (!drag || drag.pointerId !== event.pointerId) return;
      const dx = event.clientX - drag.startX;
      const next = Math.max(
        0,
        Math.min(drag.maxScroll, drag.startLeft + (dx / drag.travel) * drag.maxScroll)
      );
      onScrollLeft(next);
    },
    [onScrollLeft]
  );

  const endDrag = useCallback((event) => {
    const drag = dragRef.current;
    if (!drag || (event && drag.pointerId !== event.pointerId)) return;
    dragRef.current = null;
  }, []);

  return (
    <div
      ref={trackRef}
      className="kanban-hscroll-track"
      role="scrollbar"
      aria-orientation="horizontal"
      aria-valuemin={0}
      aria-valuemax={Math.round(maxScroll)}
      aria-valuenow={Math.round(scrollLeft)}
      onPointerDown={onTrackPointerDown}
    >
      <div
        className="kanban-hscroll-thumb"
        style={{ width: `${thumbW}px`, transform: `translate3d(${thumbLeft}px, 0, 0)` }}
        onPointerDown={onThumbPointerDown}
        onPointerMove={onThumbPointerMove}
        onPointerUp={endDrag}
        onPointerCancel={endDrag}
      />
    </div>
  );
});

/** Compact floating scroll control — replaces old full-width chevron bars. */
const scrollEdgeBtnClass =
  'scroll-edge-btn pointer-events-auto inline-flex h-7 w-7 items-center justify-center rounded-full border border-line/90 bg-surf/95 text-muted shadow-[0_6px_16px_rgba(0,0,0,.4)] backdrop-blur-md transition duration-150 hover:border-primary/45 hover:bg-surf2 hover:text-ink focus:outline-none focus-visible:ring-2 focus-visible:ring-primary/35 disabled:pointer-events-none disabled:opacity-0';

const scrollEdgeRailTopClass =
  'pointer-events-none absolute inset-x-0 top-0 z-10 flex justify-center bg-gradient-to-b from-[#0a0d14]/90 via-[#0a0d14]/45 to-transparent pt-1.5 pb-7';

const scrollEdgeRailBottomClass =
  'pointer-events-none absolute inset-x-0 bottom-0 z-10 flex justify-center bg-gradient-to-t from-[#0a0d14]/90 via-[#0a0d14]/45 to-transparent pb-1.5 pt-7';

const VerticalScrollArrows = memo(function VerticalScrollArrows({
  children,
  className = '',
  contentClassName = '',
  contentRef = null,
  style = undefined,
  /** Extra key to remeasure overflow (e.g. itemCount / role). */
  remeasureKey = null,
  contentRole = undefined,
  contentAriaLabel = undefined,
  contentAriaMultiselectable = undefined,
}) {
  const innerRef = useRef(null);
  const setRefs = useCallback((node) => {
    innerRef.current = node;
    if (typeof contentRef === 'function') contentRef(node);
    else if (contentRef) contentRef.current = node;
  }, [contentRef]);

  const { canScrollUp, canScrollDown, hasOverflow, scrollByDir } = useVerticalScrollArrows(
    innerRef,
    remeasureKey
  );

  return (
    <div className={`relative flex min-h-0 flex-col overflow-hidden ${className}`} style={style}>
      {hasOverflow && canScrollUp && (
        <div className={scrollEdgeRailTopClass}>
          <button
            type="button"
            aria-label="Rolar para cima"
            onClick={() => scrollByDir(-1)}
            className={scrollEdgeBtnClass}
          >
            <ChevronUpIcon className="h-3.5 w-3.5" strokeWidth={2.25} />
          </button>
        </div>
      )}
      <div
        ref={setRefs}
        role={contentRole}
        aria-label={contentAriaLabel}
        aria-multiselectable={contentAriaMultiselectable}
        className={`min-h-0 flex-1 overflow-y-auto overflow-x-hidden overscroll-contain scrollbar-none ${contentClassName}`}
      >
        {children}
      </div>
      {hasOverflow && canScrollDown && (
        <div className={scrollEdgeRailBottomClass}>
          <button
            type="button"
            aria-label="Rolar para baixo"
            onClick={() => scrollByDir(1)}
            className={scrollEdgeBtnClass}
          >
            <ChevronDownIcon className="h-3.5 w-3.5" strokeWidth={2.25} />
          </button>
        </div>
      )}
    </div>
  );
});

const DualRange = memo(function DualRange({
  min = 0,
  max,
  step = 1,
  value,
  onChange,
  formatValue,
  minLabel = 'Mínimo',
  maxLabel = 'Máximo',
}) {
  const storedMin = Number(value?.[0]) || 0;
  const storedMax = Number(value?.[1]) || 0;
  const effectiveMax = storedMax > 0 ? Math.min(storedMax, max) : max;
  const effectiveMin = Math.max(min, Math.min(storedMin, effectiveMax));
  const span = Math.max(max - min, 1);
  const minPercent = ((effectiveMin - min) / span) * 100;
  const maxPercent = ((effectiveMax - min) / span) * 100;
  const describeMin = effectiveMin > min ? formatValue(effectiveMin) : 'Sem mínimo';
  const describeMax = storedMax > 0 ? formatValue(effectiveMax) : 'Sem máximo';

  return (
    <div className="space-y-3">
      <div className="grid grid-cols-2 gap-3 text-xs">
        <div className="min-w-0">
          <span className="block text-muted2">{minLabel}</span>
          <span className="mt-0.5 block truncate font-medium tabular-nums text-ink">{describeMin}</span>
        </div>
        <div className="min-w-0 text-right">
          <span className="block text-muted2">{maxLabel}</span>
          <span className="mt-0.5 block truncate font-medium tabular-nums text-ink">{describeMax}</span>
        </div>
      </div>
      <div className="dual-range relative h-5" style={{ '--range-start': `${minPercent}%`, '--range-end': `${maxPercent}%` }}>
        <div className="absolute inset-x-0 top-1/2 h-1 -translate-y-1/2 rounded-full bg-line" aria-hidden />
        <div
          className="absolute top-1/2 h-1 -translate-y-1/2 rounded-full bg-primary"
          style={{ left: `${minPercent}%`, right: `${100 - maxPercent}%` }}
          aria-hidden
        />
        <input
          type="range"
          min={min}
          max={max}
          step={step}
          value={effectiveMin}
          onChange={(event) => onChange([Math.min(Number(event.target.value), effectiveMax), storedMax])}
          className={`dual-range__input ${effectiveMin >= effectiveMax ? 'z-30' : 'z-20'}`}
          aria-label={minLabel}
          aria-valuetext={describeMin}
        />
        <input
          type="range"
          min={min}
          max={max}
          step={step}
          value={effectiveMax}
          onChange={(event) => {
            const next = Number(event.target.value);
            const nextStoredMax = next >= max ? 0 : next;
            onChange([Math.min(effectiveMin, next), nextStoredMax]);
          }}
          className="dual-range__input z-10"
          aria-label={maxLabel}
          aria-valuetext={describeMax}
        />
      </div>
    </div>
  );
});

const RadarTrendsPage = memo(function RadarTrendsPage({
  trendsIntel,
  loading,
  refreshing,
  error,
  onReload,
  onSearchProfile,
}) {
  const trends = trendsIntel?.trends || [];
  const suggestions = trendsIntel?.intel?.suggestions || [];
  const trendsSource = String(trendsIntel?.meta?.source || '');
  const isNewsMode = /news_sector|google_news|rss/i.test(trendsSource);
  const isRelatedMode = /pytrends|related/i.test(trendsSource);
  const itemLink = (item) => {
    const fromNews = (item.news || []).find((news) => news?.url)?.url;
    return fromNews || item.url || item.link || null;
  };
  const itemSource = (item) => {
    const fromNews = (item.news || []).find((news) => news?.source)?.source;
    return fromNews || item.source || '';
  };
  const itemImage = (item) => {
    const fromNews = (item.news || []).find((news) => news?.picture || news?.image || news?.thumbnail);
    return item.picture || item.image || item.thumbnail || fromNews?.picture || fromNews?.image || fromNews?.thumbnail || null;
  };
  const cleanTitle = (item) => {
    let title = String(item.title || '').trim();
    const source = itemSource(item);
    if (source && title.toLowerCase().endsWith(` - ${source.toLowerCase()}`)) {
      title = title.slice(0, title.length - source.length - 3).trim();
    }
    return title;
  };
  const formatNewsDate = (value) => {
    if (!value) return '';
    try {
      return new Date(value).toLocaleString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
      });
    } catch {
      return '';
    }
  };
  const prioritizedTrends = [...trends].sort((a, b) => Number(Boolean(itemImage(b))) - Number(Boolean(itemImage(a))));
  const showNewsCards = isNewsMode || prioritizedTrends.some((item) => itemImage(item));

  return (
    <div className="mt-5 space-y-4">
      <header className="flex flex-col gap-3 border-b border-line pb-4 sm:flex-row sm:items-end sm:justify-between">
        <div className="min-w-0">
          <div className="flex flex-wrap items-center gap-2">
            <h2 className="text-lg font-semibold text-ink">Radar Trends</h2>
            <span className="rounded-full border border-line bg-bg2 px-2 py-0.5 font-mono text-[10px] font-semibold text-muted">
              BR · drones enterprise
            </span>
            {trendsIntel?.day && <span className="font-mono text-[10px] text-muted">{trendsIntel.day}</span>}
            {trendsIntel?.cached && (
              <span className="rounded-full bg-status-success/10 px-2 py-0.5 font-mono text-[10px] font-semibold text-status-success">
                cache do dia
              </span>
            )}
          </div>
          <p className="mt-1 max-w-3xl text-xs leading-relaxed text-muted">
            Sinais do mercado brasileiro e perfis de prospecção gerados uma vez por dia para orientar buscas na base RFB.
          </p>
        </div>
        <button
          type="button"
          disabled={refreshing || loading}
          onClick={onReload}
          className={`${btnSecondary} w-full shrink-0 sm:w-auto`}
          title="Recarrega o resultado cacheado do dia"
        >
          <ArrowPathIcon className={`h-4 w-4 ${refreshing || loading ? 'animate-spin' : ''}`} />
          {refreshing || loading ? 'Carregando…' : 'Recarregar'}
        </button>
      </header>

      {error && (
        <div className="rounded-[12px] border border-status-danger/30 bg-status-danger/10 px-3 py-2 text-xs text-status-danger" role="alert">
          {error}
        </div>
      )}

      {loading && !trendsIntel ? (
        <div className="space-y-4" aria-label="Carregando Radar Trends">
          <div className="h-20 animate-pulse rounded-[12px] bg-bg2" />
          <div className="grid gap-3 md:grid-cols-2 xl:grid-cols-3">
            {[1, 2, 3].map((item) => <div key={item} className="h-56 animate-pulse rounded-[12px] bg-bg2" />)}
          </div>
        </div>
      ) : (
        <>
          {(trendsIntel?.intel?.opportunity_day || trendsIntel?.intel?.summary) && (
            <section className="rounded-[12px] border border-primary/25 bg-primary/[0.05] px-4 py-3">
              <h3 className="text-sm font-semibold text-ink">Leitura do dia</h3>
              <p className="mt-1 max-w-4xl text-xs leading-relaxed text-muted">
                {trendsIntel?.intel?.opportunity_day || trendsIntel?.intel?.summary}
              </p>
            </section>
          )}

          {prioritizedTrends.length > 0 && (
            <section>
              <div className="mb-2 flex flex-wrap items-end justify-between gap-2">
                <div>
                  <h3 className="text-sm font-semibold text-ink">
                    {isRelatedMode ? 'Correlatos do setor' : 'Notícias e sinais do mercado'}
                  </h3>
                  <p className="mt-0.5 text-[11px] text-muted">
                    {showNewsCards ? 'Conteúdos com imagem aparecem primeiro.' : 'Termos relacionados às principais frentes comerciais.'}
                  </p>
                </div>
                <span className="font-mono text-[10px] text-muted2">{prioritizedTrends.length} sinais</span>
              </div>

              {showNewsCards ? (
                <div className="grid items-stretch gap-3 md:grid-cols-2 xl:grid-cols-3">
                  {prioritizedTrends.slice(0, 12).map((item, index) => {
                    const href = itemLink(item);
                    const source = itemSource(item);
                    const picture = itemImage(item);
                    const title = cleanTitle(item);
                    const content = (
                      <>
                        {picture && (
                          <div className="aspect-[16/9] overflow-hidden bg-bg2">
                            <img
                              src={picture}
                              alt=""
                              loading="lazy"
                              referrerPolicy="no-referrer"
                              className="h-full w-full object-cover transition-transform duration-200 group-hover:scale-[1.02]"
                              onError={(event) => { event.currentTarget.parentElement.style.display = 'none'; }}
                            />
                          </div>
                        )}
                        <div className="flex min-h-0 flex-1 flex-col p-3">
                          <div className="flex items-center justify-between gap-2 font-mono text-[10px] text-muted2">
                            <span className="truncate">{source || `Sinal ${String(index + 1).padStart(2, '0')}`}</span>
                            {item.pubDate && <span className="shrink-0">{formatNewsDate(item.pubDate)}</span>}
                          </div>
                          <h4 className="mt-1.5 line-clamp-3 text-sm font-semibold leading-snug text-ink group-hover:text-primary">
                            {title}
                          </h4>
                          <span className="mt-auto pt-3 text-[11px] font-semibold text-primary">Ir para a matéria ↗</span>
                        </div>
                      </>
                    );
                    return href ? (
                      <a
                        key={`${item.title}-${index}`}
                        href={href}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="group flex min-h-[11rem] flex-col overflow-hidden rounded-[12px] border border-line bg-bg2 transition-colors hover:border-primary/40 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary/40"
                        aria-label={`${title}. Abrir matéria em nova aba`}
                      >
                        {content}
                      </a>
                    ) : (
                      <article key={`${item.title}-${index}`} className="group flex min-h-[11rem] flex-col overflow-hidden rounded-[12px] border border-line bg-bg2">
                        {content}
                      </article>
                    );
                  })}
                </div>
              ) : (
                <div className="flex flex-wrap gap-1.5">
                  {prioritizedTrends.slice(0, 18).map((item) => {
                    const href = itemLink(item);
                    const body = (
                      <>
                        {item.kind === 'rising' && <span className="font-mono text-[9px] font-semibold text-status-success">↑</span>}
                        <span className="font-medium">{item.title}</span>
                        {item.traffic && item.traffic !== 'news' && <span className="font-mono text-[10px] text-muted">{item.traffic}</span>}
                        {href && <span className="font-mono text-[9px] text-primary/70">↗</span>}
                      </>
                    );
                    const chipClass = 'inline-flex items-center gap-1.5 rounded-full border border-line bg-bg2 px-2.5 py-1 text-[11px] text-ink transition-colors hover:border-primary/40 hover:text-primary';
                    return href ? (
                      <a key={`${item.seed || ''}-${item.kind || ''}-${item.title}`} href={href} target="_blank" rel="noopener noreferrer" className={chipClass}>
                        {body}
                      </a>
                    ) : (
                      <span key={`${item.seed || ''}-${item.kind || ''}-${item.title}`} className={chipClass}>{body}</span>
                    );
                  })}
                </div>
              )}
            </section>
          )}

          <section>
            <div className="mb-2 flex flex-wrap items-end justify-between gap-2">
              <div>
                <h3 className="text-sm font-semibold text-ink">Perfis sugeridos para prospecção</h3>
                <p className="mt-0.5 text-[11px] text-muted">A busca abre com os critérios aplicados e os resultados carregados.</p>
              </div>
              {suggestions.length > 0 && <span className="font-mono text-[10px] text-muted2">{suggestions.length} perfis</span>}
            </div>
            {suggestions.length === 0 ? (
              <div className="rounded-[12px] border border-dashed border-line px-4 py-8 text-center text-xs text-muted">
                {trendsIntel?.intel?.summary || 'Nenhum perfil sugerido para hoje.'}
              </div>
            ) : (
              <div className="grid items-stretch gap-3 md:grid-cols-2 xl:grid-cols-3">
                {suggestions.map((suggestion, index) => {
                  const filters = suggestion.filters || {};
                  const porteLabel = filters.porte === '01' ? 'ME' : filters.porte === '03' ? 'EPP' : filters.porte === '05' ? 'Demais' : filters.porte;
                  const priorityClass = suggestion.priority === 'alta'
                    ? 'bg-status-success/15 text-status-success'
                    : suggestion.priority === 'baixa'
                      ? 'border border-line bg-bg2 text-muted'
                      : 'bg-primary/12 text-primary';
                  return (
                    <article key={`${suggestion.title}-${index}`} className="flex h-full flex-col rounded-[12px] border border-line bg-surf p-3">
                      <div className="flex items-start justify-between gap-2">
                        <h4 className="text-sm font-semibold text-ink">{suggestion.title}</h4>
                        {suggestion.priority && (
                          <span className={`shrink-0 rounded-full px-2 py-0.5 font-mono text-[10px] font-semibold ${priorityClass}`}>
                            {suggestion.priority}
                          </span>
                        )}
                      </div>
                      {(suggestion.company_profile || suggestion.product_fit) && (
                        <p className="mt-1 text-[11px] leading-relaxed text-muted">
                          {[suggestion.company_profile, suggestion.product_fit].filter(Boolean).join(' · ')}
                        </p>
                      )}
                      <div className="mt-2 flex flex-wrap gap-1">
                        <span className="rounded-md bg-bg2 px-1.5 py-0.5 font-mono text-[10px] text-primary">{filters.uf ? `UF ${filters.uf}` : 'Nacional'}</span>
                        {porteLabel && <span className="rounded-md bg-bg2 px-1.5 py-0.5 font-mono text-[10px] text-muted">Porte {porteLabel}</span>}
                        {(filters.capital_min > 0 || filters.capital_max > 0) && (
                          <span className="rounded-md bg-bg2 px-1.5 py-0.5 font-mono text-[10px] text-muted">
                            Capital {filters.capital_min > 0 ? `≥${Number(filters.capital_min).toLocaleString('pt-BR')}` : ''}{filters.capital_max > 0 ? ` ≤${Number(filters.capital_max).toLocaleString('pt-BR')}` : ''}
                          </span>
                        )}
                        {(filters.cnae_labels || []).slice(0, 3).map((cnae) => (
                          <span key={cnae.codigo} className="rounded-md bg-bg2 px-1.5 py-0.5 font-mono text-[10px] text-muted" title={cnae.descricao}>{cnae.codigo}</span>
                        ))}
                      </div>
                      {suggestion.rationale && <p className="mt-2 line-clamp-3 text-[11px] leading-relaxed text-muted">{suggestion.rationale}</p>}
                      <div className="mt-auto pt-3">
                        <button type="button" className={`${btnPrimary} w-full`} onClick={() => onSearchProfile(suggestion)}>
                          <MagnifyingGlassIcon className="h-4 w-4" />
                          Buscar empresas com este perfil
                        </button>
                      </div>
                    </article>
                  );
                })}
              </div>
            )}
          </section>

          {(trendsIntel?.meta?.ai?.provider || trendsIntel?.cache) && (
            <p className="border-t border-line pt-2 font-mono text-[10px] text-muted2">
              {trendsIntel?.meta?.ai?.provider && (
                <span>IA: {trendsIntel.meta.ai.provider}{trendsIntel.meta.ai.model ? ` · ${trendsIntel.meta.ai.model}` : ''}{trendsIntel.meta.ai.fallback ? ' · fallback' : ''}</span>
              )}
              {trendsIntel?.cache && trendsIntel.cache !== 'fresh' && <span>{trendsIntel?.meta?.ai?.provider ? ' · ' : ''}cache: {trendsIntel.cache}</span>}
            </p>
          )}
        </>
      )}
    </div>
  );
});

const VirtualizedColumnList = memo(function VirtualizedColumnList({
  itemIds,
  itemCount,
  estimateSize,
  isDragActiveColumn,
  isBoardDragging,
  emptyNode,
  renderItem,
  focusItemId = null,
}) {
  const parentRef = useRef(null);
  const shouldVirtualize = itemCount >= COLUMN_VIRTUAL_THRESHOLD;
  const remeasureKey = `${itemCount}:${itemIds[0] ?? ''}:${itemIds[itemIds.length - 1] ?? ''}`;
  const { canScrollUp, canScrollDown, hasOverflow, scrollByDir } = useVerticalScrollArrows(parentRef, remeasureKey);

  const estimateSizeFn = useCallback(
    () => estimateSize + COLUMN_LIST_GAP_PX,
    [estimateSize]
  );
  const getItemKey = useCallback(
    (index) => itemIds[index] ?? index,
    [itemIds]
  );

  // Idle: small overscan. Active drag column: wider for gap. Other columns while
  // board is dragging: minimal nodes (static cards, column droppable still works).
  let overscan = 4;
  if (isBoardDragging) {
    overscan = isDragActiveColumn ? 12 : 2;
  }

  const virtualizer = useVirtualizer({
    count: shouldVirtualize ? itemCount : 0,
    getScrollElement: () => parentRef.current,
    estimateSize: estimateSizeFn,
    overscan,
    getItemKey,
  });

  useEffect(() => {
    if (focusItemId == null || focusItemId === '') return undefined;
    const focusId = String(focusItemId);
    const index = itemIds.findIndex((id) => String(id) === focusId);
    if (index < 0) return undefined;

    let cancelled = false;
    let timeoutId = 0;

    const scrollToFocus = () => {
      if (cancelled) return;
      if (shouldVirtualize) {
        virtualizer.scrollToIndex(index, { align: 'center', behavior: 'smooth' });
        return;
      }
      const node = parentRef.current?.querySelector(`[data-contact-id="${focusId}"]`);
      node?.scrollIntoView({ block: 'nearest', inline: 'nearest', behavior: 'smooth' });
    };

    // Wait for filter/layout paint, then retry once — virtual rows may not exist yet.
    const frame = window.requestAnimationFrame(() => {
      scrollToFocus();
      timeoutId = window.setTimeout(scrollToFocus, 60);
    });

    return () => {
      cancelled = true;
      window.cancelAnimationFrame(frame);
      if (timeoutId) window.clearTimeout(timeoutId);
    };
  }, [focusItemId, itemIds, shouldVirtualize, virtualizer]);

  return (
    <div className="relative mt-3 flex min-h-0 flex-1 flex-col">
      {hasOverflow && canScrollUp && (
        <div className={scrollEdgeRailTopClass}>
          <button
            type="button"
            aria-label="Rolar coluna para cima"
            onClick={() => scrollByDir(-1)}
            className={scrollEdgeBtnClass}
          >
            <ChevronUpIcon className="h-3.5 w-3.5" strokeWidth={2.25} />
          </button>
        </div>
      )}
      <div
        ref={parentRef}
        className={`min-h-0 flex-1 overflow-y-auto overflow-x-hidden kanban-column-scroll scrollbar-none ${shouldVirtualize ? '' : 'flex flex-col gap-[9px]'}`}
      >
        <SortableContext
          items={isDragActiveColumn || !isBoardDragging ? itemIds : []}
          strategy={verticalListSortingStrategy}
        >
          {itemCount === 0 && emptyNode}
          {!shouldVirtualize && itemCount > 0 && (
            Array.from({ length: itemCount }, (_, index) => (
              <React.Fragment key={itemIds[index] ?? index}>
                {renderItem(index)}
              </React.Fragment>
            ))
          )}
          {shouldVirtualize && itemCount > 0 && (
            <div
              className="relative w-full"
              style={{ height: virtualizer.getTotalSize() }}
            >
              {virtualizer.getVirtualItems().map((virtualRow) => (
                <div
                  key={virtualRow.key}
                  data-index={virtualRow.index}
                  ref={virtualizer.measureElement}
                  className="absolute left-0 w-full"
                  style={{ top: virtualRow.start }}
                >
                  <div style={{ paddingBottom: COLUMN_LIST_GAP_PX }}>
                    {renderItem(virtualRow.index)}
                  </div>
                </div>
              ))}
            </div>
          )}
        </SortableContext>
      </div>
      {hasOverflow && canScrollDown && (
        <div className={scrollEdgeRailBottomClass}>
          <button
            type="button"
            aria-label="Rolar coluna para baixo"
            onClick={() => scrollByDir(1)}
            className={scrollEdgeBtnClass}
          >
            <ChevronDownIcon className="h-3.5 w-3.5" strokeWidth={2.25} />
          </button>
        </div>
      )}
    </div>
  );
});

const KanbanColumn = memo(function KanbanColumn({
  title,
  contacts,
  dotClass,
  showMenu,
  menuLabel,
  onMenuAction,
  onMoveToColumn,
  availableColumns,
  newContactUrl,
  isDarkMode,
  activeDragId,
  focusedSearchContactId = null,
}) {
  const { setNodeRef, isOver } = useDroppable({ id: `column:${title}` });
  const itemIds = useMemo(() => contacts.map((c) => String(c.id)), [contacts]);
  const totalOpportunity = useMemo(
    () => contacts.reduce((sum, contact) => {
      const value = parseCurrency(contact.custom_attributes?.Valor_Oportunidade);
      return value ? sum + value : sum;
    }, 0),
    [contacts]
  );
  const formattedTotal = totalOpportunity ? formatCurrency(totalOpportunity) : null;
  const activeIdStr = activeDragId != null ? String(activeDragId) : '';
  const isBoardDragging = Boolean(activeDragId) && !String(activeDragId).startsWith('opp:');
  const containsActive = Boolean(activeIdStr && itemIds.includes(activeIdStr));
  // Only the source/target column keeps real sortables during drag.
  const isDragActiveColumn = Boolean(isBoardDragging && (isOver || containsActive));
  const enableSortable = !isBoardDragging || isDragActiveColumn;
  const focusIdStr = focusedSearchContactId != null ? String(focusedSearchContactId) : '';
  const columnHasSearchFocus = Boolean(focusIdStr && itemIds.includes(focusIdStr));
  const stageGroup = groupForStageNum(getStageNumber(title));
  const isLostOrAfter = isLeadLostOrAfterStage(title);

  const renderItem = useCallback(
    (index) => {
      const contact = contacts[index];
      if (!contact) return null;
      const shared = {
        contact,
        columnId: title,
        showMenu,
        menuLabel,
        onMenuAction,
        onMoveToColumn,
        availableColumns,
        isDarkMode,
        isSearchFocus: focusIdStr !== '' && String(contact.id) === focusIdStr,
      };
      return enableSortable ? <KanbanCard {...shared} /> : <KanbanCardStatic {...shared} />;
    },
    [contacts, title, showMenu, menuLabel, onMenuAction, onMoveToColumn, availableColumns, isDarkMode, enableSortable, focusIdStr]
  );

  return (
    <div
      ref={setNodeRef}
      data-column-title={title}
      className={`kanban-column w-[var(--kanban-col-w)] max-w-[calc(100vw-2.5rem)] flex-shrink-0 rounded-2xl border border-line bg-bg2 p-2.5 sm:p-3 snap-start flex flex-col min-h-0 max-h-[calc(100dvh-16rem)] sm:max-h-[calc(100vh-280px)] ${isOver ? 'is-over' : ''} ${columnHasSearchFocus ? 'is-search-focus-column' : ''} ${isLostOrAfter ? 'kanban-column-lost' : ''}`}
    >
      <div className="flex flex-col gap-1.5 pb-2 border-b border-border bg-cardAlt sticky top-0 z-10">
        <div className="flex min-w-0 items-center justify-between gap-2">
          <div className="flex min-w-0 items-center gap-2">
            <span className={`h-2 w-2 shrink-0 rounded-full ${dotClass}`} />
            <h3 className="min-w-0 truncate text-sm font-semibold text-ink" title={title}>{title}</h3>
            <span className="shrink-0 text-xs px-2 py-0.5 rounded-full border border-border bg-card text-muted">
              {contacts.length}
            </span>
          </div>
          <div className="flex shrink-0 items-center gap-1.5">
            {stageGroup ? (
              <StageGroupTag label={stageGroup.label} color={stageGroup.color} />
            ) : null}
            {newContactUrl ? (
              <button
                type="button"
                className="h-7 w-7 flex shrink-0 items-center justify-center rounded-lg text-muted hover:text-ink hover:bg-card"
                onPointerDown={(event) => event.stopPropagation()}
                onClick={(event) => {
                  event.stopPropagation();
                  window.open(newContactUrl, '_blank', 'noreferrer');
                }}
                aria-label="Adicionar contato"
              >
                <svg viewBox="0 0 24 24" className="h-4 w-4" fill="none" stroke="currentColor" strokeWidth="1.6">
                  <path d="M12 5v14M5 12h14" />
                </svg>
              </button>
            ) : null}
          </div>
        </div>
        {formattedTotal && (
          <span className="font-mono text-sm font-bold text-ink dark:text-[#e5e7eb]">{formattedTotal}</span>
        )}
      </div>
      <VirtualizedColumnList
        itemIds={itemIds}
        itemCount={contacts.length}
        estimateSize={FUNNEL_CARD_ESTIMATE_PX}
        isDragActiveColumn={isDragActiveColumn}
        isBoardDragging={isBoardDragging}
        focusItemId={columnHasSearchFocus ? focusIdStr : null}
        emptyNode={(
          <div className="rounded-xl border border-dashed border-border bg-card p-4 text-xs text-muted">
            Sem leads ainda.
          </div>
        )}
        renderItem={renderItem}
      />
    </div>
  );
});

const formatLicitacaoDateShort = (dateStr) => {
  if (!dateStr) return null;
  try {
    const date = new Date(dateStr);
    return date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
  } catch {
    return null;
  }
};

const getLicitacaoDateStatus = (dateStr) => {
  if (!dateStr) return 'none';
  try {
    const date = new Date(dateStr);
    const now = new Date();
    const diffHours = (date - now) / (1000 * 60 * 60);
    if (diffHours < 0) return 'passed';
    if (diffHours <= 48) return 'urgent';
    if (diffHours <= 168) return 'soon';
    return 'ok';
  } catch {
    return 'none';
  }
};

const LICITACAO_STATUS_COLORS = {
  passed: 'text-status-danger',
  urgent: 'text-status-danger font-semibold',
  soon: 'text-status-warning',
  ok: 'text-muted',
  none: 'text-muted',
};

const LicitacaoCardBody = memo(function LicitacaoCardBody({ opportunity, onEdit }) {
  const formattedValue = formatCurrency(opportunity.valor_oportunidade);
  const pncpOpportunityUrl = opportunity.links_pncp || opportunity?.links?.pncp || null;
  const itemCount = Number(opportunity.items_count || 0);
  const technicalRequirementsCount = Number(opportunity.technical_requirements_count || 0);
  const technicalPendingCount = Number(opportunity.technical_pending_count || 0);
  const technicalNonCompliantCount = Number(opportunity.technical_non_compliant_count || 0);
  const technicalItemsWithoutChecklistCount = Number(opportunity.technical_items_without_checklist_count || 0);
  const technicalBadge = technicalNonCompliantCount > 0
    ? { label: 'Não atende', className: 'border border-status-danger/30 bg-status-danger/10 text-status-danger' }
    : (itemCount === 0 || technicalRequirementsCount === 0 || technicalPendingCount > 0 || technicalItemsWithoutChecklistCount > 0)
      ? { label: 'Pendência Téc.', className: 'border border-status-warning/35 bg-status-warning/10 text-status-warning' }
      : { label: 'Atende', className: 'border border-status-success/30 bg-status-success/10 text-status-success' };
  // Prazo vencido fica no funil até confirmação (modal); badge "Prazo vencido" quando atrasado.
  const prazoClass = opportunity.prazo_status === 'atrasado'
    ? 'border border-status-danger/40 bg-status-danger/15 text-status-danger'
    : opportunity.prazo_status === 'vence_hoje'
      ? 'border border-status-danger/30 bg-status-danger/10 text-status-danger'
      : opportunity.prazo_status === 'vence_48h'
        ? 'border border-status-warning/35 bg-status-warning/10 text-status-warning'
        : opportunity.prazo_status === 'sem_data'
          ? 'border border-border bg-muted/20 text-muted'
          : 'border border-primary/30 bg-primary/10 text-primary';
  const prazoLabel = opportunity.prazo_status === 'atrasado'
    ? 'Prazo vencido'
    : opportunity.prazo_status === 'vence_hoje'
      ? 'Vence hoje'
      : opportunity.prazo_status === 'vence_48h'
        ? 'Vence em 48h'
        : opportunity.prazo_status === 'sem_data'
          ? 'Sem prazo'
          : 'No prazo';
  // Status operacional só Ativo|Suspenso (legado perdido/ganho/… → Ativo; coluna do pipe é o encerramento).
  const statusKey = String(opportunity.status || 'ativo').toLowerCase() === 'suspenso' ? 'suspenso' : 'ativo';
  const statusBadgeClass = statusKey === 'suspenso'
    ? 'border border-status-warning/35 bg-status-warning/10 text-status-warning'
    : 'border border-primary/25 bg-primary/10 text-primary';

  const sessaoDate = formatLicitacaoDateShort(opportunity.data_sessao);
  const sessaoStatus = getLicitacaoDateStatus(opportunity.data_sessao);
  const propostaDate = formatLicitacaoDateShort(opportunity.data_envio_proposta_limite);
  const propostaStatus = getLicitacaoDateStatus(opportunity.data_envio_proposta_limite);

  return (
    <>
      <div className="flex items-center justify-between gap-2">
        <span className={`inline-flex items-center text-[10px] font-semibold px-2 py-0.5 rounded-full leading-tight whitespace-nowrap ${prazoClass}`}>
          {prazoLabel}
        </span>
        <div className="flex items-center gap-2">
          <span className={`inline-flex items-center text-[10px] uppercase px-2 py-0.5 rounded-full leading-tight whitespace-nowrap ${statusBadgeClass}`}>{statusKey}</span>
          <button
            type="button"
            onPointerDown={(event) => event.stopPropagation()}
            onClick={(event) => {
              event.stopPropagation();
              onEdit?.(opportunity);
            }}
            className="h-6 w-6 rounded-md border border-border text-muted hover:text-ink hover:bg-cardAlt"
            title="Editar card"
          >
            <svg viewBox="0 0 24 24" className="h-3.5 w-3.5 mx-auto" fill="none" stroke="currentColor" strokeWidth="1.8">
              <path d="M4 20h4l10-10-4-4L4 16v4z" />
            </svg>
          </button>
        </div>
      </div>
      <div className="mt-2">
        <h4 className="text-sm font-semibold text-ink leading-snug truncate">
          {pncpOpportunityUrl ? (
            <a
              href={pncpOpportunityUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="hover:underline"
              onClick={(event) => event.stopPropagation()}
              onPointerDown={(event) => event.stopPropagation()}
            >
              {opportunity.titulo}
            </a>
          ) : opportunity.titulo}
        </h4>
        <p className="text-xs text-muted mt-1 truncate">{opportunity.orgao_nome || 'Órgão não definido'}</p>
      </div>
      <div className="mt-2 space-y-1 text-[11px]">
        <div className="flex justify-between">
          <span className="text-muted">Proposta início:</span>
          <span className={LICITACAO_STATUS_COLORS[sessaoStatus]}>{sessaoDate || 'não definida'}</span>
        </div>
        <div className="flex justify-between">
          <span className="text-muted">Proposta fim:</span>
          <span className={LICITACAO_STATUS_COLORS[propostaStatus]}>{propostaDate || 'não definida'}</span>
        </div>
      </div>
      <div className="mt-2 pt-2 border-t border-border flex items-center justify-between text-xs">
        <span className="text-muted truncate">Edital: {opportunity.numero_edital || 'n/d'}</span>
        <span className="font-mono font-semibold text-ink">{formattedValue || 'R$ 0,00'}</span>
      </div>
      <div className="mt-1 flex items-center justify-between gap-2 text-[10px]">
        <span className={`px-2 py-0.5 rounded-full font-semibold leading-tight ${technicalBadge.className}`}>{technicalBadge.label}</span>
        <span className="text-muted truncate">
          {technicalRequirementsCount > 0 ? `${technicalRequirementsCount} requisitos` : 'Checklist não criado'}
        </span>
      </div>
    </>
  );
});

const LicitacaoCard = memo(function LicitacaoCard({ opportunity, columnId, onOpen, onEdit, isSearchFocus = false }) {
  const sortableId = `opp:${opportunity.id}`;
  const sortableData = useMemo(() => ({ columnId, type: 'opportunity' }), [columnId]);
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({
    id: sortableId,
    data: sortableData,
    transition: SORTABLE_TRANSITION,
    animateLayoutChanges: skipSortableLayoutAnim,
  });

  const style = {
    transform: CSS.Translate.toString(transform),
    transition,
    opacity: isDragging ? 0 : undefined,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      {...attributes}
      {...listeners}
      role="button"
      tabIndex={0}
      data-contact-id={sortableId}
      onClick={() => onOpen?.(opportunity)}
      className={kanbanCardClassName(isDragging, isSearchFocus)}
    >
      <LicitacaoCardBody opportunity={opportunity} onEdit={onEdit} />
    </div>
  );
});

const LicitacaoCardStatic = memo(function LicitacaoCardStatic({ opportunity, onOpen, onEdit, isSearchFocus = false }) {
  return (
    <div
      role="button"
      tabIndex={0}
      data-contact-id={`opp:${opportunity.id}`}
      onClick={() => onOpen?.(opportunity)}
      className={kanbanCardClassName(false, isSearchFocus)}
    >
      <LicitacaoCardBody opportunity={opportunity} onEdit={onEdit} />
    </div>
  );
});

const LicitacaoColumn = memo(function LicitacaoColumn({
  title,
  opportunities,
  onOpen,
  onEdit,
  activeDragId,
  focusedSearchOpportunityId = null,
}) {
  const { setNodeRef, isOver } = useDroppable({ id: `licitação-column:${title}` });
  const itemIds = useMemo(() => opportunities.map((o) => `opp:${o.id}`), [opportunities]);
  const totalValue = useMemo(
    () => opportunities.reduce((sum, item) => sum + (parseCurrency(item.valor_oportunidade) || 0), 0),
    [opportunities]
  );
  const activeIdStr = activeDragId != null ? String(activeDragId) : '';
  const isBoardDragging = Boolean(activeDragId) && String(activeDragId).startsWith('opp:');
  const containsActive = Boolean(activeIdStr && itemIds.includes(activeIdStr));
  const isDragActiveColumn = Boolean(isBoardDragging && (isOver || containsActive));
  const enableSortable = !isBoardDragging || isDragActiveColumn;
  const focusIdStr = focusedSearchOpportunityId != null ? String(focusedSearchOpportunityId) : '';
  const focusItemId = focusIdStr ? `opp:${focusIdStr}` : null;
  const columnHasSearchFocus = Boolean(focusItemId && itemIds.includes(focusItemId));
  const stageGroup = licGroupForStageNum(getStageNumber(title));
  const isLostOrAfter = isLicLostOrAfterStage(title);

  const renderItem = useCallback(
    (index) => {
      const opportunity = opportunities[index];
      if (!opportunity) return null;
      const isSearchFocus = focusIdStr !== '' && String(opportunity.id) === focusIdStr;
      if (!enableSortable) {
        return (
          <LicitacaoCardStatic
            opportunity={opportunity}
            onOpen={onOpen}
            onEdit={onEdit}
            isSearchFocus={isSearchFocus}
          />
        );
      }
      return (
        <LicitacaoCard
          opportunity={opportunity}
          columnId={title}
          onOpen={onOpen}
          onEdit={onEdit}
          isSearchFocus={isSearchFocus}
        />
      );
    },
    [opportunities, title, onOpen, onEdit, enableSortable, focusIdStr]
  );

  return (
    <div
      ref={setNodeRef}
      data-column-title={title}
      className={`kanban-column w-[var(--kanban-col-w)] max-w-[calc(100vw-2.5rem)] flex-shrink-0 rounded-2xl border border-line bg-bg2 p-2.5 sm:p-3 snap-start flex flex-col min-h-0 max-h-[calc(100dvh-16rem)] sm:max-h-[calc(100vh-280px)] ${isOver ? 'is-over' : ''} ${columnHasSearchFocus ? 'is-search-focus-column' : ''} ${isLostOrAfter ? 'kanban-column-lost' : ''}`}
    >
      <div className="flex flex-col gap-1.5 pb-2 border-b border-line bg-bg2 sticky top-0 z-10">
        <div className="flex min-w-0 items-center justify-between gap-2">
          <div className="flex min-w-0 items-center gap-2">
            <span className="h-2 w-2 shrink-0 rounded-full bg-secondary" />
            <h3 className="min-w-0 truncate text-sm font-semibold text-ink" title={title}>{title}</h3>
            <span className="shrink-0 font-mono text-xs px-2 py-0.5 rounded-full border border-line bg-surf text-muted">{opportunities.length}</span>
          </div>
          {stageGroup ? (
            <StageGroupTag label={stageGroup.label} color={stageGroup.color} />
          ) : null}
        </div>
        <span className="font-mono text-xs font-semibold text-ink">{formatCurrency(totalValue) || 'R$ 0,00'}</span>
      </div>
      <VirtualizedColumnList
        itemIds={itemIds}
        itemCount={opportunities.length}
        estimateSize={LICITACAO_CARD_ESTIMATE_PX}
        isDragActiveColumn={isDragActiveColumn}
        isBoardDragging={isBoardDragging}
        focusItemId={columnHasSearchFocus ? focusItemId : null}
        emptyNode={(
          <div className="rounded-xl border border-dashed border-border bg-card p-4 text-xs text-muted">
            Sem oportunidades nesta etapa.
          </div>
        )}
        renderItem={renderItem}
      />
    </div>
  );
});

// ===================== PCA — Plano Anual de Contratações =====================

const formatPcaCurrency = (v) => {
  if (v === null || v === undefined || v === '') return '—';
  const n = Number(v);
  if (!Number.isFinite(n)) return '—';
  return n.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', minimumFractionDigits: 2 });
};

const formatPcaQuantity = (v) => {
  if (v === null || v === undefined || v === '') return '—';
  const n = Number(v);
  if (!Number.isFinite(n)) return '—';
  const isIntegerLike = Math.abs(n - Math.trunc(n)) < 1e-9;
  return n.toLocaleString('pt-BR', {
    minimumFractionDigits: 0,
    maximumFractionDigits: isIntegerLike ? 0 : 3,
  });
};

const formatPcaDate = (v) => {
  if (!v) return '—';
  try {
    const d = new Date(v);
    if (Number.isNaN(d.getTime())) return '—';
    return d.toLocaleDateString('pt-BR');
  } catch { return '—'; }
};

const groupPcaSignalsByWatchlist = (signals) => {
  const groups = new Map();
  for (const s of (signals || [])) {
    if (!s.watchlist_id) continue;
    const key = `watchlist_${s.watchlist_id}`;
    if (!groups.has(key)) {
      groups.set(key, {
        key,
        title: s.watchlist_nome || (s.watchlist_id ? `Watchlist #${s.watchlist_id}` : 'Sem watchlist'),
        plans: new Map(),
        itemsCount: 0,
        totalCount: Number(s.watchlist_total_count) || 0,
      });
    }
    const group = groups.get(key);
    group.totalCount = Math.max(group.totalCount, Number(s.watchlist_total_count) || 0);
    const planKey = `plano_${s.plano_id || `${s.orgao_cnpj}:${s.codigo_unidade}:${s.ano_pca}`}`;
    if (!group.plans.has(planKey)) {
      group.plans.set(planKey, {
        key: planKey,
        plano_id: s.plano_id,
        id_pca_pncp: s.id_pca_pncp,
        orgao_cnpj: s.orgao_cnpj,
        orgao_razao: s.orgao_razao_social,
        codigo_unidade: s.codigo_unidade,
        unidade_nome: s.unidade_nome,
        ano_pca: s.ano_pca,
        pncp_url: `https://pncp.gov.br/app/pca/${s.orgao_cnpj}/${s.ano_pca}`,
        items: [],
        valor_total: 0,
        max_score: 0,
      });
    }
    const plan = group.plans.get(planKey);
    plan.items.push(s);
    plan.valor_total += Number(s.valor_total) || 0;
    plan.max_score = Math.max(plan.max_score, Number(s.score) || 0);
    group.itemsCount += 1;
  }
  return Array.from(groups.values()).map(group => ({
    ...group,
    plans: Array.from(group.plans.values()).sort((a, b) => {
      const byValorTotal = b.valor_total - a.valor_total;
      if (byValorTotal !== 0) return byValorTotal;
      return b.max_score - a.max_score;
    }),
  }));
};

const groupEditalSignalsByWatchlist = (signals) => {
  const groups = new Map();
  for (const s of (signals || [])) {
    if (!s.watchlist_id) continue;
    const key = `watchlist_${s.watchlist_id}`;
    if (!groups.has(key)) {
      groups.set(key, {
        key,
        title: s.watchlist_nome || `Watchlist #${s.watchlist_id}`,
        items: [],
        itemsCount: 0,
        totalCount: Number(s.watchlist_total_count) || 0,
        maxScore: 0,
      });
    }
    const group = groups.get(key);
    group.items.push(s);
    group.itemsCount += 1;
    group.totalCount = Math.max(group.totalCount, Number(s.watchlist_total_count) || 0);
    group.maxScore = Math.max(group.maxScore, Number(s.score) || 0);
  }
  return Array.from(groups.values()).sort((a, b) => b.maxScore - a.maxScore);
};

const PcaChips = ({ items, onRemove, accent }) => (
  <div className="flex flex-wrap gap-1.5">
    {(items || []).map((t, i) => (
      <span
        key={`${t}-${i}`}
        className={`inline-flex items-center gap-1 rounded-lg px-2 py-0.5 font-display text-[11px] font-semibold uppercase tracking-wide ${
          accent === 'pos'
            ? 'border border-primary/30 bg-primary/10 text-primary'
            : 'border border-amber/30 bg-amber/15 text-amber'
        }`}
      >
        {t}
        {onRemove && (
          <button
            type="button"
            className="normal-case opacity-70 hover:opacity-100"
            onClick={() => onRemove(i)}
            aria-label={`remover ${t}`}
          >×</button>
        )}
      </span>
    ))}
  </div>
);

const statusFilterPill = (active) =>
  `inline-flex h-8 items-center justify-center rounded-lg border px-3 text-xs font-semibold transition ${
    active
      ? 'border-primary bg-primary/10 text-primary'
      : 'border-line bg-bg2 text-muted hover:border-line2 hover:text-ink'
  }`;

const statusFilterLabel = (s) => ({
  novo: 'Novos',
  visto: 'Vistos',
  promovido: 'Promovidos',
  descartado: 'Descartados',
}[s] || s);

function PcaExplorer({ onPromoted, onSwitchToBoard, onOpenOpportunity }) {
  const [q, setQ] = useState('');
  const [usarIa, setUsarIa] = useState(true);
  const [positivos, setPositivos] = useState([]);
  const [negativos, setNegativos] = useState([]);
  const [fonteIa, setFonteIa] = useState(null);
  const [items, setItems] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [filtros, setFiltros] = useState({
    valor_min: '', valor_max: '', mes_previsto: '',
    orgao_cnpj: '', unidade_codigo: '',
    ano_pca: String(new Date().getFullYear()),
  });
  const [showFilters, setShowFilters] = useState(false);
  const [editTerms, setEditTerms] = useState(false);
  const [posDraft, setPosDraft] = useState('');
  const [negDraft, setNegDraft] = useState('');
  const [busy, setBusy] = useState({});
  const [itemBusy, setItemBusy] = useState({});
  const [saveDialog, setSaveDialog] = useState(false);
  const [saveName, setSaveName] = useState('');
  const [saveWhatsappEnabled, setSaveWhatsappEnabled] = useState(false);
  const [saveWhatsappNumber, setSaveWhatsappNumber] = useState('');
  const [saveWhatsappScoreBand, setSaveWhatsappScoreBand] = useState('all');
  const [saveBusy, setSaveBusy] = useState(false);
  const [saveNotice, setSaveNotice] = useState(null);
  const [selecionados, setSelecionados] = useState({});
  const [lastPromoted, setLastPromoted] = useState(null);
  const [bootstrapStatus, setBootstrapStatus] = useState(null);
  const [hasSearched, setHasSearched] = useState(false);
  // Força o painel de cards a recarregar após “Salvar e monitorar” (mesmo modelo dos jobs de editais).
  const [watchlistListRefreshVersion, setWatchlistListRefreshVersion] = useState(0);

  const filtrosAtivos = Object.entries(filtros).filter(([k, v]) => v && !(k === 'ano_pca' && v === String(new Date().getFullYear()))).length;
  const watchlistTerms = useMemo(() => {
    const source = positivos.length ? positivos : (q.trim() ? [q.trim()] : []);
    const seen = new Set();
    return source.map(term => String(term || '').trim()).filter(term => {
      const key = term.toLocaleLowerCase('pt-BR');
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }, [positivos, q]);

  // Auto-dismiss do toast de promoção
  useEffect(() => {
    if (!lastPromoted) return;
    const id = setTimeout(() => setLastPromoted(null), 8000);
    return () => clearTimeout(id);
  }, [lastPromoted]);

  useEffect(() => {
    if (!saveNotice) return undefined;
    const id = setTimeout(() => setSaveNotice(null), 7000);
    return () => clearTimeout(id);
  }, [saveNotice]);

  const fetchBootstrapStatus = useCallback(async () => {
    try {
      const r = await axios.get('/api/licitacoes/pca/bootstrap/status');
      setBootstrapStatus(r.data);
      return r.data;
    } catch {
      return null;
    }
  }, []);

  // Status é rápido durante a carga; fora dela, revalida em intervalo leve e
  // quando o usuário volta para a aba. Não há motivo para consultar a cada 5s sempre.
  useEffect(() => {
    fetchBootstrapStatus();
  }, [fetchBootstrapStatus]);

  useEffect(() => {
    const intervalMs = bootstrapStatus?.running ? 5000 : 5 * 60 * 1000;
    const id = setInterval(() => {
      if (document.visibilityState === 'visible') fetchBootstrapStatus();
    }, intervalMs);
    return () => clearInterval(id);
  }, [bootstrapStatus?.running, fetchBootstrapStatus]);

  useEffect(() => {
    const refreshWhenVisible = () => {
      if (document.visibilityState === 'visible') fetchBootstrapStatus();
    };
    document.addEventListener('visibilitychange', refreshWhenVisible);
    return () => document.removeEventListener('visibilitychange', refreshWhenVisible);
  }, [fetchBootstrapStatus]);

  const runSearch = async (overridePositivos, overrideNegativos) => {
    if (!q.trim() && !overridePositivos?.length) {
      setError('Digite uma palavra-chave para buscar.');
      return;
    }
    setHasSearched(true);
    setLoading(true);
    setError(null);
    try {
      const params = {
        q: q.trim(),
        usar_ia: overridePositivos ? 'false' : (usarIa ? 'true' : 'false'),
        ano_pca: filtros.ano_pca || undefined,
        valor_min: filtros.valor_min || undefined,
        valor_max: filtros.valor_max || undefined,
        mes_previsto: filtros.mes_previsto || undefined,
        orgao_cnpj: filtros.orgao_cnpj || undefined,
        unidade_codigo: filtros.unidade_codigo || undefined,
        tam: 50,
      };
      if (overridePositivos) {
        params.positivos_override = JSON.stringify(overridePositivos);
        params.negativos_override = JSON.stringify(overrideNegativos || []);
      }
      const r = await axios.get('/api/licitacoes/pca/search', { params });
      setPositivos(r.data.positivos || []);
      setNegativos(r.data.negativos || []);
      setFonteIa(r.data.fonte_ia || null);
      setItems((r.data.items || []).map(it => ({
        ...it,
        signal_status: it.signal_status || 'novo',
      })));
      setTotal(r.data.total || 0);
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally {
      setLoading(false);
    }
  };

  const refazerComEditados = () => runSearch(positivos, negativos);

  const toggleItem = (key, itemId) => {
    setSelecionados(prev => {
      const set = new Set(prev[key] || []);
      if (set.has(itemId)) set.delete(itemId);
      else set.add(itemId);
      return { ...prev, [key]: set };
    });
  };
  const setAllForCt = (key, itemIds, mode) => {
    setSelecionados(prev => ({
      ...prev,
      [key]: new Set(mode === 'all' ? itemIds : []),
    }));
  };

  const promoverContratacao = async (ct) => {
    const set = selecionados[ct.key];
    const itemIds = set ? Array.from(set) : [];
    const itemIdsPromoviveis = itemIds.filter((id) => {
      const item = ct.itens.find(i => i.item_id === id);
      return item && !item.ja_promovido;
    });
    if (!itemIdsPromoviveis.length) return;
    setBusy(prev => ({ ...prev, [ct.key]: true }));
    try {
      const r = await axios.post('/api/licitacoes/pca/contratacoes/promote', {
        plano_id: ct.plano_id,
        item_ids: itemIdsPromoviveis,
        titulo: ct.contratacao_nome || (ct.contratacao_id ? `Contratação ${ct.contratacao_id}` : null),
      });
      onPromoted && onPromoted();
      setSelecionados(prev => ({ ...prev, [ct.key]: new Set() }));
      // Itens promovidos saem da busca (já estão no pipeline).
      setItems(prev => prev.filter(it => !itemIdsPromoviveis.includes(it.item_id)));
      setTotal(prev => Math.max(0, Number(prev || 0) - itemIdsPromoviveis.length));
      setLastPromoted({
        titulo: r.data?.titulo || ct.contratacao_nome || `Contratação ${ct.contratacao_id || ''}`,
        itens: itemIdsPromoviveis.length,
        opportunityId: r.data?.id,
        pncpUrl: ct.pncp_url,
      });
    } catch (e) {
      alert(`Erro ao promover: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [ct.key]: false }));
    }
  };

  const salvarWatchlist = async () => {
    if (!watchlistTerms.length) {
      setSaveNotice({ tone: 'error', message: 'Adicione ao menos um termo antes de salvar.' });
      return;
    }
    const waPayload = buildWhatsappPayload(saveWhatsappEnabled, saveWhatsappNumber, saveWhatsappScoreBand);
    if (saveWhatsappEnabled && !waPayload.whatsapp_numbers.length) {
      setSaveNotice({ tone: 'error', message: 'Informe ao menos um WhatsApp válido com DDD.' });
      return;
    }
    setSaveBusy(true);
    try {
      await axios.post('/api/licitacoes/pca/watchlist', {
        nome: saveName || q.trim() || watchlistTerms[0],
        palavras_chave: watchlistTerms,
        termos_negativos: negativos,
        usar_ia: usarIa,
        valor_minimo: filtros.valor_min ? Number(filtros.valor_min) : null,
        valor_maximo: filtros.valor_max ? Number(filtros.valor_max) : null,
        ...waPayload,
      });
      setSaveDialog(false);
      setSaveName('');
      setSaveWhatsappEnabled(false);
      setSaveWhatsappNumber('');
      setSaveWhatsappScoreBand('all');
      setWatchlistListRefreshVersion(v => v + 1);
      setSaveNotice({
        tone: 'success',
        message: `Busca salva (${watchlistTerms.length} termo${watchlistTerms.length === 1 ? '' : 's'}). O card aparece em Minhas buscas abaixo.${saveWhatsappEnabled ? ' Alertas WhatsApp ligados para novidades.' : ' Você pode ligar o WhatsApp no card.'}`,
      });
    } catch (e) {
      setSaveNotice({ tone: 'error', message: e.response?.data?.error || e.message || 'Não foi possível salvar a busca.' });
    } finally {
      setSaveBusy(false);
    }
  };

  const updateItemLocal = useCallback((itemId, changes) => {
    setItems(prev => prev.map(it => (String(it.item_id) === String(itemId) ? { ...it, ...changes } : it)));
  }, []);

  const promoteSingleItem = async (item) => {
    const key = `promote:${item.item_id}`;
    setItemBusy(prev => ({ ...prev, [key]: true }));
    try {
      await axios.post('/api/licitacoes/pca/signals/promote-item', { item_id: item.item_id });
      // Item promovido sai da busca (já está no pipeline).
      setItems(prev => prev.filter(it => String(it.item_id) !== String(item.item_id)));
      setTotal(prev => Math.max(0, Number(prev || 0) - 1));
      onPromoted && onPromoted();
    } catch (e) {
      alert(`Erro ao promover item: ${e.response?.data?.error || e.message}`);
    } finally {
      setItemBusy(prev => ({ ...prev, [key]: false }));
    }
  };

  const setSingleItemStatus = async (item, status) => {
    const key = `status:${item.item_id}:${status}`;
    setItemBusy(prev => ({ ...prev, [key]: true }));
    try {
      await axios.put(`/api/licitacoes/pca/items/${item.item_id}/status`, { status });
      updateItemLocal(item.item_id, { signal_status: status });
    } catch (e) {
      alert(`Erro ao atualizar status: ${e.response?.data?.error || e.message}`);
    } finally {
      setItemBusy(prev => ({ ...prev, [key]: false }));
    }
  };

  // Lista plana de Futuras Contratações (uma por card).
  // Itens sem futura_contratacao_id viram cards "solo" (key inclui o item_id pra não fundir não-relacionados).
  const contratacoesPlanas = useMemo(() => {
    const m = new Map();
    for (const it of items) {
      const ctTag = it.futura_contratacao_id || `__solo_${it.item_id}__`;
      const key = `${it.orgao_cnpj}:${it.codigo_unidade}:${ctTag}`;
      if (!m.has(key)) {
        const pncpUrl = `https://pncp.gov.br/app/pca/${it.orgao_cnpj}/${it.ano_pca}`;
        m.set(key, {
          key,
          plano_id: it.plano_id,
          id_pca_pncp: it.id_pca_pncp,
          pncp_url: pncpUrl,
          orgao_cnpj: it.orgao_cnpj,
          orgao_razao: it.orgao_razao_social,
          codigo_unidade: it.codigo_unidade,
          unidade_nome: it.unidade_nome,
          ano_pca: it.ano_pca,
          contratacao_id: it.futura_contratacao_id,
          contratacao_nome: it.futura_contratacao_nome,
          itens: [],
          valor_total: 0,
          quantidade_total: 0,
          max_score: 0,
        });
      }
      const ct = m.get(key);
      ct.itens.push(it);
      ct.valor_total += Number(it.valor_total) || 0;
      ct.quantidade_total += Number(it.quantidade) || 0;
      const s = Number(it.score) || 0;
      if (s > ct.max_score) ct.max_score = s;
    }
    return Array.from(m.values()).sort((a, b) => {
      const byValorTotal = b.valor_total - a.valor_total;
      if (byValorTotal !== 0) return byValorTotal;
      return b.max_score - a.max_score;
    });
  }, [items]);

  return (
    <div className="mt-6 space-y-5">
      <div className="rounded-[16px] border border-line bg-surf p-4 md:p-5 space-y-4">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="min-w-0 max-w-3xl">
            <h3 className={`${sectionTitle} text-base`}>PCA — Plano de Contratações Anuais</h3>
            <p className={`${subtle} mt-1.5 leading-relaxed`}>
              O <strong className="font-semibold text-ink">PCA</strong> é o plano de contratações anuais do governo:
              órgãos públicos publicam, com antecedência, o que pretendem comprar no ano — ainda{' '}
              <strong className="font-semibold text-ink">antes do edital</strong>.
              Busque, use <strong className="font-semibold text-ink">Salvar e monitorar</strong> e a busca vira card em Minhas buscas.
              {' '}
              <span className="text-muted2" title="Itens já promovidos ao board não aparecem de novo nos resultados da busca.">
                A busca não lista itens já no pipeline.
              </span>
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            {bootstrapStatus?.total_planos_db > 0 && (
              <span
                className="rounded-lg border border-line bg-bg2 px-2.5 py-1 font-mono text-[10px] text-muted"
                title={bootstrapStatus.ultimo_sync
                  ? `Base atualizada automaticamente em ${new Date(bootstrapStatus.ultimo_sync).toLocaleString('pt-BR')}`
                  : 'Base atualizada automaticamente'}
              >
                {bootstrapStatus.total_planos_db.toLocaleString('pt-BR')} planos · {bootstrapStatus.total_itens_db.toLocaleString('pt-BR')} itens · automático
              </span>
            )}
          </div>
        </div>

        {bootstrapStatus?.running && (
          <div role="status" className="flex flex-wrap items-center justify-between gap-2 rounded-[12px] border border-primary/25 bg-primary/[0.07] px-3 py-2 text-xs text-ink">
            <span className="font-semibold">
              Preparando a base de PCAs — etapa {bootstrapStatus.mes_atual ?? '…'}/{bootstrapStatus.mes_total ?? '…'}
            </span>
            <span className="text-muted">A atualização continua em segundo plano; você pode sair desta tela.</span>
          </div>
        )}

        {bootstrapStatus && !bootstrapStatus.running && !bootstrapStatus.total_planos_db && (
          <div role="status" className="rounded-[12px] border border-amber/30 bg-amber/10 px-3 py-2 text-xs text-ink">
            <span className="font-semibold">Preparando a base de PCAs automaticamente.</span>{' '}
            <span className="text-muted">
              Nenhuma ação é necessária{bootstrapStatus.error ? '; uma nova tentativa será feita pelo sistema' : ''}.
            </span>
          </div>
        )}

        <div className="grid min-w-0 grid-cols-1 gap-2 sm:grid-cols-2 lg:grid-cols-[minmax(0,1fr)_auto_auto_auto] lg:items-center">
          <div className="relative flex h-[42px] min-w-0 items-center rounded-[11px] border border-line bg-bg2 sm:col-span-2 lg:col-span-1">
            <MagnifyingGlassIcon className="pointer-events-none absolute left-3 h-4 w-4 text-muted" />
            <input
              type="text"
              placeholder='Buscar PCAs — ex: "drone", "raio-x", "veículo blindado"…'
              value={q}
              onChange={e => setQ(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && runSearch()}
              className="h-full w-full min-w-0 rounded-[11px] bg-transparent pl-10 pr-28 text-base sm:text-sm font-semibold text-ink outline-none placeholder:text-muted"
            />
            <button
              type="button"
              onClick={() => setUsarIa(v => !v)}
              title={usarIa ? 'Busca IA ativada — expande termos correlatos' : 'Busca IA desativada'}
              className={`absolute right-2 shrink-0 rounded-md px-2 py-1 text-[10.5px] font-bold transition ${usarIa ? 'bg-cyan/10 text-cyan' : 'bg-bg text-muted2'}`}
            >
              ✦ Busca IA
            </button>
          </div>
          <button type="button" onClick={() => runSearch()} disabled={loading} className={`${btnPrimaryControl} w-full lg:w-auto lg:px-6`}>
            {loading ? 'Buscando…' : 'Buscar'}
          </button>
          <button
            type="button"
            onClick={() => setShowFilters(v => !v)}
            className={`${btnSecondaryControl} w-full lg:w-auto ${showFilters || filtrosAtivos > 0 ? 'border-primary/40 text-primary' : ''}`}
          >
            Filtros{filtrosAtivos > 0 ? ` (${filtrosAtivos})` : ''}
          </button>
          <button
            type="button"
            onClick={() => setSaveDialog(true)}
            disabled={!q.trim() && !positivos.length}
            className={`${btnSecondaryControl} w-full sm:col-span-2 lg:col-span-1 lg:w-auto`}
            title="Salva esta busca como assinatura monitorada (sinais + WhatsApp opcional)"
          >
            Salvar e monitorar
          </button>
        </div>

        {(positivos.length > 0 || negativos.length > 0) && (
          <div className="space-y-2 border-t border-line pt-3">
            <div className="flex flex-wrap items-center justify-between gap-2">
              <p className="text-xs text-muted">
                <span className="font-semibold text-ink">Termos ativos nesta busca.</span>{' '}
                O PCA procura qualquer um deles; “Salvar e monitorar” transforma este conjunto na sua assinatura.
              </p>
              <span className={metaChip}>{watchlistTerms.length} na assinatura</span>
            </div>
            <div className="flex items-start gap-2 text-xs">
              <span className="mt-0.5 shrink-0 font-mono text-[10px] uppercase tracking-wide text-muted2">+ {positivos.length}</span>
              <PcaChips items={positivos} onRemove={(i) => setPositivos(positivos.filter((_, idx) => idx !== i))} accent="pos" />
            </div>
            {negativos.length > 0 && (
              <div className="flex items-start gap-2 text-xs">
                <span className="mt-0.5 shrink-0 font-mono text-[10px] uppercase tracking-wide text-muted2">− {negativos.length}</span>
                <PcaChips items={negativos} onRemove={(i) => setNegativos(negativos.filter((_, idx) => idx !== i))} accent="neg" />
              </div>
            )}
            <div className="flex flex-wrap items-center gap-3 pt-1 text-xs">
              {fonteIa && <span className="text-muted">via {fonteIa}</span>}
              <button type="button" onClick={() => setEditTerms(v => !v)} className="font-semibold text-primary hover:underline">
                {editTerms ? 'Fechar edição' : 'Adicionar termos'}
              </button>
              <button type="button" onClick={refazerComEditados} className="font-semibold text-primary hover:underline">
                Refazer busca
              </button>
            </div>
            {editTerms && (
              <div className="grid min-w-0 grid-cols-1 gap-2 pt-1 sm:grid-cols-2">
                <input
                  value={posDraft}
                  onChange={e => setPosDraft(e.target.value)}
                  onKeyDown={e => {
                    if (e.key === 'Enter' && posDraft.trim()) {
                      setPositivos([...positivos, posDraft.trim()]);
                      setPosDraft('');
                    }
                  }}
                  placeholder="+ termo positivo (Enter)"
                  className={`${input} h-8 w-full min-w-0 text-xs`}
                />
                <input
                  value={negDraft}
                  onChange={e => setNegDraft(e.target.value)}
                  onKeyDown={e => {
                    if (e.key === 'Enter' && negDraft.trim()) {
                      setNegativos([...negativos, negDraft.trim()]);
                      setNegDraft('');
                    }
                  }}
                  placeholder="− termo negativo (Enter)"
                  className={`${input} h-8 w-full min-w-0 text-xs`}
                />
              </div>
            )}
          </div>
        )}

        {showFilters && (
          <div className="space-y-4 rounded-[14px] border border-line bg-bg2/40 p-4">
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.1em] text-muted2">Filtros da busca PCA</p>
            <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 lg:grid-cols-4">
              <div className="min-w-0">
                <label className="mb-1.5 block text-xs font-medium text-muted">Ano PCA</label>
                <input className={`${input} w-full text-xs`} placeholder="Ex.: 2026"
                  value={filtros.ano_pca} onChange={e => setFiltros({ ...filtros, ano_pca: e.target.value })} />
              </div>
              <div className="min-w-0">
                <label className="mb-1.5 block text-xs font-medium text-muted">Mês previsto</label>
                <input className={`${input} w-full text-xs`} placeholder="1–12"
                  value={filtros.mes_previsto} onChange={e => setFiltros({ ...filtros, mes_previsto: e.target.value })} />
              </div>
              <div className="min-w-0">
                <label className="mb-1.5 block text-xs font-medium text-muted">Valor mínimo (R$)</label>
                <input className={`${input} w-full text-xs`} placeholder="0"
                  value={filtros.valor_min} onChange={e => setFiltros({ ...filtros, valor_min: e.target.value })} />
              </div>
              <div className="min-w-0">
                <label className="mb-1.5 block text-xs font-medium text-muted">Valor máximo (R$)</label>
                <input className={`${input} w-full text-xs`} placeholder="Sem limite"
                  value={filtros.valor_max} onChange={e => setFiltros({ ...filtros, valor_max: e.target.value })} />
              </div>
            </div>
            <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
              <div className="min-w-0">
                <label className="mb-1.5 block text-xs font-medium text-muted">CNPJ do órgão</label>
                <input className={`${input} w-full text-xs`} placeholder="00.000.000/0000-00"
                  value={filtros.orgao_cnpj} onChange={e => setFiltros({ ...filtros, orgao_cnpj: e.target.value })} />
              </div>
              <div className="min-w-0">
                <label className="mb-1.5 block text-xs font-medium text-muted">UASG (código unidade)</label>
                <input className={`${input} w-full text-xs`} placeholder="Código da unidade"
                  value={filtros.unidade_codigo} onChange={e => setFiltros({ ...filtros, unidade_codigo: e.target.value })} />
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Cards de buscas salvas — a própria busca é a assinatura (mesmo modelo dos editais). */}
      <div>
        <div className="flex flex-wrap items-end justify-between gap-2">
          <div className="min-w-0">
            <h3 className={`${sectionTitle} text-[15px]`}>Minhas buscas</h3>
            <p className={`${subtle} mt-0.5`}>
              Cada card é uma busca salva (assinatura). Clique para ver os sinais; WhatsApp só para novidades.
            </p>
          </div>
          <span className="justify-self-start text-[11px] text-muted sm:justify-self-end">Atualização automática</span>
        </div>
        <PcaWatchlistsPanel
          onPromoted={onPromoted}
          listRefreshVersion={watchlistListRefreshVersion}
        />
      </div>

      {error && <div className="rounded-[12px] border border-status-danger/30 bg-status-danger/10 px-3 py-2.5 text-sm text-status-danger">{error}</div>}

      {(hasSearched || loading || contratacoesPlanas.length > 0) && (
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div>
            {!loading && contratacoesPlanas.length > 0 && (
              <p className="text-xs text-muted">
                <span className="font-semibold text-ink">Resultados da busca</span>
                {' · '}
                <span className="font-semibold text-ink">{contratacoesPlanas.length}</span> contratação(ões)
                {' · '}
                <span className="font-semibold text-ink">{total}</span> item(ns)
                <span className="text-muted2"> · ordenado por maior valor</span>
                <span className="text-muted2" title="Itens já promovidos ao board ficam de fora desta lista.">
                  {' · '}sem o que já está no pipe
                </span>
              </p>
            )}
            {loading && <p className="text-xs text-muted">Buscando no banco de PCAs…</p>}
          </div>
        </div>
      )}

      <div className="space-y-2.5">
        {contratacoesPlanas.map(ct => {
          const allItemIds = ct.itens.map(i => i.item_id);
          const sel = selecionados[ct.key] || new Set();
          const selectedCount = sel.size;
          const selectedPromotableCount = ct.itens.filter(i => sel.has(i.item_id) && !i.ja_promovido).length;
          const promotedCount = ct.itens.filter(i => i.ja_promovido).length;
          const valorSelecionado = ct.itens
            .filter(i => sel.has(i.item_id))
            .reduce((acc, i) => acc + (Number(i.valor_total) || 0), 0);
          const titulo = ct.contratacao_nome
            || (ct.contratacao_id ? `Contratação ${ct.contratacao_id}` : ct.itens[0]?.descricao || 'Item PCA');
          return (
            <details key={ct.key} className="group rounded-[14px] border border-line bg-surf overflow-hidden transition hover:border-primary/40">
              <summary className="flex cursor-pointer list-none items-start gap-3 p-3.5 [&::-webkit-details-marker]:hidden">
                <div className="min-w-0 flex-1">
                  <div className="mb-1.5 flex flex-wrap items-center gap-1.5">
                    <span className="inline-flex items-center rounded-md border border-primary/25 bg-primary/10 px-2 py-0.5 font-display text-[10px] font-semibold uppercase tracking-wide text-primary">
                      {ct.orgao_razao || ct.orgao_cnpj}
                    </span>
                    <span className="rounded-md border border-line bg-bg2 px-2 py-0.5 font-mono text-[10px] text-muted">UASG {ct.codigo_unidade}</span>
                    <span className="rounded-md border border-line bg-bg2 px-2 py-0.5 font-mono text-[10px] text-muted">PCA {ct.ano_pca}</span>
                    {ct.contratacao_id && <span className="font-mono text-[10px] text-muted2">{ct.contratacao_id}</span>}
                    <a
                      href={ct.pncp_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      onClick={(e) => e.stopPropagation()}
                      className="ml-auto text-[11px] font-semibold text-primary hover:underline"
                      title="Abrir PCA no PNCP"
                    >
                      PNCP ↗
                    </a>
                  </div>
                  <div className="truncate text-sm font-semibold text-ink">{titulo}</div>
                  <div className="mt-1.5 flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-muted">
                    <span>{ct.itens.length} item(ns)</span>
                    <span>{formatPcaQuantity(ct.quantidade_total)} un.</span>
                    <span className="font-mono font-semibold text-ink">{formatPcaCurrency(ct.valor_total)}</span>
                    {promotedCount > 0 && <span className="text-emerald-600">{promotedCount}/{ct.itens.length} promovido(s)</span>}
                    <span className="inline-flex items-center gap-1 rounded-md bg-primary/10 px-1.5 py-0.5 font-mono text-[10px] font-semibold text-primary">
                      score {ct.max_score.toFixed(2)}
                    </span>
                  </div>
                </div>
                <button
                  type="button"
                  onClick={(e) => { e.preventDefault(); e.stopPropagation(); promoverContratacao(ct); }}
                  disabled={busy[ct.key] || selectedPromotableCount === 0}
                  className="h-9 shrink-0 rounded-[10px] bg-[linear-gradient(135deg,#7c5cff,#5a3ff0)] px-3 text-xs font-semibold text-white hover:brightness-110 disabled:opacity-40"
                  title={selectedCount === 0
                    ? 'Selecione itens primeiro'
                    : selectedPromotableCount === 0
                      ? 'Itens selecionados já estão promovidos'
                      : `Promover ${selectedPromotableCount} de ${ct.itens.length} (${formatPcaCurrency(valorSelecionado)})`}
                >
                  {busy[ct.key] ? '…' : `Promover${selectedPromotableCount > 0 ? ` (${selectedPromotableCount})` : ''}`}
                </button>
              </summary>
              <div className="border-t border-line bg-bg2/50 p-3.5">
                <div className="mb-2.5 flex flex-wrap items-center gap-3 text-xs">
                  <button type="button" onClick={() => setAllForCt(ct.key, allItemIds, 'all')}
                    className="font-semibold text-primary hover:underline">Selecionar todos ({ct.itens.length})</button>
                  <button type="button" onClick={() => setAllForCt(ct.key, allItemIds, 'none')}
                    className="text-muted hover:underline">Limpar</button>
                  {selectedCount > 0 && (
                    <span className="ml-auto font-mono text-muted">
                      {selectedCount} sel. · {formatPcaCurrency(valorSelecionado)}
                    </span>
                  )}
                </div>
                <div className="divide-y divide-border">
                  {ct.itens.map(item => {
                    const checked = sel.has(item.item_id);
                    return (
                      <label key={item.item_id} className={`py-2 flex items-start gap-3 cursor-pointer rounded-md px-2 -mx-2 transition-colors ${checked ? 'bg-primary/15 ring-1 ring-primary/30' : 'hover:bg-primary/5'}`}>
                        <input
                          type="checkbox"
                          checked={checked}
                          onChange={() => toggleItem(ct.key, item.item_id)}
                          className="mt-1"
                        />
                        <div className="flex-1 min-w-0">
                          <div className="text-sm text-ink">{item.descricao}</div>
                          <div className="mt-1 flex flex-wrap gap-x-3 gap-y-1 text-xs text-muted">
                            <span>{formatPcaQuantity(item.quantidade)} {item.unidade_medida || ''}</span>
                            <span>{formatPcaCurrency(item.valor_total)}</span>
                            {item.mes_previsto && <span>mês {item.mes_previsto}/{ct.ano_pca}</span>}
                            {item.classificacao_nome && <span className="truncate max-w-[200px]">{item.classificacao_nome}</span>}
                            {item.ja_promovido && (
                              <span className="inline-flex items-center rounded-md bg-emerald-500/15 px-2 py-0.5 font-semibold text-emerald-600">
                                Promovido
                              </span>
                            )}
                            {item.ja_promovido && item.promovido_para_opportunity_id && onOpenOpportunity && (
                              <button
                                type="button"
                                onClick={(event) => {
                                  event.preventDefault();
                                  event.stopPropagation();
                                  onOpenOpportunity(item.promovido_para_opportunity_id);
                                }}
                                className="text-primary hover:underline"
                              >
                                Ver no Board ↗
                              </button>
                            )}
                          </div>
                          <div className="mt-2 flex flex-wrap gap-2">
                            {!item.ja_promovido && (
                              <button
                                type="button"
                                onClick={(event) => {
                                  event.preventDefault();
                                  event.stopPropagation();
                                  promoteSingleItem(item);
                                }}
                                disabled={itemBusy[`promote:${item.item_id}`]}
                                className="h-7 rounded-md bg-primary px-2.5 text-[11px] font-semibold text-white disabled:opacity-50"
                              >
                                {itemBusy[`promote:${item.item_id}`] ? 'Promovendo...' : 'Promover item'}
                              </button>
                            )}
                            {item.signal_status !== 'novo' && (
                              <button
                                type="button"
                                onClick={(event) => {
                                  event.preventDefault();
                                  event.stopPropagation();
                                  setSingleItemStatus(item, 'novo');
                                }}
                                disabled={itemBusy[`status:${item.item_id}:novo`]}
                                className="h-7 rounded-md border border-border px-2.5 text-[11px] text-muted disabled:opacity-50"
                              >
                                Novo
                              </button>
                            )}
                            {item.signal_status !== 'visto' && (
                              <button
                                type="button"
                                onClick={(event) => {
                                  event.preventDefault();
                                  event.stopPropagation();
                                  setSingleItemStatus(item, 'visto');
                                }}
                                disabled={itemBusy[`status:${item.item_id}:visto`]}
                                className="h-7 rounded-md border border-border px-2.5 text-[11px] text-muted disabled:opacity-50"
                              >
                                Visto
                              </button>
                            )}
                            {item.signal_status !== 'descartado' && (
                              <button
                                type="button"
                                onClick={(event) => {
                                  event.preventDefault();
                                  event.stopPropagation();
                                  setSingleItemStatus(item, 'descartado');
                                }}
                                disabled={itemBusy[`status:${item.item_id}:descartado`]}
                                className="h-7 rounded-md border border-border px-2.5 text-[11px] text-muted disabled:opacity-50"
                              >
                                Descartar
                              </button>
                            )}
                          </div>
                        </div>
                      </label>
                    );
                  })}
                </div>
              </div>
            </details>
          );
        })}
        {!loading && !error && items.length === 0 && hasSearched && (
          <div className="rounded-[14px] border border-dashed border-line bg-surf/60 px-4 py-10 text-center">
            <p className="text-sm font-semibold text-ink">Nenhum PCA encontrado</p>
            <p className={`${subtle} mx-auto mt-1 max-w-lg`}>
              Tente ampliar os termos, remover filtros ou desativar a expansão por IA.
            </p>
            {bootstrapStatus?.total_planos_db > 0 && (
              <p className={`${subtle} mt-2`}>
                A base tem {bootstrapStatus.total_planos_db.toLocaleString('pt-BR')} planos e é atualizada automaticamente
                {bootstrapStatus.ultimo_sync
                  ? ` · última atualização ${new Date(bootstrapStatus.ultimo_sync).toLocaleString('pt-BR')}`
                  : ''}.
              </p>
            )}
          </div>
        )}
      </div>

      {/* TOAST de promoção */}
      {lastPromoted && (
        <div className="fixed bottom-4 right-4 z-50 rounded-2xl border border-primary/40 bg-card shadow-xl p-4 max-w-sm animate-in fade-in slide-in-from-bottom-2">
          <div className="flex items-start gap-3">
            <div className="flex-1 min-w-0">
              <div className="text-sm font-semibold text-ink">✓ Promovido para o Board</div>
              <div className="mt-1 text-xs text-muted truncate">
                {lastPromoted.titulo}
              </div>
              <div className="text-xs text-muted">
                {lastPromoted.itens} item(ns) · coluna 1. Monitoramento de PCA
              </div>
              <div className="mt-2 flex items-center gap-3 flex-wrap">
                {onSwitchToBoard && (
                  <button type="button" onClick={() => { onSwitchToBoard(); setLastPromoted(null); }}
                    className="text-xs font-semibold text-primary hover:underline">
                    Ver no Board ↗
                  </button>
                )}
                {lastPromoted.pncpUrl && (
                  <a href={lastPromoted.pncpUrl} target="_blank" rel="noopener noreferrer"
                    className="text-xs font-semibold text-primary hover:underline">
                    Ver no PNCP ↗
                  </a>
                )}
                <button type="button" onClick={() => setLastPromoted(null)}
                  className="text-xs text-muted hover:underline ml-auto">
                  Fechar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {saveDialog && (
        <div className={modalOverlay} onClick={() => { if (!saveBusy) setSaveDialog(false); }} role="presentation">
          <div
            className={`${modalPanel} max-w-md space-y-4`}
            onClick={(event) => event.stopPropagation()}
            role="dialog"
            aria-modal="true"
            aria-labelledby="pca-save-watchlist-title"
          >
            <div>
              <h3 id="pca-save-watchlist-title" className="text-base font-semibold text-ink">Salvar e monitorar esta busca</h3>
              <p className={`${subtle} mt-1`}>
                Esta busca vira uma <strong className="text-ink">assinatura</strong>: o sistema continua batendo nos PCAs
                e gera sinais novos. WhatsApp opcional só para o que ainda não tinha sido visto.
              </p>
            </div>
            <input
              className={`${input} w-full`}
              placeholder="Nome (ex: Drones / RPA)"
              value={saveName}
              onChange={e => setSaveName(e.target.value)}
            />
            <label className="flex cursor-pointer items-start gap-2 text-xs text-muted">
              <input
                type="checkbox"
                className="mt-0.5"
                checked={saveWhatsappEnabled}
                onChange={e => setSaveWhatsappEnabled(e.target.checked)}
              />
              <span>
                <span className="block font-semibold text-ink">Avisar pelo WhatsApp</span>
                <span className="mt-0.5 block text-muted">Só oportunidades novas — não reenvia o histórico.</span>
              </span>
            </label>
            {saveWhatsappEnabled && (
              <div className="space-y-3">
                <WhatsappScoreBandPicker
                  value={saveWhatsappScoreBand}
                  disabled={saveBusy}
                  onChange={(bandId) => setSaveWhatsappScoreBand(bandId)}
                />
                <div>
                  <label className="mb-1.5 block text-xs font-medium text-muted">
                    Celulares que recebem o alerta
                  </label>
                  <textarea
                    className={`${textarea} w-full min-h-[4.5rem] resize-y font-mono text-[13px]`}
                    rows={3}
                    placeholder={WHATSAPP_NUMBERS_PLACEHOLDER}
                    value={saveWhatsappNumber}
                    onChange={e => setSaveWhatsappNumber(e.target.value)}
                  />
                  <WhatsappNumbersFieldHelp
                    count={parseWhatsappNumbers(saveWhatsappNumber).length}
                    error={saveWhatsappEnabled && !parseWhatsappNumbers(saveWhatsappNumber).length}
                  />
                </div>
              </div>
            )}
            <div className="space-y-2 rounded-[12px] bg-bg2/60 p-3">
              <div className="flex items-center justify-between gap-2">
                <span className="text-xs font-semibold text-ink">Termos da assinatura</span>
                <span className={metaChip}>{watchlistTerms.length}</span>
              </div>
              <PcaChips items={watchlistTerms} accent="pos" />
              {negativos.length > 0 && (
                <>
                  <span className="block pt-1 text-xs font-semibold text-ink">Termos excluídos</span>
                  <PcaChips items={negativos} accent="neg" />
                </>
              )}
              {usarIa && (
                <p className={subtle}>A IA poderá atualizar a expansão sem remover os termos que você selecionou.</p>
              )}
            </div>
            <div className="flex justify-end gap-2">
              <button type="button" disabled={saveBusy} onClick={() => setSaveDialog(false)} className={btnSecondary}>Cancelar</button>
              <button
                type="button"
                disabled={saveBusy || !watchlistTerms.length || (saveWhatsappEnabled && !parseWhatsappNumbers(saveWhatsappNumber).length)}
                onClick={salvarWatchlist}
                className={btnPrimary}
              >
                {saveBusy ? 'Salvando…' : 'Ativar monitoramento'}
              </button>
            </div>
          </div>
        </div>
      )}

      {saveNotice && createPortal(
        <div className="fixed bottom-5 right-5 z-[70] w-[min(26rem,calc(100vw-2rem))]" role="status" aria-live="polite">
          <div className={`rounded-[14px] border px-4 py-3 ${saveNotice.tone === 'success'
            ? 'border-status-success/35 bg-card text-ink'
            : 'border-status-danger/35 bg-card text-status-danger'}`}>
            <div className="flex items-start gap-3">
              {saveNotice.tone === 'success'
                ? <CheckCircleIcon className="mt-0.5 h-5 w-5 shrink-0 text-status-success" />
                : <ExclamationTriangleIcon className="mt-0.5 h-5 w-5 shrink-0 text-status-danger" />}
              <div className="min-w-0 flex-1">
                <p className="text-sm font-semibold">{saveNotice.tone === 'success' ? 'Busca salva' : 'Não foi possível salvar'}</p>
                <p className="mt-0.5 text-xs leading-relaxed text-muted">{saveNotice.message}</p>
              </div>
              <button type="button" onClick={() => setSaveNotice(null)} className={iconBtn} aria-label="Fechar aviso">
                <XMarkIcon className="h-4 w-4" />
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

const PCA_SIGNALS_PAGE_SIZE = 25;
const EDITAL_SIGNALS_PAGE_SIZE = 25;

/** Barra de paginação compacta para listas de sinais (popup e painel). */
function SignalsPaginationBar({
  page = 1,
  total = 0,
  pageSize = 25,
  loading = false,
  onPageChange,
}) {
  const totalPages = Math.max(1, Math.ceil(Math.max(0, total) / Math.max(1, pageSize)));
  if (total <= 0) return null;
  const from = (page - 1) * pageSize + 1;
  const to = Math.min(page * pageSize, total);
  return (
    <div className="flex flex-wrap items-center justify-between gap-2 border-t border-line pt-3">
      <span className="font-mono text-[11px] text-muted2">
        {from.toLocaleString('pt-BR')}–{to.toLocaleString('pt-BR')} de {total.toLocaleString('pt-BR')}
      </span>
      <div className="flex items-center gap-2">
        <button
          type="button"
          disabled={page <= 1 || loading}
          onClick={() => onPageChange?.(page - 1)}
          className="h-8 rounded-lg border border-line px-3 text-xs font-semibold text-ink disabled:opacity-50 hover:bg-bg2"
        >
          Anterior
        </button>
        <span className="min-w-[4.5rem] text-center font-mono text-xs text-muted">
          {page} / {totalPages}
        </span>
        <button
          type="button"
          disabled={page >= totalPages || loading}
          onClick={() => onPageChange?.(page + 1)}
          className="h-8 rounded-lg border border-line px-3 text-xs font-semibold text-ink disabled:opacity-50 hover:bg-bg2"
        >
          Próxima
        </button>
      </div>
    </div>
  );
}

/** Aceita string CSV/linhas, array ou whatsapp_numbers da API. */
function parseWhatsappNumbers(value, extra = null) {
  const chunks = [];
  const push = (raw) => {
    if (raw == null || raw === '') return;
    if (Array.isArray(raw)) {
      raw.forEach(push);
      return;
    }
    String(raw).split(/[,;\n|]+/).forEach((part) => {
      const trimmed = String(part || '').trim();
      if (trimmed) chunks.push(trimmed);
    });
  };
  push(value);
  push(extra);
  const out = [];
  const seen = new Set();
  for (const chunk of chunks) {
    const digits = chunk.replace(/\D/g, '');
    if (digits.length < 10) continue;
    if (seen.has(digits)) continue;
    seen.add(digits);
    out.push(chunk.replace(/\s+/g, ' ').trim());
  }
  return out;
}

function formatWhatsappAlertLabel(value, numbersProp = null, minScore = null) {
  const nums = parseWhatsappNumbers(numbersProp, value);
  if (!nums.length) return '';
  const base = nums.length === 1 ? nums[0] : `${nums.length} números`;
  const band = whatsappMinScoreToBandId(minScore);
  if (band === 'high') return `${base} · só alta`;
  if (band === 'medium') return `${base} · média+`;
  return base;
}

/**
 * Botão da barra do card: "Assinar" ou só o sino.
 * Sino verde = WhatsApp ligado — não repetir chip "Alertas · …" no corpo do card.
 */
function WhatsappAlertActionContent({ subscribed, alertsOn }) {
  if (!subscribed) return 'Assinar';
  if (alertsOn) {
    return <BellAlertIcon className="h-3.5 w-3.5 text-emerald-600 dark:text-emerald-300 bell-ring" aria-hidden />;
  }
  return <BellIcon className="h-3.5 w-3.5" aria-hidden />;
}

function whatsappAlertActionTitle({ subscribed, alertsOn, number, numbers, minScore }) {
  if (!subscribed) return 'Esta busca vira assinatura; opcional WhatsApp para novos editais';
  if (alertsOn) {
    const label = formatWhatsappAlertLabel(number, numbers, minScore);
    return label
      ? `WhatsApp em ${label} — editar números e faixas de score`
      : 'WhatsApp ligado — editar números e faixas de score';
  }
  return 'Assinatura ativa — ligar ou editar avisos WhatsApp';
}

function whatsappAlertActionAria({ subscribed, alertsOn }) {
  if (!subscribed) return 'Assinar busca';
  if (alertsOn) return 'Editar alertas WhatsApp';
  return 'Configurar alertas WhatsApp';
}

/** Faixas iguais à UI de score: vermelho <38, amarelo >=38, verde >=68. */
const WHATSAPP_SCORE_BANDS = [
  {
    id: 'all',
    minScore: 0,
    label: 'Todas',
    hint: 'Inclui baixa (vermelho)',
    swatch: 'bg-status-danger',
    activeClass: 'border-status-danger/40 bg-status-danger/10 text-status-danger',
  },
  {
    id: 'medium',
    minScore: PNCP_SCORE_MEDIUM_THRESHOLD,
    label: 'Média+',
    hint: `Amarelo e verde (≥ ${PNCP_SCORE_MEDIUM_THRESHOLD})`,
    swatch: 'bg-amber-500',
    activeClass: 'border-amber-400/50 bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-200 dark:border-amber-700',
  },
  {
    id: 'high',
    minScore: PNCP_SCORE_HIGH_THRESHOLD,
    label: 'Só alta',
    hint: `Somente verde (≥ ${PNCP_SCORE_HIGH_THRESHOLD})`,
    swatch: 'bg-status-success',
    activeClass: 'border-status-success/40 bg-status-success/10 text-status-success',
  },
];

function normalizeWhatsappMinScore(value, bandId = null) {
  if (bandId) {
    const byId = WHATSAPP_SCORE_BANDS.find((b) => b.id === bandId);
    if (byId) return byId.minScore;
  }
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return 0;
  if (n >= PNCP_SCORE_HIGH_THRESHOLD) return PNCP_SCORE_HIGH_THRESHOLD;
  if (n >= PNCP_SCORE_MEDIUM_THRESHOLD) return PNCP_SCORE_MEDIUM_THRESHOLD;
  return 0;
}

function whatsappMinScoreToBandId(value) {
  const min = normalizeWhatsappMinScore(value);
  if (min >= PNCP_SCORE_HIGH_THRESHOLD) return 'high';
  if (min >= PNCP_SCORE_MEDIUM_THRESHOLD) return 'medium';
  return 'all';
}

function buildWhatsappPayload(enabled, numbersInput, minScoreOrBand = 0) {
  const numbers = parseWhatsappNumbers(numbersInput);
  const minScore = normalizeWhatsappMinScore(minScoreOrBand, typeof minScoreOrBand === 'string' ? minScoreOrBand : null);
  if (!enabled || !numbers.length) {
    return {
      whatsapp_enabled: false,
      whatsapp_number: null,
      whatsapp_numbers: [],
      whatsapp_min_score: minScore,
      whatsapp_score_band: whatsappMinScoreToBandId(minScore),
    };
  }
  return {
    whatsapp_enabled: true,
    whatsapp_number: numbers.join(','),
    whatsapp_numbers: numbers,
    whatsapp_min_score: minScore,
    whatsapp_score_band: whatsappMinScoreToBandId(minScore),
  };
}

function numbersToWhatsappTextarea(value, numbersProp = null) {
  return parseWhatsappNumbers(numbersProp, value).join('\n');
}

const WHATSAPP_NUMBERS_PLACEHOLDER =
  '11941901424\n48999998888\nou: 11 94190-1424, 48 99999-8888';

function WhatsappNumbersFieldHelp({ count = 0, error = false }) {
  return (
    <div className="mt-1.5 space-y-1 text-[11px] leading-snug text-muted">
      <ul className="list-disc space-y-0.5 pl-4">
        <li>
          <strong className="font-semibold text-ink">DDD obrigatório</strong>
          {' '}(ex.: <span className="font-mono text-ink/90">11</span> + celular).
        </li>
        <li>
          <strong className="font-semibold text-ink">DDI 55 opcional</strong>
          {' '}— se não colocar, o sistema assume Brasil (<span className="font-mono text-ink/90">55</span>).
        </li>
        <li>
          Vários números: <strong className="font-semibold text-ink">um por linha</strong>
          {' '}ou separados por <strong className="font-semibold text-ink">vírgula</strong>.
        </li>
        <li>Espaços, traços e parênteses são ignorados.</li>
      </ul>
      {count > 0 ? (
        <p className="text-status-success">
          {count} número{count === 1 ? '' : 's'} válido{count === 1 ? '' : 's'} reconhecido{count === 1 ? '' : 's'}.
        </p>
      ) : (
        <p>Ex.: <span className="font-mono text-ink/80">11941901424</span> ou <span className="font-mono text-ink/80">55 11 94190-1424</span></p>
      )}
      {error && (
        <p className="text-status-danger">Informe ao menos um celular válido com DDD (10 ou 11 dígitos).</p>
      )}
    </div>
  );
}

function WhatsappScoreBandPicker({ value = 'all', onChange, disabled = false }) {
  const activeId = whatsappMinScoreToBandId(
    typeof value === 'string' && ['all', 'medium', 'high'].includes(value)
      ? WHATSAPP_SCORE_BANDS.find((b) => b.id === value)?.minScore
      : value
  );
  const active = WHATSAPP_SCORE_BANDS.find((b) => b.id === activeId) || WHATSAPP_SCORE_BANDS[0];
  return (
    <div>
      <p className="mb-1.5 text-xs font-medium text-muted">Enviar WhatsApp a partir de</p>
      <div className="grid grid-cols-3 gap-1.5">
        {WHATSAPP_SCORE_BANDS.map((band) => {
          const selected = band.id === activeId;
          return (
            <button
              key={band.id}
              type="button"
              disabled={disabled}
              onClick={() => onChange?.(band.id, band.minScore)}
              className={`rounded-[12px] border px-2 py-2 text-left transition ${
                selected ? band.activeClass : 'border-line bg-bg2/40 text-muted hover:bg-bg2'
              } ${disabled ? 'opacity-50 pointer-events-none' : ''}`}
              aria-pressed={selected}
            >
              <span className="flex items-center gap-1.5">
                <span className={`h-2 w-2 shrink-0 rounded-full ${band.swatch}`} aria-hidden />
                <span className="text-[12px] font-semibold leading-none">{band.label}</span>
              </span>
              <span className="mt-1 block text-[10px] leading-snug opacity-80">{band.hint}</span>
            </button>
          );
        })}
      </div>
      <p className={`${subtle} mt-1.5`}>
        Filtro só do WhatsApp — o acervo da assinatura continua com todas as faixas. Agora: <strong className="text-ink">{active.hint}</strong>.
      </p>
    </div>
  );
}

/** Modal de WhatsApp para watchlists (substitui window.prompt nativo). */
function WatchlistWhatsappDialog({
  open,
  watchlistName,
  initialNumber = '',
  initialNumbers = null,
  initialEnabled = false,
  initialMinScore = 0,
  initialScoreBand = null,
  saving = false,
  onClose,
  onSave,
}) {
  const [enabled, setEnabled] = useState(false);
  const [numbersText, setNumbersText] = useState('');
  const [scoreBand, setScoreBand] = useState('all');
  const inputRef = useRef(null);
  const onCloseRef = useRef(onClose);
  onCloseRef.current = onClose;

  // Snapshot only when the dialog opens — never reset while the user is typing
  // (parent re-renders used to recreate initialNumbers / onClose and steal focus).
  useEffect(() => {
    if (!open) return;
    const text = numbersToWhatsappTextarea(initialNumber, initialNumbers);
    setEnabled(initialEnabled || Boolean(text.trim()));
    setNumbersText(text);
    setScoreBand(initialScoreBand || whatsappMinScoreToBandId(initialMinScore));
    // eslint-disable-next-line react-hooks/exhaustive-deps -- intentional: init on open only
  }, [open]);

  useEffect(() => {
    if (!open) return undefined;
    const t = window.setTimeout(() => inputRef.current?.focus(), 40);
    const onKey = (event) => {
      if (event.key === 'Escape' && !saving) onCloseRef.current?.();
    };
    window.addEventListener('keydown', onKey);
    return () => {
      window.clearTimeout(t);
      window.removeEventListener('keydown', onKey);
    };
  }, [open, saving]);

  if (!open) return null;

  const parsedNumbers = parseWhatsappNumbers(numbersText);
  const numbersValid = !enabled || parsedNumbers.length > 0;
  const handleSave = () => {
    if (!numbersValid) return;
    onSave?.(buildWhatsappPayload(enabled, numbersText, scoreBand));
  };

  return createPortal(
    <div
      className={modalOverlay}
      onClick={() => { if (!saving) onClose?.(); }}
      role="presentation"
    >
      <div
        className={`${modalPanel} max-w-md space-y-4`}
        onClick={(event) => event.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-labelledby="watchlist-wa-title"
      >
        <div className="flex items-start justify-between gap-3">
          <div className="min-w-0">
            <h3 id="watchlist-wa-title" className="font-display text-base font-semibold text-ink">
              Alertas por WhatsApp
            </h3>
            <p className={`${subtle} mt-0.5`}>
              {watchlistName
                ? <>Watchlist <span className="font-semibold text-ink">{watchlistName}</span></>
                : 'Receba novos sinais no celular'}
            </p>
          </div>
          <button type="button" onClick={onClose} disabled={saving} className={iconBtn} aria-label="Fechar">
            <XMarkIcon className="h-5 w-5" />
          </button>
        </div>

        <label className="flex cursor-pointer items-start gap-3 rounded-[12px] border border-line bg-bg2/50 px-3 py-2.5">
          <input
            type="checkbox"
            className="mt-0.5"
            checked={enabled}
            onChange={(event) => setEnabled(event.target.checked)}
            disabled={saving}
          />
          <span className="min-w-0">
            <span className="block text-sm font-semibold text-ink">Ativar alertas</span>
            <span className={`${subtle} mt-0.5 block`}>
              Envia aviso a todos os números quando a watchlist capturar novos sinais.
            </span>
          </span>
        </label>

        <div className={enabled ? '' : 'opacity-50 pointer-events-none'}>
          <WhatsappScoreBandPicker
            value={scoreBand}
            disabled={saving || !enabled}
            onChange={(bandId) => setScoreBand(bandId)}
          />
          <label htmlFor="watchlist-wa-numbers" className="mb-1.5 mt-3 block text-xs font-medium text-muted">
            Celulares que recebem o alerta
          </label>
          <textarea
            id="watchlist-wa-numbers"
            ref={inputRef}
            rows={3}
            disabled={saving || !enabled}
            className={`${textarea} w-full min-h-[4.5rem] resize-y font-mono text-[13px]`}
            placeholder={WHATSAPP_NUMBERS_PLACEHOLDER}
            value={numbersText}
            onChange={(event) => setNumbersText(event.target.value)}
          />
          <WhatsappNumbersFieldHelp count={parsedNumbers.length} error={enabled && !numbersValid} />
        </div>

        <div className="flex flex-wrap items-center justify-end gap-2 border-t border-line pt-3">
          <button type="button" disabled={saving} onClick={onClose} className={btnSecondary}>
            Cancelar
          </button>
          <button
            type="button"
            disabled={saving || !numbersValid}
            onClick={handleSave}
            className={btnPrimary}
          >
            {saving ? 'Salvando…' : 'Salvar'}
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
}

/** Confirma a criação de uma watchlist sem recorrer aos diálogos nativos do navegador. */
function CreateEditalWatchlistDialog({
  open,
  defaultName = '',
  contextLabel = '',
  saving = false,
  initialWhatsappEnabled = false,
  initialWhatsappNumber = '',
  initialWhatsappNumbers = null,
  initialWhatsappMinScore = 0,
  initialWhatsappScoreBand = null,
  alreadySubscribed = false,
  onClose,
  onSave,
}) {
  const [name, setName] = useState('');
  const [whatsappEnabled, setWhatsappEnabled] = useState(false);
  const [whatsappNumbersText, setWhatsappNumbersText] = useState('');
  const [whatsappScoreBand, setWhatsappScoreBand] = useState('all');
  const nameInputRef = useRef(null);
  const onCloseRef = useRef(onClose);
  onCloseRef.current = onClose;

  // Snapshot only when the dialog opens — parent re-renders must not reset fields
  // or re-focus the name input (that was stealing focus after 1 character).
  useEffect(() => {
    if (!open) return;
    setName(String(defaultName || ''));
    setWhatsappEnabled(Boolean(initialWhatsappEnabled));
    setWhatsappNumbersText(numbersToWhatsappTextarea(initialWhatsappNumber, initialWhatsappNumbers));
    setWhatsappScoreBand(initialWhatsappScoreBand || whatsappMinScoreToBandId(initialWhatsappMinScore));
    // eslint-disable-next-line react-hooks/exhaustive-deps -- intentional: init on open only
  }, [open]);

  useEffect(() => {
    if (!open) return undefined;
    const timer = window.setTimeout(() => {
      nameInputRef.current?.focus();
      nameInputRef.current?.select();
    }, 40);
    const handleKeyDown = (event) => {
      if (event.key === 'Escape' && !saving) onCloseRef.current?.();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.clearTimeout(timer);
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [open, saving]);

  if (!open) return null;

  const cleanName = String(name || '').trim();
  const parsedNumbers = parseWhatsappNumbers(whatsappNumbersText);
  const numberIsValid = !whatsappEnabled || parsedNumbers.length > 0;
  const canSave = Boolean(cleanName) && numberIsValid && !saving;
  const handleSave = () => {
    if (!canSave) return;
    onSave?.({
      nome: cleanName,
      ...buildWhatsappPayload(whatsappEnabled, whatsappNumbersText, whatsappScoreBand),
    });
  };

  return createPortal(
    <div
      className={`${modalOverlay} z-[80]`}
      onClick={() => { if (!saving) onClose?.(); }}
      role="presentation"
    >
      <div
        className={`${modalPanel} max-w-md flex flex-col gap-4`}
        onClick={(event) => event.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-labelledby="create-edital-watchlist-title"
        aria-describedby="create-edital-watchlist-description"
      >
        <div className="flex items-start gap-3">
          <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-primary/10 text-primary">
            <BellIcon className="h-5 w-5" aria-hidden />
          </div>
          <div className="min-w-0 flex-1">
            <h3 id="create-edital-watchlist-title" className="font-display text-base font-semibold text-ink">
              {alreadySubscribed ? 'Alertas desta busca' : 'Esta busca vira assinatura'}
            </h3>
            <p id="create-edital-watchlist-description" className="mt-1 text-sm text-muted">
              O card continua coletando. Opcionalmente avisamos no WhatsApp só quando aparecer
              <strong className="text-ink"> edital novo</strong> (não reenvia o acervo já na lista).
            </p>
          </div>
          <button type="button" onClick={onClose} disabled={saving} className={iconBtn} aria-label="Fechar">
            <XMarkIcon className="h-5 w-5" />
          </button>
        </div>

        <div>
          <label htmlFor="create-edital-watchlist-name" className="mb-1.5 block text-xs font-medium text-muted">
            Nome da assinatura
          </label>
          <input
            id="create-edital-watchlist-name"
            ref={nameInputRef}
            className={`${input} w-full`}
            value={name}
            maxLength={200}
            disabled={saving}
            onChange={(event) => setName(event.target.value)}
            onKeyDown={(event) => {
              if (event.key === 'Enter' && !whatsappEnabled) {
                event.preventDefault();
                handleSave();
              }
            }}
          />
          {contextLabel && <p className={`${subtle} mt-1.5 truncate`}>Busca: {contextLabel}</p>}
        </div>

        <label className="flex cursor-pointer items-start gap-3 rounded-[12px] border border-line bg-bg2/50 px-3 py-2.5">
          <input
            type="checkbox"
            className="mt-0.5"
            checked={whatsappEnabled}
            disabled={saving}
            onChange={(event) => setWhatsappEnabled(event.target.checked)}
          />
          <span className="min-w-0">
            <span className="block text-sm font-semibold text-ink">Avisar pelo WhatsApp</span>
            <span className={`${subtle} mt-0.5 block`}>
              Matcher diário (~08h) + fila a cada 5 min. Só oportunidades que ainda não tinham sido vistas.
            </span>
          </span>
        </label>

        {whatsappEnabled && (
          <div className="space-y-3">
            <WhatsappScoreBandPicker
              value={whatsappScoreBand}
              disabled={saving}
              onChange={(bandId) => setWhatsappScoreBand(bandId)}
            />
            <div>
              <label htmlFor="create-edital-watchlist-whatsapp" className="mb-1.5 block text-xs font-medium text-muted">
                Celulares que recebem o alerta
              </label>
              <textarea
                id="create-edital-watchlist-whatsapp"
                rows={3}
                className={`${textarea} w-full min-h-[4.5rem] resize-y font-mono text-[13px]`}
                placeholder={WHATSAPP_NUMBERS_PLACEHOLDER}
                value={whatsappNumbersText}
                disabled={saving}
                onChange={(event) => setWhatsappNumbersText(event.target.value)}
              />
              <WhatsappNumbersFieldHelp count={parsedNumbers.length} error={!numberIsValid} />
            </div>
          </div>
        )}

        <div className="flex flex-col-reverse gap-2 border-t border-line pt-3 sm:flex-row sm:justify-end">
          <button type="button" disabled={saving} onClick={onClose} className={btnSecondary}>
            Cancelar
          </button>
          <button type="button" disabled={!canSave} onClick={handleSave} className={btnPrimary}>
            {saving ? 'Salvando…' : (alreadySubscribed ? 'Salvar alertas' : 'Ativar assinatura')}
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
}

function PcaSignalsPanel({ onPromoted, watchlistId = null, compact = false, onChanged, refreshVersion = 0 }) {
  const [signals, setSignals] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [statusFilter, setStatusFilter] = useState('novo');
  const [page, setPage] = useState(1);
  const [busy, setBusy] = useState({});
  const [selectedSignals, setSelectedSignals] = useState({});
  const [collapsedWatchlists, setCollapsedWatchlists] = useState({});
  const [statusCounts, setStatusCounts] = useState({ novo: 0, visto: 0, promovido: 0, descartado: 0 });
  const [pageInfo, setPageInfo] = useState({ total: 0, pageSize: PCA_SIGNALS_PAGE_SIZE });
  const flatMode = Boolean(watchlistId) || compact;

  const loadCounts = useCallback(async () => {
    try {
      const r = await axios.get('/api/licitacoes/pca/signals/stats');
      setStatusCounts({
        novo: Number(r.data?.novo) || 0,
        visto: Number(r.data?.visto) || 0,
        promovido: Number(r.data?.promovido) || 0,
        descartado: Number(r.data?.descartado) || 0,
      });
    } catch {
      setStatusCounts({ novo: 0, visto: 0, promovido: 0, descartado: 0 });
    }
  }, []);

  const load = useCallback(async ({ background = false, pageOverride } = {}) => {
    const activePage = Math.max(1, pageOverride ?? page);
    if (!background) setLoading(true);
    setError(null);
    try {
      const offset = (activePage - 1) * PCA_SIGNALS_PAGE_SIZE;
      const r = await axios.get('/api/licitacoes/pca/signals', {
        params: {
          status: statusFilter,
          limit: PCA_SIGNALS_PAGE_SIZE,
          offset,
          ...(watchlistId ? { watchlist_id: watchlistId } : {}),
        },
      });
      const rows = Array.isArray(r.data) ? r.data : (r.data?.data || []);
      const total = Array.isArray(r.data) ? rows.length : (Number(r.data?.total) || 0);
      const totalPages = Math.max(1, Math.ceil(total / PCA_SIGNALS_PAGE_SIZE));
      if (rows.length === 0 && total > 0 && activePage > totalPages) {
        setPage(totalPages);
        return;
      }
      setSignals(rows);
      setPageInfo({ total, pageSize: PCA_SIGNALS_PAGE_SIZE });
      loadCounts();
    } catch (e) {
      setError(e.response?.status === 504
        ? 'A atualização demorou mais que o esperado. Vamos tentar novamente automaticamente.'
        : (e.response?.data?.error || 'Não foi possível carregar os sinais agora.'));
    } finally {
      if (!background) setLoading(false);
    }
  }, [statusFilter, loadCounts, watchlistId, page]);

  // Reset page when switching watchlist; status filter resets page in the click handler.
  useEffect(() => { setPage(1); }, [watchlistId]);

  useEffect(() => { load(); }, [load, refreshVersion]);

  useEffect(() => {
    let lastRefresh = Date.now();
    const refreshIfStale = () => {
      if (document.visibilityState !== 'visible' || Date.now() - lastRefresh < 60000) return;
      lastRefresh = Date.now();
      load({ background: true });
    };
    const intervalId = setInterval(refreshIfStale, 5 * 60 * 1000);
    document.addEventListener('visibilitychange', refreshIfStale);
    window.addEventListener('focus', refreshIfStale);
    return () => {
      clearInterval(intervalId);
      document.removeEventListener('visibilitychange', refreshIfStale);
      window.removeEventListener('focus', refreshIfStale);
    };
  }, [load]);

  useEffect(() => {
    setSelectedSignals({});
  }, [statusFilter, page]);

  const changeStatusFilter = (nextStatus) => {
    setStatusFilter(nextStatus);
    setPage(1);
  };

  const goToPage = (nextPage) => {
    const totalPages = Math.max(1, Math.ceil((pageInfo.total || 0) / PCA_SIGNALS_PAGE_SIZE));
    const clamped = Math.min(Math.max(1, nextPage), totalPages);
    setPage(clamped);
  };

  const toggleSelected = (id) => {
    setSelectedSignals(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const selectedIds = Object.keys(selectedSignals).filter(id => selectedSignals[id]).map(id => Number(id));
  const groupedSignals = useMemo(() => groupPcaSignalsByWatchlist(signals), [signals]);

  const toggleWatchlistCollapsed = (key) => {
    setCollapsedWatchlists(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const setAllWatchlistsCollapsed = (collapsed) => {
    const next = {};
    groupedSignals.forEach(group => {
      next[group.key] = collapsed;
    });
    setCollapsedWatchlists(next);
  };

  const runBatch = async (action, status = null) => {
    if (!selectedIds.length) return;
    setBusy(prev => ({ ...prev, __batch: true }));
    try {
      await axios.post('/api/licitacoes/pca/signals/batch', {
        action,
        status,
        signal_ids: selectedIds,
      });
      if (action === 'promote') onPromoted && onPromoted();
      setSelectedSignals({});
      await load();
      onChanged?.();
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, __batch: false }));
    }
  };

  const act = async (id, kind) => {
    setBusy(prev => ({ ...prev, [id]: true }));
    try {
      if (kind === 'promote') {
        await axios.post(`/api/licitacoes/pca/signals/${id}/promote`);
        onPromoted && onPromoted();
      } else if (kind === 'unpromote') {
        await axios.post(`/api/licitacoes/pca/signals/${id}/unpromote`);
      } else if (kind === 'dismiss') {
        await axios.post(`/api/licitacoes/pca/signals/${id}/dismiss`);
      } else if (kind === 'seen') {
        await axios.post(`/api/licitacoes/pca/signals/${id}/seen`);
      } else if (kind === 'to_novo' || kind === 'to_visto' || kind === 'to_descartado') {
        const status = kind.replace('to_', '');
        await axios.put(`/api/licitacoes/pca/signals/${id}/status`, { status });
      }
      await load();
      onChanged?.();
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [id]: false }));
    }
  };

  const plansFromGroups = useMemo(() => {
    if (!flatMode) return [];
    return groupedSignals.flatMap(group => group.plans || []);
  }, [flatMode, groupedSignals]);

  const renderPlan = (plan) => (
    <div key={plan.key} className="overflow-hidden rounded-[12px] border border-line bg-surf">
      <div className="flex flex-wrap items-center gap-2 border-b border-line px-3 py-2.5">
        <div className="min-w-[240px] flex-1">
          <div className="text-sm font-semibold text-ink">
            {plan.orgao_razao || plan.orgao_cnpj} · PCA {plan.ano_pca}
          </div>
          <div className="mt-1 flex flex-wrap gap-2 text-xs text-muted">
            <span className="rounded-md border border-line bg-bg2 px-1.5 py-0.5 font-mono text-[10px]">UASG {plan.codigo_unidade}</span>
            {plan.unidade_nome && <span>{plan.unidade_nome}</span>}
            <span>{plan.items.length} item{plan.items.length !== 1 ? 's' : ''}</span>
            <span className="font-mono font-semibold text-ink">{formatPcaCurrency(plan.valor_total)}</span>
            <span className="font-mono text-[10px] text-primary">score {Number(plan.max_score || 0).toFixed(2)}</span>
          </div>
        </div>
        <a
          href={plan.pncp_url}
          target="_blank"
          rel="noopener noreferrer"
          className={`${btnSecondarySm}`}
          title="Abrir PCA no PNCP"
        >
          PNCP ↗
        </a>
      </div>
      <div className="divide-y divide-border">
        {plan.items.map(s => (
          <div key={s.id} className="flex flex-col gap-3 p-3 sm:flex-row sm:items-start">
            <div className="flex min-w-0 flex-1 items-start gap-3">
              <input type="checkbox" checked={!!selectedSignals[s.id]} onChange={() => toggleSelected(s.id)} className="mt-1.5 shrink-0" />
              <div className="min-w-0 flex-1">
                <div className="text-sm text-ink">{s.descricao}</div>
                <div className="mt-1.5 flex flex-wrap items-center gap-1.5">
                  <span className={metaChip}>Item {s.numero_item || '—'}</span>
                  {s.futura_contratacao_id && <span className={metaChip}>Contratação {s.futura_contratacao_id}</span>}
                  {s.futura_contratacao_nome && <span className={metaChip}>{s.futura_contratacao_nome}</span>}
                  <span className={metaChip}>Mês {s.mes_previsto ?? '—'}</span>
                  <span className={metaChip}>Qtd. {formatPcaQuantity(s.quantidade)}</span>
                  {s.unidade_medida && <span className={metaChip}>{s.unidade_medida}</span>}
                  <span className={metaChip}>{formatPcaCurrency(s.valor_total)}</span>
                  <span className="inline-flex items-center rounded-md bg-primary/10 px-1.5 py-0.5 font-mono text-[10px] font-semibold text-primary">Score {Number(s.score || 0).toFixed(2)}</span>
                  <span className={metaChip}>{formatPcaDate(s.criado_em)}</span>
                </div>
              </div>
            </div>
            <div className="flex flex-wrap items-center gap-1.5 sm:justify-end sm:pl-2">
              {statusFilter !== 'promovido' && (
                <>
                  {s.status !== 'novo' && (
                    <button type="button" disabled={busy[s.id]}
                      onClick={() => act(s.id, 'to_novo')}
                      className={btnSecondarySm}>Novo</button>
                  )}
                  {s.status !== 'visto' && (
                    <button type="button" disabled={busy[s.id]}
                      onClick={() => act(s.id, 'to_visto')}
                      className={btnSecondarySm}>Visto</button>
                  )}
                  {s.status !== 'descartado' && (
                    <button type="button" disabled={busy[s.id]}
                      onClick={() => act(s.id, 'to_descartado')}
                      className={btnSecondarySm}>Descartar</button>
                  )}
                </>
              )}
              {statusFilter === 'novo' && (
                <button type="button" disabled={busy[s.id]}
                  onClick={() => act(s.id, 'promote')}
                  className={btnPrimarySm}>Promover</button>
              )}
              {statusFilter === 'promovido' && (
                <button type="button" disabled={busy[s.id]}
                  onClick={() => act(s.id, 'unpromote')}
                  className={btnSecondarySm}>Despromover</button>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className={`${compact ? 'mt-0' : 'mt-4'} space-y-4`}>
      <div className="flex flex-wrap items-center gap-2">
        {['novo', 'visto', 'promovido', 'descartado'].map(s => (
          <button
            key={s}
            type="button"
            onClick={() => changeStatusFilter(s)}
            className={statusFilterPill(statusFilter === s)}
          >
            {statusFilterLabel(s)}
            {flatMode
              ? (s === statusFilter ? ` (${pageInfo.total})` : '')
              : ` (${statusCounts[s] || 0})`}
          </button>
        ))}
        <span className="inline-flex h-8 items-center font-mono text-[11px] text-muted2">
          pág. {page} · {pageInfo.total || statusCounts[statusFilter] || 0} total
        </span>
        {!flatMode && groupedSignals.length > 0 && (
          <div className="flex items-center gap-1.5">
            <button type="button" onClick={() => setAllWatchlistsCollapsed(false)} className={btnSecondarySm}>
              Expandir
            </button>
            <button type="button" onClick={() => setAllWatchlistsCollapsed(true)} className={btnSecondarySm}>
              Colapsar
            </button>
          </div>
        )}
        <span className="ml-auto inline-flex h-8 items-center text-[11px] text-muted">
          {PCA_SIGNALS_PAGE_SIZE}/página
        </span>
      </div>

      {statusFilter !== 'promovido' && (
        <div className="flex flex-wrap items-center gap-2 rounded-[12px] border border-line bg-bg2/40 px-3 py-2">
          <span className="inline-flex h-8 items-center text-xs text-muted">{selectedIds.length} selecionado(s) nesta página</span>
          {statusFilter === 'novo' && (
            <button type="button" disabled={!selectedIds.length || busy.__batch}
              onClick={() => runBatch('promote')}
              className={btnPrimarySm}>
              Promover selecionados
            </button>
          )}
          <button type="button" disabled={!selectedIds.length || busy.__batch}
            onClick={() => runBatch('status', 'visto')}
            className={btnSecondarySm}>Marcar visto</button>
          <button type="button" disabled={!selectedIds.length || busy.__batch}
            onClick={() => runBatch('status', 'descartado')}
            className={btnSecondarySm}>Descartar</button>
          <button type="button" disabled={!selectedIds.length || busy.__batch}
            onClick={() => setSelectedSignals({})}
            className={btnGhostSm}>Limpar</button>
        </div>
      )}

      {error && (
        <div className="flex flex-wrap items-center justify-between gap-2 rounded-[12px] border border-status-danger/30 bg-status-danger/10 px-3 py-2.5 text-sm text-status-danger">
          <span>{error}</span>
          <button type="button" onClick={() => load()} className="text-xs font-semibold underline">Tentar novamente</button>
        </div>
      )}

      {loading ? (
        <div className={`${subtle} py-8 text-center`}>Carregando sinais…</div>
      ) : error && signals.length === 0 ? null : signals.length === 0 ? (
        <div className="rounded-[14px] border border-dashed border-line bg-surf/60 px-4 py-10 text-center">
          <p className="text-sm font-semibold text-ink">Nenhum sinal {statusFilterLabel(statusFilter).toLowerCase()}</p>
          <p className={`${subtle} mt-1`}>Os sinais aparecem após o sync das buscas monitoradas ativas.</p>
        </div>
      ) : flatMode ? (
        <div className="space-y-2.5">
          {plansFromGroups.map(renderPlan)}
          <SignalsPaginationBar
            page={page}
            total={pageInfo.total}
            pageSize={PCA_SIGNALS_PAGE_SIZE}
            loading={loading}
            onPageChange={goToPage}
          />
        </div>
      ) : (
        <div className="space-y-3">
          {groupedSignals.map(group => {
            const isCollapsed = !!collapsedWatchlists[group.key];
            const itemLabel = group.totalCount > group.itemsCount ? `${group.itemsCount}/${group.totalCount}` : group.itemsCount;
            return (
            <div key={group.key} className="overflow-hidden rounded-[14px] border border-line bg-surf">
              <button
                type="button"
                onClick={() => toggleWatchlistCollapsed(group.key)}
                aria-expanded={!isCollapsed}
                className="flex w-full items-center gap-2 border-b border-line bg-primary/[0.07] px-3.5 py-2.5 text-left text-xs font-semibold text-primary hover:bg-primary/12"
              >
                <span className="w-4 text-center font-mono text-[10px] text-muted" aria-hidden="true">{isCollapsed ? '▸' : '▾'}</span>
                <span className="min-w-0 flex-1 truncate font-display text-[13px] font-semibold uppercase tracking-wide">{group.title}</span>
                <span className="shrink-0 rounded-md border border-primary/20 bg-surf px-2 py-0.5 font-mono text-[11px] text-primary">
                  {itemLabel} sinal{Number(group.itemsCount) === 1 ? '' : 's'}
                </span>
              </button>
              {!isCollapsed && (
              <div className="space-y-2.5 bg-bg2/30 p-3">
                {group.plans.map(renderPlan)}
              </div>
              )}
            </div>
            );
          })}
          <SignalsPaginationBar
            page={page}
            total={pageInfo.total}
            pageSize={PCA_SIGNALS_PAGE_SIZE}
            loading={loading}
            onPageChange={goToPage}
          />
        </div>
      )}
    </div>
  );
}

function PcaWatchlistsPanel({ onPromoted, listRefreshVersion = 0 }) {
  const [watchlists, setWatchlists] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [busy, setBusy] = useState({});
  const [resultsWatchlist, setResultsWatchlist] = useState(null);
  const [signalsRefreshVersion, setSignalsRefreshVersion] = useState(0);

  const loadWatchlists = useCallback(async ({ background = false } = {}) => {
    if (!background) setLoading(true);
    setError(null);
    try {
      const r = await axios.get('/api/licitacoes/pca/watchlist');
      setWatchlists(r.data || []);
    } catch (e) {
      setError(e.response?.status === 504
        ? 'A atualização demorou mais que o esperado. Vamos tentar novamente automaticamente.'
        : (e.response?.data?.error || 'Não foi possível carregar as buscas salvas agora.'));
    } finally {
      if (!background) setLoading(false);
    }
  }, []);

  useEffect(() => {
    // listRefreshVersion > 0 = recarregar em background após “Salvar e monitorar”.
    loadWatchlists({ background: listRefreshVersion > 0 });
  }, [loadWatchlists, listRefreshVersion]);

  useEffect(() => {
    let lastRefresh = Date.now();
    const refreshIfStale = () => {
      if (document.visibilityState !== 'visible' || Date.now() - lastRefresh < 60000) return;
      lastRefresh = Date.now();
      loadWatchlists({ background: true });
    };
    const intervalId = setInterval(refreshIfStale, 5 * 60 * 1000);
    document.addEventListener('visibilitychange', refreshIfStale);
    window.addEventListener('focus', refreshIfStale);
    return () => {
      clearInterval(intervalId);
      document.removeEventListener('visibilitychange', refreshIfStale);
      window.removeEventListener('focus', refreshIfStale);
    };
  }, [loadWatchlists]);

  useEffect(() => {
    if (!resultsWatchlist) return;
    const next = watchlists.find(w => w.id === resultsWatchlist.id);
    if (next && next !== resultsWatchlist) setResultsWatchlist(next);
  }, [watchlists, resultsWatchlist]);

  const refreshAfterSignals = useCallback(() => {
    setSignalsRefreshVersion(v => v + 1);
    loadWatchlists({ background: true });
  }, [loadWatchlists]);

  const openResults = (row) => setResultsWatchlist(row);
  const closeResults = () => {
    setResultsWatchlist(null);
    refreshAfterSignals();
  };

  const toggleAtivo = async (row) => {
    setBusy(prev => ({ ...prev, [row.id]: true }));
    try {
      await axios.put(`/api/licitacoes/pca/watchlist/${row.id}`, { ativo: !row.ativo });
      await loadWatchlists();
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [row.id]: false }));
    }
  };

  const removeWatchlist = async (row) => {
    if (!window.confirm(`Excluir a busca salva "${row.nome}"?`)) return;
    setBusy(prev => ({ ...prev, [row.id]: true }));
    try {
      await axios.delete(`/api/licitacoes/pca/watchlist/${row.id}`);
      if (resultsWatchlist?.id === row.id) setResultsWatchlist(null);
      await loadWatchlists();
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [row.id]: false }));
    }
  };

  const [whatsappTarget, setWhatsappTarget] = useState(null);

  const saveWhatsapp = async (payload) => {
    if (!whatsappTarget) return;
    const row = whatsappTarget;
    setBusy(prev => ({ ...prev, [`wa:${row.id}`]: true }));
    try {
      await axios.put(`/api/licitacoes/pca/watchlist/${row.id}`, {
        whatsapp_enabled: payload.whatsapp_enabled,
        whatsapp_number: payload.whatsapp_number,
        whatsapp_numbers: payload.whatsapp_numbers,
        whatsapp_min_score: payload.whatsapp_min_score,
        whatsapp_score_band: payload.whatsapp_score_band,
      });
      setWhatsappTarget(null);
      await loadWatchlists({ background: true });
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [`wa:${row.id}`]: false }));
    }
  };

  return (
    <div className="mt-3 space-y-3">
      {error && (
        <div className="flex flex-wrap items-center justify-between gap-2 rounded-[12px] border border-status-danger/30 bg-status-danger/10 px-3 py-2.5 text-sm text-status-danger">
          <span>{error}</span>
          <button type="button" onClick={() => loadWatchlists()} className="text-xs font-semibold underline">Tentar novamente</button>
        </div>
      )}

      {loading ? (
        <div className={`${subtle} py-8 text-center`}>Carregando buscas salvas…</div>
      ) : error && watchlists.length === 0 ? null : watchlists.length === 0 ? (
        <div className="rounded-[14px] border border-dashed border-line bg-surf/60 px-4 py-10 text-center">
          <p className="text-sm font-semibold text-ink">Nenhuma busca salva ainda</p>
          <p className={`${subtle} mt-1 mx-auto max-w-md`}>
            Monte os termos acima e use <strong>Salvar e monitorar</strong> — a busca vira este card e continua gerando sinais.
          </p>
        </div>
      ) : (
        <div className="grid items-stretch gap-3 md:grid-cols-2">
          {watchlists.map(w => {
            const novos = Number(w.sinais_novos || 0);
            const totalSinais = Number(w.sinais_total || 0);
            return (
              <div key={w.id} className={`${entityCard} ${w.ativo ? '' : 'opacity-75'}`}>
                <button type="button" onClick={() => openResults(w)} className="min-w-0 flex-1 text-left">
                  <div className="flex items-center justify-between gap-2">
                    <div className="min-w-0">
                      <p className="truncate font-display text-[13px] font-semibold uppercase tracking-wide text-ink hover:text-primary">{w.nome}</p>
                      <p className="mt-0.5 font-mono text-[10px] text-muted2">criada {formatPcaDate(w.criado_em)}</p>
                    </div>
                    <span className={w.ativo ? statusPillActive : statusPillInactive}>
                      {w.ativo ? 'Ativa' : 'Inativa'}
                    </span>
                  </div>
                  <div className="mt-2.5 flex flex-wrap items-center gap-1.5">
                    <span className={metaChip}>IA: {w.usar_ia ? 'sim' : 'não'}</span>
                    <span className={metaChip}>
                      Sinais: {totalSinais.toLocaleString('pt-BR')}
                      {novos > 0 ? ` · ${novos} novo${novos === 1 ? '' : 's'}` : ''}
                    </span>
                  </div>
                  <div className="mt-2.5 flex min-h-[1.75rem] flex-1 flex-col gap-1.5">
                    {(w.palavras_chave || []).length > 0 && (
                      <div className="flex flex-wrap content-start gap-1">
                        {(w.palavras_chave || []).slice(0, 6).map(t => (
                          <span key={t} className={termChip}>{t}</span>
                        ))}
                        {(w.palavras_chave || []).length > 6 && (
                          <span className={metaChip}>+{(w.palavras_chave || []).length - 6}</span>
                        )}
                      </div>
                    )}
                    {(w.termos_negativos || []).length > 0 && (
                      <div className="flex flex-wrap content-start gap-1">
                        {(w.termos_negativos || []).slice(0, 4).map(t => (
                          <span key={t} className={termChipNeg}>− {t}</span>
                        ))}
                      </div>
                    )}
                  </div>
                </button>
                <div className={cardActionBar}>
                  <button type="button" onClick={() => openResults(w)} className={btnSecondaryXs}>
                    Resultados
                  </button>
                  <button type="button" disabled={busy[w.id]} onClick={() => toggleAtivo(w)} className={btnSecondaryXs}>
                    {w.ativo ? 'Desativar' : 'Ativar'}
                  </button>
                  <button
                    type="button"
                    disabled={busy[`wa:${w.id}`]}
                    onClick={() => setWhatsappTarget(w)}
                    className={`${btnSecondaryXs} min-w-[2rem] px-2`}
                    title={whatsappAlertActionTitle({
                      subscribed: true,
                      alertsOn: Boolean(w.whatsapp_enabled && (w.whatsapp_number || w.whatsapp_numbers?.length)),
                      number: w.whatsapp_number,
                      numbers: w.whatsapp_numbers,
                      minScore: w.whatsapp_min_score,
                    })}
                    aria-label={whatsappAlertActionAria({
                      subscribed: true,
                      alertsOn: Boolean(w.whatsapp_enabled && (w.whatsapp_number || w.whatsapp_numbers?.length)),
                    })}
                  >
                    <WhatsappAlertActionContent
                      subscribed
                      alertsOn={Boolean(w.whatsapp_enabled && (w.whatsapp_number || w.whatsapp_numbers?.length))}
                    />
                  </button>
                  <button type="button" disabled={busy[w.id]} onClick={() => removeWatchlist(w)} className={`${btnDangerGhost} ml-auto`}>
                    Excluir
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      <WatchlistWhatsappDialog
        open={Boolean(whatsappTarget)}
        watchlistName={whatsappTarget?.nome}
        initialNumber={whatsappTarget?.whatsapp_number || ''}
        initialNumbers={whatsappTarget?.whatsapp_numbers || null}
        initialEnabled={Boolean(whatsappTarget?.whatsapp_enabled && (whatsappTarget?.whatsapp_number || whatsappTarget?.whatsapp_numbers?.length))}
        initialMinScore={whatsappTarget?.whatsapp_min_score}
        initialScoreBand={whatsappTarget?.whatsapp_score_band}
        saving={Boolean(whatsappTarget && busy[`wa:${whatsappTarget.id}`])}
        onClose={() => { if (!(whatsappTarget && busy[`wa:${whatsappTarget.id}`])) setWhatsappTarget(null); }}
        onSave={saveWhatsapp}
      />

      {resultsWatchlist && createPortal(
        <div className={modalOverlay} onClick={closeResults} role="presentation">
          <div
            className="flex w-full max-w-5xl max-h-[92vh] flex-col overflow-hidden rounded-[16px] border border-border bg-card shadow-lift dark:bg-[#111827] dark:border-[#1f2937]"
            onClick={(event) => event.stopPropagation()}
            role="dialog"
            aria-modal="true"
            aria-label={`Sinais da busca ${resultsWatchlist.nome}`}
          >
            <div className="flex shrink-0 items-start justify-between gap-3 border-b border-line px-4 py-3.5 sm:px-5">
              <div className="min-w-0">
                <h3 className="truncate font-display text-base font-semibold uppercase tracking-wide text-ink">
                  {resultsWatchlist.nome}
                </h3>
                <p className="mt-1 font-mono text-[11px] text-muted">
                  {Number(resultsWatchlist.sinais_total || 0).toLocaleString('pt-BR')} sinal(is)
                  {Number(resultsWatchlist.sinais_novos || 0) > 0
                    ? ` · ${Number(resultsWatchlist.sinais_novos).toLocaleString('pt-BR')} novo(s)`
                    : ''}
                  {' · '}promova para o board quando fizer sentido
                </p>
              </div>
              <button type="button" onClick={closeResults} className={iconBtn} aria-label="Fechar">
                <XMarkIcon className="h-5 w-5" />
              </button>
            </div>
            <VerticalScrollArrows className="min-h-0 flex-1" contentClassName="px-4 py-4 sm:px-5">
              <PcaSignalsPanel
                watchlistId={resultsWatchlist.id}
                compact
                onPromoted={onPromoted}
                refreshVersion={signalsRefreshVersion}
                onChanged={refreshAfterSignals}
              />
            </VerticalScrollArrows>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

function EditalWatchlistsPanel({ onSignalsChanged, onImportSignal, onNewCountChange, listRefreshVersion = 0 }) {
  const [watchlists, setWatchlists] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [busy, setBusy] = useState({});
  const [resultsWatchlist, setResultsWatchlist] = useState(null);
  const [signalsRefreshVersion, setSignalsRefreshVersion] = useState(0);

  const loadWatchlists = useCallback(async ({ background = false } = {}) => {
    if (!background) setLoading(true);
    setError(null);
    try {
      const r = await axios.get('/api/licitacoes/editais/watchlist');
      setWatchlists(r.data || []);
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally {
      if (!background) setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadWatchlists({ background: listRefreshVersion > 0 });
  }, [loadWatchlists, listRefreshVersion]);

  useEffect(() => {
    if (!resultsWatchlist) return;
    const next = watchlists.find(w => w.id === resultsWatchlist.id);
    if (next && next !== resultsWatchlist) setResultsWatchlist(next);
  }, [watchlists, resultsWatchlist]);

  const refreshAfterSignals = useCallback(() => {
    setSignalsRefreshVersion(v => v + 1);
    loadWatchlists({ background: true });
    onSignalsChanged?.();
  }, [loadWatchlists, onSignalsChanged]);

  const toggleAtivo = async (row) => {
    setBusy(prev => ({ ...prev, [row.id]: true }));
    try {
      await axios.put(`/api/licitacoes/editais/watchlist/${row.id}`, { ativo: !row.ativo });
      await loadWatchlists();
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [row.id]: false }));
    }
  };

  const [whatsappTarget, setWhatsappTarget] = useState(null);

  const saveWhatsapp = async (payload) => {
    if (!whatsappTarget) return;
    const row = whatsappTarget;
    setBusy(prev => ({ ...prev, [`wa:${row.id}`]: true }));
    try {
      await axios.put(`/api/licitacoes/editais/watchlist/${row.id}`, {
        whatsapp_enabled: payload.whatsapp_enabled,
        whatsapp_number: payload.whatsapp_number,
        whatsapp_numbers: payload.whatsapp_numbers,
        whatsapp_min_score: payload.whatsapp_min_score,
        whatsapp_score_band: payload.whatsapp_score_band,
      });
      setWhatsappTarget(null);
      await loadWatchlists({ background: true });
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [`wa:${row.id}`]: false }));
    }
  };

  const removeWatchlist = async (row) => {
    if (!window.confirm(`Excluir watchlist "${row.nome}"?`)) return;
    setBusy(prev => ({ ...prev, [row.id]: true }));
    try {
      await axios.delete(`/api/licitacoes/editais/watchlist/${row.id}`);
      if (resultsWatchlist?.id === row.id) setResultsWatchlist(null);
      await loadWatchlists();
      onSignalsChanged?.();
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [row.id]: false }));
    }
  };

  const openResults = (row) => setResultsWatchlist(row);
  const closeResults = () => {
    setResultsWatchlist(null);
    refreshAfterSignals();
  };

  return (
    <div className="mt-4 space-y-3">
      <div className="toolbar-meta">
        <p className={subtle}>Regras salvas são verificadas no sync. Clique no card para ver os resultados no popup.</p>
        <button type="button" onClick={loadWatchlists} className={`${btnSecondarySm} justify-self-start sm:justify-self-end`}>
          <ArrowPathIcon className="h-3.5 w-3.5" /> Atualizar
        </button>
      </div>
      {error && <div className="rounded-[12px] border border-status-danger/30 bg-status-danger/10 px-3 py-2.5 text-sm text-status-danger">{error}</div>}
      {loading ? (
        <div className={`${subtle} py-8 text-center`}>Carregando assinaturas…</div>
      ) : watchlists.length === 0 ? (
        <div className="rounded-[14px] border border-dashed border-line bg-surf/60 px-4 py-10 text-center">
          <p className="text-sm font-semibold text-ink">Nenhuma assinatura de editais</p>
          <p className={`${subtle} mt-1 mx-auto max-w-md`}>Na Busca Editais, use <strong>Assinar</strong> no card do job — a busca vira assinatura (WhatsApp opcional para novidades).</p>
        </div>
      ) : (
        <div className="grid items-stretch gap-3 md:grid-cols-2">
          {watchlists.map(w => {
            const novos = Number(w.sinais_novos || 0);
            const totalSinais = Number(w.sinais_total || 0);
            return (
              <div key={w.id} className={`${entityCard} ${w.ativo ? '' : 'opacity-75'}`}>
                <button type="button" onClick={() => openResults(w)} className="min-w-0 flex-1 text-left">
                  <div className="flex items-center justify-between gap-2">
                    <div className="min-w-0">
                      <p className="truncate font-display text-[13px] font-semibold uppercase tracking-wide text-ink hover:text-primary">{w.nome}</p>
                      <p className="mt-0.5 font-mono text-[10px] text-muted2">criada {formatPcaDate(w.criado_em)}</p>
                    </div>
                    <span className={w.ativo ? statusPillActive : statusPillInactive}>
                      {w.ativo ? 'Ativa' : 'Inativa'}
                    </span>
                  </div>
                  <div className="mt-2.5 flex flex-wrap items-center gap-1.5">
                    <span className={metaChip}>IA: {w.usar_ia ? 'sim' : 'não'}</span>
                    <span className={metaChip}>
                      Resultados: {totalSinais.toLocaleString('pt-BR')}
                      {novos > 0 ? ` · ${novos} novo${novos === 1 ? '' : 's'}` : ''}
                    </span>
                  </div>
                  <div className="mt-2.5 flex min-h-[1.75rem] flex-1 flex-col gap-1.5">
                    {(w.palavras_chave || []).length > 0 && (
                      <div className="flex flex-wrap content-start gap-1">
                        {(w.palavras_chave || []).slice(0, 6).map(t => (
                          <span key={t} className={termChip}>{t}</span>
                        ))}
                        {(w.palavras_chave || []).length > 6 && (
                          <span className={metaChip}>+{(w.palavras_chave || []).length - 6}</span>
                        )}
                      </div>
                    )}
                    {(w.termos_negativos || []).length > 0 && (
                      <div className="flex flex-wrap content-start gap-1">
                        {(w.termos_negativos || []).slice(0, 4).map(t => (
                          <span key={t} className={termChipNeg}>− {t}</span>
                        ))}
                      </div>
                    )}
                  </div>
                </button>
                <div className={cardActionBar}>
                  <button type="button" onClick={() => openResults(w)} className={btnSecondaryXs}>
                    Resultados
                  </button>
                  <button type="button" disabled={busy[w.id]} onClick={() => toggleAtivo(w)} className={btnSecondaryXs}>
                    {w.ativo ? 'Desativar' : 'Ativar'}
                  </button>
                  <button
                    type="button"
                    disabled={busy[`wa:${w.id}`]}
                    onClick={() => setWhatsappTarget(w)}
                    className={`${btnSecondaryXs} min-w-[2rem] px-2`}
                    title={whatsappAlertActionTitle({
                      subscribed: true,
                      alertsOn: Boolean(w.whatsapp_enabled && (w.whatsapp_number || w.whatsapp_numbers?.length)),
                      number: w.whatsapp_number,
                      numbers: w.whatsapp_numbers,
                      minScore: w.whatsapp_min_score,
                    })}
                    aria-label={whatsappAlertActionAria({
                      subscribed: true,
                      alertsOn: Boolean(w.whatsapp_enabled && (w.whatsapp_number || w.whatsapp_numbers?.length)),
                    })}
                  >
                    <WhatsappAlertActionContent
                      subscribed
                      alertsOn={Boolean(w.whatsapp_enabled && (w.whatsapp_number || w.whatsapp_numbers?.length))}
                    />
                  </button>
                  <button type="button" disabled={busy[w.id]} onClick={() => removeWatchlist(w)} className={`${btnDangerGhost} ml-auto`}>
                    Excluir
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      <WatchlistWhatsappDialog
        open={Boolean(whatsappTarget)}
        watchlistName={whatsappTarget?.nome}
        initialNumber={whatsappTarget?.whatsapp_number || ''}
        initialNumbers={whatsappTarget?.whatsapp_numbers || null}
        initialEnabled={Boolean(whatsappTarget?.whatsapp_enabled && (whatsappTarget?.whatsapp_number || whatsappTarget?.whatsapp_numbers?.length))}
        initialMinScore={whatsappTarget?.whatsapp_min_score}
        initialScoreBand={whatsappTarget?.whatsapp_score_band}
        saving={Boolean(whatsappTarget && busy[`wa:${whatsappTarget.id}`])}
        onClose={() => { if (!(whatsappTarget && busy[`wa:${whatsappTarget.id}`])) setWhatsappTarget(null); }}
        onSave={saveWhatsapp}
      />

      {resultsWatchlist && createPortal(
        <div className={modalOverlay} onClick={closeResults} role="presentation">
          <div
            className="flex w-full max-w-5xl max-h-[92vh] flex-col overflow-hidden rounded-[16px] border border-border bg-card shadow-lift dark:bg-[#111827] dark:border-[#1f2937]"
            onClick={(event) => event.stopPropagation()}
            role="dialog"
            aria-modal="true"
            aria-label={`Resultados da watchlist ${resultsWatchlist.nome}`}
          >
            <div className="flex shrink-0 items-start justify-between gap-3 border-b border-line px-4 py-3.5 sm:px-5">
              <div className="min-w-0">
                <h3 className="truncate font-display text-base font-semibold uppercase tracking-wide text-ink">
                  {resultsWatchlist.nome}
                </h3>
                <p className="mt-1 font-mono text-[11px] text-muted">
                  {Number(resultsWatchlist.sinais_total || 0).toLocaleString('pt-BR')} resultado(s)
                  {Number(resultsWatchlist.sinais_novos || 0) > 0
                    ? ` · ${Number(resultsWatchlist.sinais_novos).toLocaleString('pt-BR')} novo(s)`
                    : ''}
                  {' · '}editais capturados por esta watchlist
                </p>
              </div>
              <button type="button" onClick={closeResults} className={iconBtn} aria-label="Fechar">
                <XMarkIcon className="h-5 w-5" />
              </button>
            </div>
            <VerticalScrollArrows className="min-h-0 flex-1" contentClassName="px-4 py-4 sm:px-5">
              <EditalSignalsPanel
                watchlistId={resultsWatchlist.id}
                compact
                onImportSignal={onImportSignal}
                onNewCountChange={onNewCountChange}
                refreshVersion={signalsRefreshVersion}
                onChanged={refreshAfterSignals}
              />
            </VerticalScrollArrows>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

function EditalSignalsPanel({
  onImportSignal,
  onNewCountChange,
  refreshVersion = 0,
  watchlistId = null,
  compact = false,
  onChanged,
}) {
  const [signals, setSignals] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [statusFilter, setStatusFilter] = useState('novo');
  const [page, setPage] = useState(1);
  const [statusCounts, setStatusCounts] = useState({ novo: 0, visto: 0, promovido: 0, descartado: 0 });
  const [pageInfo, setPageInfo] = useState({ total: 0, pageSize: EDITAL_SIGNALS_PAGE_SIZE });
  const [busy, setBusy] = useState({});
  const [collapsedWatchlists, setCollapsedWatchlists] = useState({});

  const loadCounts = useCallback(async () => {
    try {
      const r = await axios.get('/api/licitacoes/editais/signals/stats');
      const nextCounts = {
        novo: Number(r.data?.novo) || 0,
        visto: Number(r.data?.visto) || 0,
        promovido: Number(r.data?.promovido) || 0,
        descartado: Number(r.data?.descartado) || 0,
      };
      setStatusCounts(nextCounts);
      onNewCountChange?.(getNewEditalSignalsCount(nextCounts));
    } catch {
      setStatusCounts({ novo: 0, visto: 0, promovido: 0, descartado: 0 });
    }
  }, [onNewCountChange]);

  const load = useCallback(async ({ pageOverride } = {}) => {
    const activePage = Math.max(1, pageOverride ?? page);
    setLoading(true);
    setError(null);
    try {
      const offset = (activePage - 1) * EDITAL_SIGNALS_PAGE_SIZE;
      const r = await axios.get('/api/licitacoes/editais/signals', {
        params: {
          status: statusFilter,
          limit: EDITAL_SIGNALS_PAGE_SIZE,
          offset,
          ...(watchlistId ? { watchlist_id: watchlistId } : {}),
        },
      });
      const rows = r.data?.data || [];
      const total = Number(r.data?.total) || 0;
      const totalPages = Math.max(1, Math.ceil(total / EDITAL_SIGNALS_PAGE_SIZE));
      if (rows.length === 0 && total > 0 && activePage > totalPages) {
        setPage(totalPages);
        return;
      }
      setSignals(rows);
      setPageInfo({ total, pageSize: EDITAL_SIGNALS_PAGE_SIZE });
      loadCounts();
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally {
      setLoading(false);
    }
  }, [statusFilter, loadCounts, watchlistId, page]);

  useEffect(() => { setPage(1); }, [watchlistId]);

  useEffect(() => { load(); }, [load, refreshVersion]);

  const changeStatusFilter = (nextStatus) => {
    setStatusFilter(nextStatus);
    setPage(1);
  };

  const goToPage = (nextPage) => {
    const totalPages = Math.max(1, Math.ceil((pageInfo.total || 0) / EDITAL_SIGNALS_PAGE_SIZE));
    setPage(Math.min(Math.max(1, nextPage), totalPages));
  };

  const groupedSignals = useMemo(() => groupEditalSignalsByWatchlist(signals), [signals]);
  const flatMode = Boolean(watchlistId) || compact;

  const setStatus = async (row, status) => {
    setBusy(prev => ({ ...prev, [row.id]: true }));
    try {
      await axios.put(`/api/licitacoes/editais/signals/${row.id}/status`, { status });
      await load();
      onChanged?.();
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setBusy(prev => ({ ...prev, [row.id]: false }));
    }
  };

  const renderSignalRow = (s) => {
    const item = s.payload || {};
    return (
      <div key={s.id} className="flex flex-col gap-3 p-3.5 sm:flex-row sm:items-start">
        <div className="min-w-0 flex-1">
          <div className="text-sm font-semibold text-ink">{item.titulo || item.title || 'Edital PNCP'}</div>
          <div className="mt-1 line-clamp-2 text-xs text-muted">{item.descricao || item.description}</div>
          <div className="mt-2 flex flex-wrap items-center gap-1.5">
            <span className={metaChip}>{item.orgao?.nome || item.orgao_nome || 'Órgão n/d'}</span>
            {item.unidade?.codigo && <span className={`${metaChip} font-mono`}>UASG {item.unidade.codigo}</span>}
            {item.prazo_info?.label && <span className={metaChip}>{item.prazo_info.label}</span>}
            <span className="inline-flex items-center rounded-md bg-primary/10 px-1.5 py-0.5 font-mono text-[10px] font-semibold text-primary">score {Number(s.score || 0).toFixed(2)}</span>
          </div>
        </div>
        <div className="flex shrink-0 flex-wrap items-center gap-1.5 sm:justify-end">
          {item.url && (
            <a href={item.url} target="_blank" rel="noopener noreferrer" className={btnSecondarySm}>PNCP ↗</a>
          )}
          {statusFilter !== 'promovido' && onImportSignal && (
            <button
              type="button"
              disabled={busy[s.id]}
              onClick={async () => {
                await onImportSignal(item, s.id);
                onChanged?.();
                load();
              }}
              className={btnPrimarySm}
            >
              Importar
            </button>
          )}
          {s.status !== 'visto' && (
            <button type="button" disabled={busy[s.id]} onClick={() => setStatus(s, 'visto')} className={btnSecondarySm}>Visto</button>
          )}
          {s.status !== 'descartado' && (
            <button type="button" disabled={busy[s.id]} onClick={() => setStatus(s, 'descartado')} className={btnSecondarySm}>Descartar</button>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className={`${compact ? 'mt-0' : 'mt-4'} space-y-4`}>
      <div className="flex flex-wrap items-center gap-2">
        {['novo', 'visto', 'promovido', 'descartado'].map(s => (
          <button key={s} type="button" onClick={() => changeStatusFilter(s)} className={statusFilterPill(statusFilter === s)}>
            {statusFilterLabel(s)}
            {flatMode
              ? (s === statusFilter ? ` (${pageInfo.total})` : '')
              : ` (${statusCounts[s] || 0})`}
          </button>
        ))}
        <span className="font-mono text-[11px] text-muted2">
          pág. {page} · {pageInfo.total || statusCounts[statusFilter] || 0} total
        </span>
        <button type="button" onClick={() => load()} className={`${btnSecondarySm} ml-auto`}>
          <ArrowPathIcon className="h-3.5 w-3.5" /> Atualizar
        </button>
      </div>
      {error && <div className="rounded-[12px] border border-status-danger/30 bg-status-danger/10 px-3 py-2.5 text-sm text-status-danger">{error}</div>}
      {loading ? (
        <div className={`${subtle} py-8 text-center`}>Carregando sinais…</div>
      ) : signals.length === 0 ? (
        <div className="rounded-[14px] border border-dashed border-line bg-surf/60 px-4 py-10 text-center">
          <p className="text-sm font-semibold text-ink">Nenhum sinal {statusFilterLabel(statusFilter).toLowerCase()}</p>
          <p className={`${subtle} mt-1`}>Rode o sync ou aguarde o ciclo automático das watchlists ativas.</p>
        </div>
      ) : flatMode ? (
        <div className="space-y-3">
          <div className="overflow-hidden rounded-[14px] border border-line bg-surf divide-y divide-line">
            {signals.map(renderSignalRow)}
          </div>
          <SignalsPaginationBar
            page={page}
            total={pageInfo.total}
            pageSize={EDITAL_SIGNALS_PAGE_SIZE}
            loading={loading}
            onPageChange={goToPage}
          />
        </div>
      ) : (
        <div className="space-y-3">
          {groupedSignals.map(group => {
            const isCollapsed = !!collapsedWatchlists[group.key];
            return (
              <div key={group.key} className="overflow-hidden rounded-[14px] border border-line bg-surf">
                <button type="button" onClick={() => setCollapsedWatchlists(prev => ({ ...prev, [group.key]: !prev[group.key] }))}
                  aria-expanded={!isCollapsed}
                  className="flex w-full items-center gap-2 border-b border-line bg-primary/[0.07] px-3.5 py-2.5 text-left text-xs font-semibold text-primary hover:bg-primary/12">
                  <span className="w-4 text-center font-mono text-[10px] text-muted" aria-hidden="true">{isCollapsed ? '▸' : '▾'}</span>
                  <span className="min-w-0 flex-1 truncate font-display text-[13px] font-semibold uppercase tracking-wide">{group.title}</span>
                  <span className="shrink-0 rounded-md border border-primary/20 bg-surf px-2 py-0.5 font-mono text-[11px] text-primary">{group.itemsCount} sinais</span>
                </button>
                {!isCollapsed && (
                  <div className="divide-y divide-line">
                    {group.items.map(renderSignalRow)}
                  </div>
                )}
              </div>
            );
          })}
          <SignalsPaginationBar
            page={page}
            total={pageInfo.total}
            pageSize={EDITAL_SIGNALS_PAGE_SIZE}
            loading={loading}
            onPageChange={goToPage}
          />
        </div>
      )}
    </div>
  );
}

function EditalWatchlistPage({ onImportSignal, onNewCountChange }) {
  const [syncing, setSyncing] = useState(false);
  const [listRefreshVersion, setListRefreshVersion] = useState(0);

  const refreshBadge = useCallback(async () => {
    try {
      // Mantém contadores internos da watchlist; o badge do menu é contagem de pesquisas.
      const response = await axios.get('/api/licitacoes/editais/signals/stats');
      onNewCountChange?.(getNewEditalSignalsCount(response.data));
    } catch {
      /* best-effort */
    }
  }, [onNewCountChange]);

  useEffect(() => {
    refreshBadge();
  }, [refreshBadge]);

  const handleSignalsChanged = useCallback(() => {
    setListRefreshVersion(v => v + 1);
    refreshBadge();
  }, [refreshBadge]);

  const syncNow = async () => {
    setSyncing(true);
    try {
      const r = await axios.post('/api/licitacoes/editais/sync');
      handleSignalsChanged();
      alert(`Sync concluído: ${r.data?.signals_inserted || 0} novo(s) sinal(is).`);
    } catch (e) {
      alert(`Erro: ${e.response?.data?.error || e.message}`);
    } finally {
      setSyncing(false);
    }
  };
  return (
    <div className="mt-6 space-y-5">
      <section className="rounded-[16px] border border-line bg-surf p-4 md:p-5">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div>
            <h3 className={`${sectionTitle} text-base`}>Watchlists de editais</h3>
            <p className={`${subtle} mt-0.5`}>
              Mesmo estilo das watchlists PCA. Resultados abrem no popup do card — não numa lista fora.
            </p>
          </div>
          <button type="button" disabled={syncing} onClick={syncNow} className={`${btnPrimarySm}`}>
            {syncing ? 'Sincronizando…' : 'Rodar sync'}
          </button>
        </div>
        <EditalWatchlistsPanel
          listRefreshVersion={listRefreshVersion}
          onImportSignal={onImportSignal}
          onNewCountChange={onNewCountChange}
          onSignalsChanged={refreshBadge}
        />
      </section>
    </div>
  );
}

const fetchPncpSearchJobsCount = async () => {
  const response = await axios.get('/api/licitacoes/pncp/search/jobs');
  return getCurrentPncpSearchJobsCount(Array.isArray(response.data) ? response.data : []);
};

// ===================== /PCA =====================

/** RFB filter ops — module-level so inputs do not remount on every App keystroke. */
const RFB_OP_LIST = [['contains', '∋'], ['not_contains', '∌'], ['starts', '^'], ['ends', '$'], ['exact', '=']];
const RFB_OP_TITLES = {
  contains: 'Contém',
  not_contains: 'Não contém',
  starts: 'Começa com',
  ends: 'Termina com',
  exact: 'Igual a',
};

const RfbOpPills = memo(function RfbOpPills({ val, set, compact }) {
  return (
    <div className={`flex shrink-0 items-center gap-0.5 ${compact ? '' : 'flex-wrap'}`}>
      {RFB_OP_LIST.map(([op, sym]) => (
        <button
          key={op}
          type="button"
          onClick={() => set(op)}
          title={RFB_OP_TITLES[op]}
          className={`h-6 min-w-[22px] rounded-md border px-1 text-[11px] leading-none transition ${
            val === op
              ? 'border-primary bg-primary text-white'
              : 'border-transparent text-muted2 hover:border-line hover:bg-bg2 hover:text-ink'
          }`}
        >
          {sym}
        </button>
      ))}
    </div>
  );
});

const RfbLogicToggle = memo(function RfbLogicToggle({ val, set }) {
  return (
    <div className="flex gap-0.5">
      {['AND', 'OR'].map((l) => (
        <button
          key={l}
          type="button"
          onClick={() => set(l)}
          className={`h-6 rounded-md border px-2 text-[11px] font-medium leading-none transition ${
            val === l
              ? 'border-primary bg-primary/90 text-white'
              : 'border-line bg-bg2 text-muted hover:text-ink'
          }`}
        >
          {l === 'AND' ? 'E' : 'OU'}
        </button>
      ))}
    </div>
  );
});

const RfbOpInput = memo(function RfbOpInput({ op, setOp, value, onChange, placeholder, onEnter }) {
  return (
    <div className="flex h-9 w-full min-w-0 items-stretch overflow-hidden rounded-[11px] border border-line bg-bg2 transition focus-within:border-primary/40 focus-within:ring-2 focus-within:ring-primary/30">
      <div className="flex items-center gap-0.5 border-r border-line bg-raise/30 px-1">
        <RfbOpPills val={op} set={setOp} compact />
      </div>
      <input
        type="text"
        className="min-w-0 flex-1 bg-transparent px-2.5 text-xs text-ink outline-none placeholder:text-muted"
        placeholder={placeholder}
        value={value}
        onChange={onChange}
        onKeyDown={(e) => {
          if (e.key === 'Enter') onEnter?.();
        }}
      />
    </div>
  );
});

const RfbSecondTerm = memo(function RfbSecondTerm({
  logic,
  setLogic,
  op,
  setOp,
  value,
  onChange,
  placeholder,
  onEnter,
}) {
  return (
    <div className="mt-1.5 space-y-1.5 rounded-[11px] border border-dashed border-line bg-bg2/60 p-2">
      <div className="flex flex-wrap items-center gap-1.5">
        <RfbLogicToggle val={logic} set={setLogic} />
        <span className="text-[10px] text-muted2">segundo termo</span>
      </div>
      <RfbOpInput
        op={op}
        setOp={setOp}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        onEnter={onEnter}
      />
    </div>
  );
});

/** Process page section shell — stable type so children keep focus across re-renders. */
const ProcessSection = memo(function ProcessSection({ id, children, isActive }) {
  return (
    <section
      id={id}
      className={`scroll-mt-3 rounded-[16px] border border-line bg-surf p-4 lg:p-5 ${
        isActive ? 'border-primary/25' : ''
      } dark:bg-[#141a28] dark:border-[#232c40]`}
    >
      {children}
    </section>
  );
});

const ProcessSectionHeader = memo(function ProcessSectionHeader({ kicker, title, hint, right }) {
  return (
    <div className="flex flex-wrap items-end justify-between gap-2">
      <div className="min-w-0">
        {kicker && (
          <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.1em] text-muted2">{kicker}</p>
        )}
        {title && <h3 className="mt-0.5 text-[15px] font-semibold text-ink">{title}</h3>}
        {hint && <p className="mt-1 text-xs text-muted">{hint}</p>}
      </div>
      {right}
    </div>
  );
});

