  const selectedPncpOrgao = useMemo(() => {
    if (!pncpSearchFilters.orgao_cnpj) {
      return null;
    }
    return pncpOrgaoOptions.find(item => String(item.cnpj || '') === String(pncpSearchFilters.orgao_cnpj)) || null;
  }, [pncpOrgaoOptions, pncpSearchFilters.orgao_cnpj]);

  const selectedPncpUasg = useMemo(() => {
    if (!pncpSearchFilters.unidade_codigo) {
      return null;
    }
    return pncpUasgOptions.find(item => String(item.codigo || '') === String(pncpSearchFilters.unidade_codigo)) || null;
  }, [pncpUasgOptions, pncpSearchFilters.unidade_codigo]);

  const selectedPncpTipoInstrumento = useMemo(() => {
    if (!pncpSearchFilters.tipo_id) {
      return null;
    }
    return tipoInstrumentoOptions.find(item => String(item.id || '') === String(pncpSearchFilters.tipo_id)) || null;
  }, [tipoInstrumentoOptions, pncpSearchFilters.tipo_id]);

  const pncpEditalTipoInstrumentoOptions = useMemo(
    () => tipoInstrumentoOptions.filter(item => item.bucket !== 'resultado'),
    [tipoInstrumentoOptions]
  );

  const pncpInPipelineIndex = useMemo(() => {
    const controls = new Set();
    const paths = new Set();
    const ids = new Set();

    licitacaoOpportunities.forEach(opportunity => {
      const metadata = opportunity?.metadados || {};
      const controlCandidates = [
        opportunity?.numero_compra,
        metadata?.pncp_numero_controle,
      ];
      controlCandidates.forEach(candidate => {
        const normalized = normalizePncpControlId(candidate);
        if (normalized) {
          controls.add(normalized);
        }
      });

      const idCandidate = String(metadata?.pncp_id || '').trim();
      if (idCandidate) {
        ids.add(idCandidate);
      }

      const pathCandidates = [
        opportunity?.links_pncp,
        opportunity?.links?.pncp,
      ];
      pathCandidates.forEach(candidate => {
        const pathKey = extractPncpPathKey(candidate);
        if (pathKey) {
          paths.add(pathKey);
        }
      });
    });

    return { controls, paths, ids };
  }, [licitacaoOpportunities]);

  const getPncpResultVisibility = useCallback((item) => {
    // Preferência: coluna do DB (após PATCH); depois localStorage legado; pipeline do board.
    if (item.__visibility_db === 'hidden' || pncpHiddenIds.includes(item.id)) {
      return 'hidden';
    }
    if (item.__visibility_db === 'pipeline') {
      return 'pipeline';
    }
    const controlId = normalizePncpControlId(item.numero_controle_pncp);
    if (controlId && pncpInPipelineIndex.controls.has(controlId)) {
      return 'pipeline';
    }
    const pathKey = extractPncpPathKey(item.url || item.item_url);
    if (pathKey && pncpInPipelineIndex.paths.has(pathKey)) {
      return 'pipeline';
    }
    const itemId = String(item.id || '').trim();
    if (itemId && pncpInPipelineIndex.ids.has(itemId)) {
      return 'pipeline';
    }
    return 'visible';
  }, [pncpHiddenIds, pncpInPipelineIndex]);

  const pncpResultsWithVisibility = useMemo(() => {
    return (pncpSearchResults.items || []).map(item => ({
      ...item,
      score_label: getPncpScoreLabel(item.score),
      __visibility: getPncpResultVisibility(item),
    }));
  }, [pncpSearchResults.items, getPncpResultVisibility]);

  const pncpVisibilityCounts = useMemo(() => {
    // Contagens canônicas do backend (tabela completa). Fallback: página + total.
    const server = pncpSearchResults?.visibility_counts || {};
    const pageCounts = pncpResultsWithVisibility.reduce((acc, item) => {
      acc[item.__visibility] = (acc[item.__visibility] || 0) + 1;
      return acc;
    }, { visible: 0, hidden: 0, pipeline: 0 });
    const listFromServer = Number(server.list ?? NaN);
    const visibleFromServer = Number(server.visible ?? NaN);
    const allFromServer = Number(server.all ?? NaN);
    const hiddenFromServer = Number(server.hidden ?? NaN);
    const pipelineFromServer = Number(server.pipeline ?? NaN);
    const totalPayload = Number(pncpSearchResults?.total || 0);
    const hidden = Number.isFinite(hiddenFromServer)
      ? Math.max(hiddenFromServer, pageCounts.hidden)
      : Math.max(pageCounts.hidden, pncpHiddenIds.length);
    const pipeline = Number.isFinite(pipelineFromServer)
      ? Math.max(pipelineFromServer, pageCounts.pipeline)
      : pageCounts.pipeline;
    // "Na lista" = só disponíveis (sem descartados e sem já no pipeline).
    const visible = Number.isFinite(visibleFromServer)
      ? visibleFromServer
      : Number.isFinite(listFromServer)
        ? listFromServer
        : Math.max(0, totalPayload);
    const list = Number.isFinite(listFromServer) ? listFromServer : visible;
    return {
      all: Number.isFinite(allFromServer) ? allFromServer : (list + hidden + pipeline),
      list,
      visible,
      hidden,
      pipeline,
    };
  }, [pncpResultsWithVisibility, pncpSearchResults?.visibility_counts, pncpSearchResults?.total, pncpHiddenIds.length]);

  const visiblePncpResults = useMemo(() => {
    // Aba resultados: só disponíveis (sem descartados e sem já no pipeline).
    // Itens no pipe somem da lista (visibility=pipeline no backend); sem aba "Já no pipeline".
    let list;
    if (pncpResultScope === 'hidden' || pncpResultScope === 'descartados' || pncpJobModalTab === 'descartados') {
      // Backend já devolve só visibility=hidden; aceitar payload da aba sem re-filtrar
      // por __visibility (evita sumiço se metadado falhar após enrich).
      list = pncpResultsWithVisibility.filter(item => (
        item.__visibility === 'hidden' || item.__visibility_db === 'hidden'
      ));
      // Se a página veio do scope hidden (todos os itens do payload), não esvaziar
      // por mismatch pontual de flag — confiar no que o endpoint de descartados mandou.
      if (!list.length && pncpResultsWithVisibility.length) {
        const allFromHiddenScope = pncpResultsWithVisibility.every(
          item => item.__visibility_db === 'hidden' || item.__from_hidden_scope
        );
        if (allFromHiddenScope || pncpResultsWithVisibility.some(item => item.__from_hidden_scope)) {
          list = pncpResultsWithVisibility;
        }
      }
    } else {
      // list | all | visible — só disponíveis (não descartados e não no pipeline)
      list = pncpResultsWithVisibility.filter(item => item.__visibility === 'visible');
    }
    // Filtro client-side: SRP só é conhecido após enriquecimento (itens sem
    // detalhe têm srp === null e são ocultados apenas com o filtro ligado).
    if (pncpSearchFilters.srp_only) {
      list = list.filter(item => item.srp === true);
    }
    const q = String(pncpResultLocalQuery || '').trim().toLowerCase();
    if (q) {
      list = list.filter(item => {
        const hay = [
          item.titulo,
          item.descricao,
          item.orgao?.nome,
          item.uf,
          item.modalidade?.nome,
          item.numero_controle_pncp,
        ].map(v => String(v || '').toLowerCase()).join(' ');
        return hay.includes(q);
      });
    }
    return list;
  }, [pncpResultsWithVisibility, pncpResultScope, pncpJobModalTab, pncpResultLocalQuery, pncpSearchFilters.srp_only]);

  const pncpSearchSummary = useMemo(() => {
    const backendSummary = pncpSearchResults.summary || pncpSearchResults.pageSummary;
    const fromPage = createPncpUiSummary(pncpSearchResults.items || []);
    if (!backendSummary) return fromPage;
    // Backend deve trazer total_value da lista inteira (SUM no banco).
    // Se ainda vier 0 (snapshot antigo) e a página já tem valores, não mostre R$ 0 enganoso —
    // usa ao menos a soma da página até o próximo poll com SUM correto.
    const backendValue = Number(backendSummary.total_value || 0);
    const pageValue = Number(fromPage.total_value || 0);
    return {
      ...backendSummary,
      count: Number(backendSummary.count || pncpSearchResults.total || fromPage.count || 0),
      total_value: backendValue > 0 ? backendValue : pageValue,
    };
  }, [pncpSearchResults]);

  const visiblePncpSummary = useMemo(() => createPncpUiSummary(visiblePncpResults), [visiblePncpResults]);

  const activePncpSearchJob = useMemo(() => {
    if (!activePncpSearchJobId) return null;
    return pncpSearchJobs.find(job => String(job.id) === String(activePncpSearchJobId)) || null;
  }, [activePncpSearchJobId, pncpSearchJobs]);

  const activePncpJobProgress = useMemo(() => {
    const progress = activePncpSearchJob?.progress || {};
    const done = Number(progress.terms_done || 0);
    const total = Math.max(Number(progress.terms_total || activePncpSearchJob?.terms?.length || 0), 1);
    const pct = ['completed', 'failed', 'cancelled'].includes(activePncpSearchJob?.status) ? 100 : Math.min(98, Math.round((done / total) * 100));
    return {
      done,
      total,
      pct,
      currentTerm: progress.current_term || '',
      currentPage: progress.current_page || null,
      currentCollected: Number(progress.current_term_collected || 0),
      currentReported: progress.current_term_total_reported ? Number(progress.current_term_total_reported) : null,
      totalCollected: Number(progress.items_collected || activePncpSearchJob?.total || 0),
    };
  }, [activePncpSearchJob]);

  /**
   * Fonte única de term_runs para card, auditoria e banner — evita um usar job e
   * outro query_plan velho (poll atualizava term_runs no job e o card lia plan stale).
   */
  const getPncpJobTermRuns = useCallback((job, results = null) => {
    const candidates = [
      job?.term_runs,
      results?.query_plan?.term_runs,
      job?.query_plan?.term_runs,
      results?.term_runs,
    ];
    // Prefere o array com mais progresso (soma de pages_completed / items).
    let best = [];
    let bestScore = -1;
    candidates.forEach((arr) => {
      if (!Array.isArray(arr) || !arr.length) return;
      const score = arr.reduce((s, r) => (
        s
        + Number(r?.pages_completed || 0) * 1000
        + Number(r?.items_collected || 0)
        + Number(r?.unique_new || 0)
      ), 0) + arr.length;
      if (score >= bestScore) {
        bestScore = score;
        best = arr;
      }
    });
    return best;
  }, []);

  /**
   * Funil da coleta — números alinhados à tabela de Auditoria:
   * - Lidos = soma de items_collected por termo (coluna "Lidos" da auditoria)
   * - Universo = soma de total_reported por termo de busca (coluna "Universo")
   * - Únicos / Já vistos = unique_new / duplicates (colunas da auditoria)
   */
  const getPncpJobCollectionFunnel = useCallback((job, classifiedTotal = 0, extraTermRuns = null, results = null) => {
    const termRuns = Array.isArray(extraTermRuns) && extraTermRuns.length
      ? extraTermRuns
      : getPncpJobTermRuns(job, results);
    const searchRuns = termRuns.filter(r => r?.source !== 'pncp_consulta_complement');
    const complementRuns = termRuns.filter(r => r?.source === 'pncp_consulta_complement');
    // Por termo: usa a última execução (retomadas sobrescrevem o progresso).
    const latestByTerm = new Map();
    searchRuns.forEach((run) => {
      const key = normalizeText(run?.term || '');
      if (!key) return;
      const prev = latestByTerm.get(key);
      // Em empate, fica o de mais páginas/itens (mais recente/avançado).
      if (!prev) {
        latestByTerm.set(key, run);
        return;
      }
      const prevScore = Number(prev.pages_completed || 0) * 1000 + Number(prev.items_collected || 0);
      const nextScore = Number(run.pages_completed || 0) * 1000 + Number(run.items_collected || 0);
      if (nextScore >= prevScore) latestByTerm.set(key, run);
    });
    const latestRuns = [...latestByTerm.values()];
    const complementRun = complementRuns.reduce((best, run) => {
      if (!best) return run;
      const b = Number(best.pages_completed || 0) * 1000 + Number(best.items_collected || 0);
      const n = Number(run.pages_completed || 0) * 1000 + Number(run.items_collected || 0);
      return n >= b ? run : best;
    }, null);

    let universeMax = 0;
    let universeSum = 0;
    let brutosLidosSum = 0;
    let uniqueNewSum = 0;
    let duplicatesSum = 0;
    let pagesDone = 0;
    let pagesReq = 0;
    latestRuns.forEach((run) => {
      const u = Number(run.total_reported || 0);
      if (u > universeMax) universeMax = u;
      universeSum += u;
      brutosLidosSum += Number(run.items_collected || 0);
      uniqueNewSum += Number(run.unique_new || 0);
      duplicatesSum += Number(run.duplicates_skipped || 0);
      pagesDone += Number(run.pages_completed || 0);
      pagesReq += Number(run.pages_requested || 0);
    });
    const complementUnique = Number(complementRun?.unique_new || 0);
    const complementCollected = Number(complementRun?.items_collected || 0);
    const complementDups = Number(complementRun?.duplicates_skipped || 0);
    uniqueNewSum += complementUnique;
    brutosLidosSum += complementCollected;
    duplicatesSum += complementDups;
    if (complementRun) {
      pagesDone += Number(complementRun.pages_completed || 0);
      pagesReq += Number(complementRun.pages_requested || 0);
    }

    const mainRun = latestRuns.reduce((best, run) => (
      Number(run.total_reported || 0) > Number(best?.total_reported || 0) ? run : best
    ), null);
    const currentTermName = job?.progress?.current_term || '';
    const currentRun = currentTermName
      ? (
        normalizeText(currentTermName).includes('consulta')
          ? complementRun
          : latestRuns.find((r) => normalizeText(r.term) === normalizeText(currentTermName))
      )
      : null;
    const mainRead = Number(mainRun?.items_collected || 0);
    const mainUniverse = Number(mainRun?.total_reported || 0);
    const mainPagesDone = Number(mainRun?.pages_completed || 0);
    const mainPageSize = Number(mainRun?.observed_page_size || 0) || (mainRead && mainPagesDone ? Math.round(mainRead / mainPagesDone) : 0);
    const mainPagesEst = mainUniverse > 0 && mainPageSize > 0
      ? Math.ceil(mainUniverse / mainPageSize)
      : null;

    // Lidos do card = mesma soma da coluna "Lidos" da auditoria (items_collected).
    // Progress ao vivo reforça o piso se term_runs ainda não chegou no poll.
    const progressCollected = Number(job?.progress?.current_term_collected || 0);
    const sessionUnique = Number(job?.progress?.items_collected || job?.query_plan?.raw_unique_collected || 0);
    const brutosLidos = Math.max(brutosLidosSum, mainRead, progressCollected, 0);
    const exclusiveLidos = Math.max(uniqueNewSum, sessionUnique, 0);

    const universeMaxTerm = mainUniverse || universeMax;
    const universeApi = Math.max(universeSum > 0 ? universeSum : universeMaxTerm, brutosLidos, 0);
    const universeGrewBeyondMain = brutosLidos > universeMaxTerm && universeMaxTerm > 0;
    const classified = Number(classifiedTotal || job?.total || 0);
    const statusFilter = String(job?.filters?.status || 'recebendo_proposta');
    const isOpenOnly = normalizeText(statusFilter) === 'recebendo_proposta';
    const gate = job?.progress?.gate || null;
    const coveragePct = universeApi > 0
      ? Math.min(100, Math.round((brutosLidos / universeApi) * 100))
      : null;
    return {
      universeApi,
      universeMax: universeMaxTerm,
      universeSum: universeApi,
      universeGrewBeyondMain,
      brutosLidos,
      brutosLidosSum,
      uniqueNewSum,
      exclusiveLidos,
      mainRead,
      complementUnique,
      duplicatesSum,
      classified,
      pagesDone,
      pagesReq,
      pagesEst: mainPagesEst,
      pageSize: mainPageSize,
      mainTerm: mainRun?.term || job?.filters?.q || job?.nome || '',
      mainStop: mainRun?.stop_reason || null,
      currentTerm: currentTermName || null,
      currentRead: currentRun ? Number(currentRun.items_collected || currentRun.unique_new || 0) : null,
      currentUniverse: currentRun ? Number(currentRun.total_reported || 0) : null,
      currentUnique: currentRun
        ? Number(currentRun.unique_new || 0)
        : Number(job?.progress?.current_term_unique_new || 0) || null,
      currentDuplicates: currentRun
        ? Number(currentRun.duplicates_skipped || 0)
        : Number(job?.progress?.current_term_duplicates || 0) || null,
      isOpenOnly,
      statusFilter,
      resumePage: job?.progress?.resume_from_page || null,
      resumeInMs: Number(job?.progress?.resume_in_ms || 0) || null,
      checkpoint: Boolean(job?.progress?.checkpoint || job?.progress?.checkpoint_mode || job?.progress?.resumed),
      gate,
      coveragePct,
      classifyPct: brutosLidos > 0
        ? Math.min(100, Math.round((classified / brutosLidos) * 100))
        : null,
      termRuns,
    };
  }, [getPncpJobTermRuns]);

  const formatPncpStopReason = (reason) => {
    const map = {
      rate_limited: 'Limite PNCP (pausou)',
      total_reached: 'Varreu o universo da API',
      short_page: 'Última página (menor que o tamanho)',
      empty_page: 'Página vazia',
      page_error: 'Erro na página',
      page_error_partial: 'Erro com coleta parcial',
      max_pages: 'Teto de páginas',
      target_reached: 'Meta de itens',
      cancelled: 'Cancelado',
      slice_yield: 'Cedeu a vez (rodízio)',
    };
    const key = String(reason || '');
    return map[key] || (key ? key.replace(/_/g, ' ') : '—');
  };

  /** Traduz erros técnicos do PNCP/curl para texto humano (tooltip guarda o original). */
  const formatPncpRunError = (raw) => {
    const text = String(raw || '').trim();
    if (!text) return '—';
    const lower = text.toLowerCase();
    if (/curl exit 56|recv failure|econnreset|connection reset|socket hang/.test(lower)) {
      return 'PNCP cortou a conexão (throttle) — pausa e retoma sem recomeçar';
    }
    if (/curl exit 28|etimedout|timed out|timeout/.test(lower)) {
      return 'PNCP demorou demais (timeout) — retoma depois';
    }
    if (/curl exit 52|empty reply/.test(lower)) {
      return 'PNCP respondeu vazio — possível freio de cota';
    }
    if (/429|rate.?limit|too many/.test(lower)) {
      return 'PNCP recusou por limite de requisições';
    }
    // Mantém legível: corta stderr longo
    return text.length > 90 ? `${text.slice(0, 87)}…` : text;
  };

  const formatPncpResumeCountdown = (resumeInMs, updatedAt) => {
    const base = Number(resumeInMs) || 0;
    if (base <= 0) return null;
    const updatedTs = updatedAt
      ? (typeof updatedAt === 'number' ? updatedAt : Date.parse(updatedAt))
      : Date.now();
    const elapsed = Number.isFinite(updatedTs) ? Math.max(0, Date.now() - updatedTs) : 0;
    const left = Math.max(0, base - elapsed);
    if (left <= 0) return 'retomando em instantes';
    const mins = Math.floor(left / 60000);
    const secs = Math.floor((left % 60000) / 1000);
    if (mins >= 1) return `retoma em ~${mins} min ${secs > 0 ? `${secs}s` : ''}`.trim();
    return `retoma em ~${secs}s`;
  };

  const formatPncpGateLabel = (gate) => {
    if (!gate || typeof gate !== 'object') return null;
    const paused = Number(gate.paused_for_ms || 0) > 0 || (gate.paused_until && Date.parse(gate.paused_until) > Date.now());
    const gap = Number(gate.gap_ms || 0);
    const budget = Number(gate.budget_tokens || 0);
    const cap = Number(gate.budget_capacity || 0);
    if (paused) return { label: 'Gate pausado', tone: 'amber' };
    if (gap >= 4000 || Number(gate.fail_streak || 0) >= 2) return { label: `Gate freando · gap ${gap}ms`, tone: 'amber' };
    if (cap > 0 && budget < cap * 0.3) return { label: `Orçamento baixo · ${budget}/${cap}`, tone: 'amber' };
    return { label: `Gate ok · gap ${gap || '—'}ms`, tone: 'emerald' };
  };

  const formatPncpStatusFilterLabel = (status) => {
    const s = normalizeText(status || '');
    if (s === 'recebendo_proposta') return 'Só recebendo proposta (filtro local)';
    if (s === 'todos' || !s) return 'Todos os status';
    if (s === 'suspensa' || s === 'suspenso') return 'Suspensas';
    return String(status || 'n/d');
  };

  const getPncpJobStatusMeta = (status) => {
    const normalized = String(status || 'queued');
    if (normalized === 'completed') return { label: 'Concluída', className: 'bg-emerald-500/10 text-emerald-600 border-emerald-500/25', live: false };
    if (normalized === 'running') return { label: 'Coletando', className: 'bg-primary/10 text-primary border-primary/25', live: true };
    if (normalized === 'paused_rate_limit') return { label: 'Pausada (limite PNCP)', className: 'bg-amber-500/10 text-amber-700 dark:text-amber-300 border-amber-500/30', live: true };
    if (normalized === 'queued') return { label: 'Na fila', className: 'bg-sky-500/10 text-sky-600 border-sky-500/25', live: true };
    if (normalized === 'cancelling') return { label: 'Parando…', className: 'bg-cardAlt text-muted border-border', live: true };
    if (normalized === 'cancelled') return { label: 'Parada', className: 'bg-cardAlt text-muted border-border', live: false };
    if (normalized === 'failed') return { label: 'Erro', className: 'bg-status-danger/10 text-status-danger border-status-danger/25', live: false };
    return { label: normalized.replace(/_/g, ' '), className: 'bg-cardAlt text-muted border-border', live: false };
  };

  const isPncpJobLive = (status) => ['queued', 'running', 'paused_rate_limit', 'cancelling'].includes(String(status || ''));

  const formatPncpJobAge = (value) => {
    if (!value) return '';
    const ts = typeof value === 'number' ? value : Date.parse(value);
    if (!Number.isFinite(ts)) return '';
    const diffSec = Math.max(0, Math.round((Date.now() - ts) / 1000));
    if (diffSec < 60) return 'agora';
    if (diffSec < 3600) return `${Math.floor(diffSec / 60)} min`;
    if (diffSec < 86400) return `${Math.floor(diffSec / 3600)} h`;
    return `${Math.floor(diffSec / 86400)} d`;
  };

  // Countdown até arquivamento (15 dias desde started_at; reexecuções não estendem).
  const getPncpJobArchiveMeta = (job) => {
    if (!job || job.watchlist_id) return null;
    const archiveDays = Number(job.archive_days || 15);
    let daysLeft = job.days_until_archive;
    if (daysLeft == null && job.archive_at) {
      const archiveTs = Date.parse(job.archive_at);
      if (Number.isFinite(archiveTs)) {
        daysLeft = Math.max(0, Math.ceil((archiveTs - Date.now()) / 86400000));
      }
    }
    if (daysLeft == null && job.started_at) {
      const startTs = typeof job.started_at === 'number' ? job.started_at : Date.parse(job.started_at);
      if (Number.isFinite(startTs)) {
        const archiveTs = startTs + archiveDays * 86400000;
        daysLeft = Math.max(0, Math.ceil((archiveTs - Date.now()) / 86400000));
      }
    }
    if (daysLeft == null || !Number.isFinite(Number(daysLeft))) return null;
    const n = Number(daysLeft);
    if (n <= 0) {
      return { daysLeft: 0, label: 'Arquiva hoje', urgent: true, className: 'bg-status-danger/10 text-status-danger border-status-danger/25' };
    }
    if (n === 1) {
      return { daysLeft: 1, label: 'Arquiva em 1 d', urgent: true, className: 'bg-amber-500/10 text-amber-700 dark:text-amber-300 border-amber-500/30' };
    }
    if (n <= 2) {
      return { daysLeft: n, label: `Arquiva em ${n} d`, urgent: true, className: 'bg-amber-500/10 text-amber-700 dark:text-amber-300 border-amber-500/30' };
    }
    return { daysLeft: n, label: `Arquiva em ${n} d`, urgent: false, className: 'bg-cardAlt text-muted border-border' };
  };

  const canRerunPncpSearchJob = (job) => {
    if (!job?.id || job.watchlist_id) return false;
    if (isPncpJobLive(job.status)) return false;
    const archive = getPncpJobArchiveMeta(job);
    if (archive && archive.daysLeft <= 0 && job.days_until_archive === 0) {
      // Ainda permite no último dia; bloqueio real fica no backend (410).
    }
    return ['completed', 'failed', 'cancelled'].includes(String(job.status || ''));
  };

  const seedPncpJobFilterDraft = (filters = {}) => {
    setPncpJobFilterDraft({
      tipos_documento: filters.tipos_documento || 'edital',
      status: filters.status || 'recebendo_proposta',
      modalidade_licitacao_id: filters.modalidade_licitacao_id || '',
      tipo_id: filters.tipo_id || '',
      modo_disputa_id: filters.modo_disputa_id || '',
      uf: filters.uf || '',
      esfera_id: filters.esfera_id || '',
      orgao_cnpj: filters.orgao_cnpj || '',
      unidade_codigo: filters.unidade_codigo || '',
      negative_terms: filters.negative_terms || '',
      ordenacao: filters.ordenacao || 'relevancia_desc',
      usar_ia: filters.usar_ia === undefined ? true : String(filters.usar_ia) !== 'false',
    });
  };

  const getPncpPartidaFilterChips = (filters = {}, options = {}) => {
    const chips = [];
    const f = filters || {};
    const tipoDocLabel = {
      edital: 'Editais',
      ata: 'Atas',
      contrato: 'Contratos',
      'edital,ata': 'Editais e Atas',
      'edital,ata,contrato': 'Todos docs',
    };
    const statusLabel = {
      recebendo_proposta: 'Recebendo proposta',
      encerrada: 'Encerrada',
      suspensa: 'Suspensa',
      todos: 'Todos status',
    };
    const esferaLabel = { F: 'Federal', E: 'Estadual', M: 'Municipal' };
    if (f.tipos_documento) chips.push({ key: 'tipos_documento', label: 'Documento', value: tipoDocLabel[f.tipos_documento] || f.tipos_documento });
    if (f.status) chips.push({ key: 'status', label: 'Status', value: statusLabel[f.status] || String(f.status).replace(/_/g, ' ') });
    if (f.uf) chips.push({ key: 'uf', label: 'UF', value: f.uf });
    if (f.esfera_id) chips.push({ key: 'esfera_id', label: 'Esfera', value: esferaLabel[f.esfera_id] || f.esfera_id });
    if (f.modalidade_licitacao_id) {
      const mod = (options.modalidades || []).find(m => String(m.id) === String(f.modalidade_licitacao_id));
      chips.push({ key: 'modalidade_licitacao_id', label: 'Modalidade', value: mod?.nome || f.modalidade_licitacao_id });
    }
    if (f.tipo_id) {
      const tipo = (options.tipos || []).find(t => String(t.id) === String(f.tipo_id));
      chips.push({ key: 'tipo_id', label: 'Instrumento', value: tipo?.nome || f.tipo_id });
    }
    if (f.modo_disputa_id) {
      const modo = (options.modos || []).find(m => String(m.id) === String(f.modo_disputa_id));
      chips.push({ key: 'modo_disputa_id', label: 'Disputa', value: modo?.nome || f.modo_disputa_id });
    }
    if (f.orgao_cnpj) chips.push({ key: 'orgao_cnpj', label: 'Órgão', value: f.orgao_cnpj });
    if (f.unidade_codigo) chips.push({ key: 'unidade_codigo', label: 'UASG', value: f.unidade_codigo });
    if (f.negative_terms) chips.push({ key: 'negative_terms', label: 'Excluir', value: f.negative_terms });
    return chips;
  };

  const pncpDebugLookup = useMemo(() => {
    const query = normalizePncpControlId(pncpDebugControlId);
    if (!query) {
      return null;
    }
    const queryDigits = query.replace(/\D/g, '');
    const found = pncpResultsWithVisibility.find(item => {
      const control = normalizePncpControlId(item.numero_controle_pncp);
      const path = extractPncpPathKey(item.url || item.item_url);
      const id = normalizePncpControlId(item.id);
      const combinedDigits = `${control} ${path} ${id}`.replace(/\D/g, '');
      return (control && control.includes(query))
        || (path && path.includes(query))
        || (id && id.includes(query))
        || (queryDigits.length >= 8 && combinedDigits.includes(queryDigits));
    });
    return {
      query: pncpDebugControlId,
      found,
      status: found ? found.__visibility : 'missing',
    };
  }, [pncpDebugControlId, pncpResultsWithVisibility]);

  const agentOptions = useMemo(() => {
    const names = contacts
      .map(contact => String(contact.agent_name || '').trim())
      .filter(Boolean);
    const unique = Array.from(new Set(names));
    unique.sort((a, b) => a.localeCompare(b, 'pt-BR', { sensitivity: 'base' }));
    return unique;
  }, [contacts]);

  const labelOptions = useMemo(() => {
    const allLabels = contacts
      .flatMap(contact => Array.isArray(contact.labels) ? contact.labels.map(l => l?.name) : [])
      .filter(Boolean);
    const unique = Array.from(new Set(allLabels));
    unique.sort((a, b) => a.localeCompare(b, 'pt-BR', { sensitivity: 'base' }));
    return unique;
  }, [contacts]);

  const sortContacts = (list) => {
    const sorted = [...list];
    sorted.sort((a, b) => {
      if (sortOption === 'name-asc') {
        return String(a.company_name || a.name || '').localeCompare(String(b.company_name || b.name || ''));
      }
      if (sortOption === 'name-desc') {
        return String(b.company_name || b.name || '').localeCompare(String(a.company_name || a.name || ''));
      }
      if (sortOption === 'opportunity-desc') {
        const aVal = parseCurrency(a.custom_attributes?.Valor_Oportunidade) || 0;
        const bVal = parseCurrency(b.custom_attributes?.Valor_Oportunidade) || 0;
        return bVal - aVal;
      }
      if (sortOption === 'opportunity-asc') {
        const aVal = parseCurrency(a.custom_attributes?.Valor_Oportunidade) || 0;
        const bVal = parseCurrency(b.custom_attributes?.Valor_Oportunidade) || 0;
        return aVal - bVal;
      }
      return 0;
    });
    return sorted;
  };

  const activeColumns = activeTab === 'leads' ? leadColumns : customerColumns;

  // Pre-bucket contacts once per render deps so columns keep stable array refs
  // unless that column's membership actually changed.
  const contactsByColumnPrevRef = useRef(Object.create(null));
  const contactsByColumn = useMemo(() => {
    const buckets = Object.create(null);
    activeColumns.forEach((column) => {
      buckets[column] = [];
    });
    filteredContacts.forEach((contact) => {
      const column = contact.custom_attributes?.Funil_Vendas;
      if (column && buckets[column]) {
        buckets[column].push(contact);
      }
    });
    if (!activeDragId) {
      activeColumns.forEach((column) => {
        buckets[column] = sortContacts(buckets[column]);
      });
    }
    // Reuse previous column arrays when membership/order is unchanged — critical
    // for funnel boards so untouched columns skip React.memo invalidation.
    const prev = contactsByColumnPrevRef.current;
    activeColumns.forEach((column) => {
      const nextList = buckets[column];
      const prevList = prev[column];
      if (
        prevList
        && prevList.length === nextList.length
        && prevList.every((item, index) => item === nextList[index])
      ) {
        buckets[column] = prevList;
      }
    });
    contactsByColumnPrevRef.current = buckets;
    return buckets;
  }, [filteredContacts, activeColumns, activeDragId, sortOption]);

  const getContactsForColumn = (columnName) => contactsByColumn[columnName] || [];
  const dotClass = activeTab === 'leads' ? 'bg-primary' : 'bg-secondary';
  const showMenu = true;
  const menuLabel = activeTab === 'leads' ? 'Enviar para novos clientes' : 'Voltar para Inbox';
  const newContactUrl = activeTab === 'customers'
    ? 'https://chatwoot.tenryu.com.br/app/accounts/2/contacts?page=1'
    : null;

  // Ordered matches for board search focus (column order → card order in column).
  const boardSearchMatches = useMemo(() => {
    if (!searchQuery.trim()) return [];
    const matches = [];
    activeColumns.forEach((column) => {
      (contactsByColumn[column] || []).forEach((contact) => {
        matches.push({
          contactId: contact.id,
          column,
          label: contact.company_name || contact.name || `Contato #${contact.id}`,
        });
      });
    });
    return matches;
  }, [searchQuery, activeColumns, contactsByColumn]);

  const boardSearchMatchKey = boardSearchMatches
    .map((match) => `${match.contactId}@${match.column}`)
    .join('|');

  const operationalLicitacaoCount = useMemo(
    () => countOperationalLicitacoes(licitacaoOpportunities, licitacaoColumns),
    [licitacaoOpportunities]
  );

  const filteredLicitacaoOpportunities = useMemo(() => {
    // Keep source order so drag-and-drop can open gaps between cards (Trello-like).
    return licitacaoOpportunities.filter((item) => licitacaoMatchesQuery(item, licitacaoSearch));
  }, [licitacaoOpportunities, licitacaoSearch]);

  const opportunitiesByColumnPrevRef = useRef(Object.create(null));
  const opportunitiesByColumn = useMemo(() => {
    const buckets = Object.create(null);
    licitacaoColumns.forEach((column) => {
      buckets[column] = [];
    });
    filteredLicitacaoOpportunities.forEach((item) => {
      const column = item.fase;
      if (column && buckets[column]) {
        buckets[column].push(item);
      }
    });
    const prev = opportunitiesByColumnPrevRef.current;
    licitacaoColumns.forEach((column) => {
      const nextList = buckets[column];
      const prevList = prev[column];
      if (
        prevList
        && prevList.length === nextList.length
        && prevList.every((item, index) => item === nextList[index])
      ) {
        buckets[column] = prevList;
      }
    });
    opportunitiesByColumnPrevRef.current = buckets;
    return buckets;
  }, [filteredLicitacaoOpportunities]);

  const getOpportunitiesForColumn = (columnName) => opportunitiesByColumn[columnName] || [];

  // Ordered matches for licitação pipeline search focus (column order → card order).
  const licitacaoSearchMatches = useMemo(() => {
    if (!licitacaoSearch.trim()) return [];
    const matches = [];
    licitacaoColumns.forEach((column) => {
      (opportunitiesByColumn[column] || []).forEach((item) => {
        matches.push({
          opportunityId: item.id,
          column,
          label: item.titulo || `Licitação #${item.id}`,
        });
      });
    });
    return matches;
  }, [licitacaoSearch, opportunitiesByColumn]);

  const licitacaoSearchMatchKey = licitacaoSearchMatches
    .map((match) => `${match.opportunityId}@${match.column}`)
    .join('|');

  const moveOpportunityToStage = async (opportunityId, targetStage) => {
    if (!targetStage) {
      return;
    }
    const previous = licitacaoOpportunities;
    setLicitacaoOpportunities(prev => prev.map(item => (
      String(item.id) === String(opportunityId)
        ? { ...item, fase: targetStage }
        : item
    )));
    try {
      await axios.put(`/api/licitacoes/opportunities/${opportunityId}`, { fase: targetStage });
    } catch (error) {
      console.error('Error moving licitação opportunity:', error);
      setLicitacaoOpportunities(previous);
    }
  };

  const resetNewOpportunityFormState = useCallback(() => {
    setShowNewOpportunityForm(false);
    setNewOpportunityFormSubview(null);
    setIsPncpImportDraft(false);
    setNewOpportunityForm(createEmptyOpportunityForm());
    setNewOpportunityContact({ contact_id: '', papel: '', observacao: '' });
    setNewOpportunityContactQuery('');
    setOrgaoLookupQuery('');
    setUasgLookupQuery('');
    setModalidadeLookupQuery('');
    setCatalogoLookupQuery('');
    setNewOpportunityItemForm({ numero_item: '', descricao: '', modelo_produto: '', quantidade: '', custo_total_item: '' });
    setNewOpportunityItemsDraft([]);
    setNewOpportunityItemRequirementForm({});
    setExpandedDraftChecklist({});
    setChecklistModalItemId(null);
  }, []);

  const openNewOpportunityForm = useCallback(() => {
    setIsPncpImportDraft(false);
    setNewOpportunityForm(createEmptyOpportunityForm());
    setNewOpportunityContact({ contact_id: '', papel: '', observacao: '' });
    setNewOpportunityContactQuery('');
    setOrgaoLookupQuery('');
    setUasgLookupQuery('');
    setModalidadeLookupQuery('');
    setCatalogoLookupQuery('');
    setNewOpportunityItemForm({ numero_item: '', descricao: '', modelo_produto: '', quantidade: '', custo_total_item: '' });
    setNewOpportunityItemsDraft([]);
    setNewOpportunityItemRequirementForm({});
    setExpandedDraftChecklist({});
    setChecklistModalItemId(null);
    setNewOpportunityFormSubview(licitacaoSubview);
    setShowNewOpportunityForm(true);
  }, [licitacaoSubview]);

  // Trava o scroll do body e Esc fecha o modal ativo (nova licitação ou detalhe).
  // Depend only on open/closed — NOT on the full selectedOpportunity object.
  // Re-running this on every keystroke was toggling body overflow and blurring inputs.
  const hasSelectedOpportunityModal = Boolean(selectedOpportunity);
  useEffect(() => {
    const anyModal = showNewOpportunityForm || hasSelectedOpportunityModal;
    if (!anyModal) return undefined;
    const prev = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    const onKey = (event) => {
      if (event.key !== 'Escape') return;
      if (showNewOpportunityForm) {
        resetNewOpportunityFormState();
        return;
      }
      setSelectedOpportunity(null);
      setContactLinkQuery('');
    };
    window.addEventListener('keydown', onKey);
    return () => {
      document.body.style.overflow = prev;
      window.removeEventListener('keydown', onKey);
    };
  }, [showNewOpportunityForm, hasSelectedOpportunityModal, resetNewOpportunityFormState]);

  const createOpportunity = async () => {
    if (!newOpportunityForm.titulo.trim()) {
      return;
    }
    try {
      const linkedContacts = Array.isArray(newOpportunityForm.linked_contacts)
        ? newOpportunityForm.linked_contacts
            .map(item => ({
              contact_id: Number(item.contact_id),
              papel: item.papel,
              principal: Boolean(item.principal),
              observacao: item.observacao || null,
            }))
            .filter(item => Number.isFinite(item.contact_id))
        : [];

      const payload = {
        ...newOpportunityForm,
        orgao_codigo: newOpportunityForm.orgao_codigo || newOpportunityForm.orgao_cnpj || null,
        valor_oportunidade: newOpportunityForm.valor_oportunidade
          ? parseCurrency(newOpportunityForm.valor_oportunidade)
          : null,
        comissao_percentual: newOpportunityForm.comissao_percentual
          ? Number(String(newOpportunityForm.comissao_percentual).replace(',', '.'))
          : null,
        comissao_valor_previsto: newOpportunityForm.comissao_valor_previsto
          ? Number(String(newOpportunityForm.comissao_valor_previsto).replace(',', '.'))
          : null,
        valor_revenda_previsto: newOpportunityForm.valor_revenda_previsto
          ? Number(String(newOpportunityForm.valor_revenda_previsto).replace(',', '.'))
          : null,
        intermediario_id: newOpportunityForm.intermediario_id ? Number(newOpportunityForm.intermediario_id) : null,
        palavras_chave: newOpportunityForm.palavras_chave,
        links: {
          edital: newOpportunityForm.links_edital || null,
          pncp: newOpportunityForm.links_pncp || null,
          compras: newOpportunityForm.links_compras || null,
          sei: newOpportunityForm.links_sei || null,
        },
        linked_contacts: linkedContacts,
      };
      const response = await axios.post('/api/licitacoes/opportunities', payload);
      const created = response.data;

      for (const item of newOpportunityItemsDraft) {
        if (!String(item?.descricao || '').trim()) {
          continue;
        }

        let createdItem;
        try {
          const createdItemResponse = await axios.post(`/api/licitacoes/opportunities/${created.id}/items`, {
            numero_item: item.numero_item,
            descricao: item.descricao,
            modelo_produto: item.modelo_produto,
            quantidade: parseCurrency(item.quantidade),
            unidade: item.unidade,
            valor_referencia: parseCurrency(item.valor_referencia),
            custo_total_item: parseCurrency(item.custo_total_item),
          });
          createdItem = createdItemResponse.data;
        } catch (itemError) {
          console.error('Error creating imported item:', itemError, item);
          continue;
        }

        const requirements = Array.isArray(item.requirements) ? item.requirements : [];
        for (const req of requirements) {
          if (!String(req?.requisito || '').trim()) {
            continue;
          }
          try {
            await axios.post(`/api/licitacoes/opportunities/${created.id}/items/${createdItem.id}/requirements`, {
              requisito: req.requisito,
              status: req.status,
              observacao: req.observacao,
              valor_ofertado: req.custo_subitem,
            });
          } catch (reqError) {
            console.error('Error creating imported item requirement:', reqError, req);
          }
        }
      }

      if (String(newOpportunityForm.comentario_inicial || '').trim()) {
        await axios.post(`/api/licitacoes/opportunities/${created.id}/comments`, {
          content: newOpportunityForm.comentario_inicial,
        });
      }

      setLicitacaoOpportunities(prev => [response.data, ...prev]);
      resetNewOpportunityFormState();
    } catch (error) {
      console.error('Error creating licitação opportunity:', error);
    }
  };

  const addDraftItem = () => {
    if (!newOpportunityItemForm.descricao.trim()) {
      return;
    }
    const draftId = `draft-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`;
    setNewOpportunityItemsDraft(prev => ([
      ...prev,
      {
        id: draftId,
        numero_item: newOpportunityItemForm.numero_item || null,
        descricao: newOpportunityItemForm.descricao,
        modelo_produto: newOpportunityItemForm.modelo_produto || null,
        quantidade: parseCurrency(newOpportunityItemForm.quantidade),
        valor_referencia: null,
        custo_total_item: parseCurrency(newOpportunityItemForm.custo_total_item),
        requirements: [],
      },
    ]));
    setNewOpportunityItemForm({ numero_item: '', descricao: '', modelo_produto: '', quantidade: '', custo_total_item: '' });
  };

  const removeDraftItem = (draftId) => {
    setNewOpportunityItemsDraft(prev => prev.filter(item => item.id !== draftId));
    setNewOpportunityItemRequirementForm(prev => {
      const next = { ...prev };
      delete next[draftId];
      return next;
    });
  };

  const updateDraftItem = (draftId, changes) => {
    setNewOpportunityItemsDraft(prev => prev.map(item => (item.id === draftId ? { ...item, ...changes } : item)));
  };

  const addDraftItemRequirement = (draftId) => {
    const form = newOpportunityItemRequirementForm[draftId] || { requisito: '' };
    if (!String(form.requisito || '').trim()) {
      return;
    }
    setNewOpportunityItemsDraft(prev => prev.map(item => (
      item.id === draftId
        ? {
            ...item,
            requirements: [
              ...(item.requirements || []),
              {
                id: `req-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`,
                requisito: form.requisito,
                status: form.status || 'verificar',
                observacao: form.observacao || null,
                custo_subitem: form.custo_subitem ? parseCurrency(form.custo_subitem) : null,
                ordem: (item.requirements || []).length,
              },
            ],
          }
        : item
    )));
    setNewOpportunityItemRequirementForm(prev => ({
      ...prev,
      [draftId]: { requisito: '', status: 'verificar', observacao: '', custo_subitem: '' },
    }));
  };

  const removeDraftItemRequirement = (draftId, requirementId) => {
    setNewOpportunityItemsDraft(prev => prev.map(item => (
      item.id === draftId
        ? { ...item, requirements: (item.requirements || []).filter(req => req.id !== requirementId) }
        : item
    )));
  };

  const addContactToNewOpportunity = () => {
    const resolvedId = String(
      newOpportunityContact.contact_id
      || resolveContactIdFromInput(newOpportunityContactQuery, filteredContactsForNewOpportunity)
      || resolveContactIdFromInput(newOpportunityContactQuery, contacts)
      || ''
    );

    if (!resolvedId) {
      return;
    }
    setNewOpportunityForm(prev => {
      const alreadyExists = prev.linked_contacts.some(
        item => String(item.contact_id) === resolvedId
      );
      if (alreadyExists) {
        return prev;
      }
      return {
        ...prev,
        linked_contacts: [
          ...prev.linked_contacts,
          {
            contact_id: Number(resolvedId),
            papel: newOpportunityContact.papel || null,
            observacao: newOpportunityContact.observacao || null,
            principal: prev.linked_contacts.length === 0,
          },
        ],
      };
    });
    setNewOpportunityContact({ contact_id: '', papel: '', observacao: '' });
    setNewOpportunityContactQuery('');
  };

  const removeContactFromNewOpportunity = (contactId) => {
    setNewOpportunityForm(prev => {
      const next = prev.linked_contacts.filter(item => String(item.contact_id) !== String(contactId));
      if (next.length > 0 && !next.some(item => item.principal)) {
        next[0] = { ...next[0], principal: true };
      }
      return { ...prev, linked_contacts: next };
    });
  };

  const setPrincipalContactForNewOpportunity = (contactId) => {
    setNewOpportunityForm(prev => ({
      ...prev,
      linked_contacts: prev.linked_contacts.map(item => ({
        ...item,
        principal: String(item.contact_id) === String(contactId),
      })),
    }));
  };

  // Buscar editais/licitações no PNCP
  // resetScope: só ao abrir o job (poll ao vivo não deve resetar filtro/escopo do usuário).
  const applyPncpJobSnapshot = (job, { resetScope = false } = {}) => {
    if (!job) return;
    // Snapshot do job NÃO carrega a página de resultados (isso é loadPncpJobResults).
    // Na aba Descartados, job.items costuma ser a lista ativa — nunca substituir por ele.
    const onDiscardedTab = pncpJobModalTabRef.current === 'descartados'
      || pncpResultScopeRef.current === 'hidden';
    setPncpSearchResults(prev => {
      const nextTotal = Number(job.total || 0) || Number(prev.total || 0) || 0;
      // term_runs vivo do backend tem prioridade — NÃO ficar preso em query_plan parcial velho.
      const freshRuns = getPncpJobTermRuns(job, prev);
      const nextPlan = {
        ...(prev.query_plan || {}),
        ...(job.query_plan || {}),
        mode: job.query_plan?.mode || prev.query_plan?.mode || 'deep_background',
        term_runs: freshRuns.length
          ? freshRuns
          : (job.term_runs || job.query_plan?.term_runs || prev.query_plan?.term_runs || []),
        terms: job.terms || job.query_plan?.terms || prev.query_plan?.terms,
        terms_planned: job.terms || job.query_plan?.terms_planned || prev.query_plan?.terms_planned,
      };
      const keepItems = onDiscardedTab
        || (Array.isArray(prev.items) && prev.items.length > 0);
      return {
        ...prev,
        // Não zera a lista quando o job está em 'queued' entre retomadas (items=[]).
        // A lista canônica vem de loadPncpJobResults; snapshot só preenche se ainda não houver página.
        items: keepItems
          ? (prev.items || [])
          : (Array.isArray(job.items) ? job.items : []),
        // Na aba Descartados o total da página é o count hidden, não o total do job.
        total: onDiscardedTab
          ? Number(prev.total || job.visibility_counts?.hidden || 0)
          : (nextTotal || (Array.isArray(job.items) ? job.items.length : 0) || Number(prev.total || 0)),
        pagina: prev.pagina || 1,
        tamanhoPagina: prev.tamanhoPagina || 25,
        totalPaginas: prev.totalPaginas || Math.max(1, Math.ceil((nextTotal || 1) / 25)),
        termosUsados: job.terms || prev.termosUsados || [],
        termosNegativos: job.negative_terms || prev.termosNegativos || [],
        fonteIA: job.suggested_positive_terms?.length ? 'IA + termos aceitos' : (prev.fonteIA || null),
        summary: job.summary || prev.summary || null,
        query_plan: nextPlan,
        list_by_term: job.list_by_term || job.query_plan?.list_by_term || prev.list_by_term || null,
        list_total: Number(job.list_total ?? job.query_plan?.list_total ?? prev.list_total ?? nextTotal) || nextTotal,
        visibility_counts: job.visibility_counts || prev.visibility_counts || null,
        diagnostics: {
          aiRequested: true,
          aiUsed: Boolean(job.suggested_positive_terms?.length || job.accepted_positive_terms?.length),
          jobStatus: job.status,
        },
      };
    });
    if (resetScope) {
      setPncpResultScope('list');
      pncpResultScopeRef.current = 'list';
      setShowPncpHidden(false);
    }
  };

  const normalizePncpResultScope = (raw) => {
    const scope = String(raw || 'list').toLowerCase();
    // pipeline removido da UI — itens no board só somem de "Na lista" via reconcile.
    if (scope === 'pipeline') return 'list';
    if (scope === 'visible' || scope === 'all' || scope === 'active') return 'list';
    if (scope === 'descartados' || scope === 'discarded' || scope === 'hidden') return 'hidden';
    return scope || 'list';
  };

  const getDesiredPncpResultScope = () => {
    // Aba Descartados tem prioridade sobre o chip de escopo (poll com closure velha).
    if (pncpJobModalTabRef.current === 'descartados') return 'hidden';
    return normalizePncpResultScope(pncpResultScopeRef.current || 'list');
  };

  const loadPncpJobResults = async (jobId, page = 1, overrides = {}) => {
    if (!jobId) return null;
    // fromPoll: só alimenta a lista com a visualização atual (refs). Não pode
    // “puxar” página/ordenação/tamanho de volta ao default enquanto o user navega.
    const fromPoll = Boolean(overrides.fromPoll);
    // list = disponíveis (sem pipeline); pipeline = já no board; hidden = Descartados.
    const rawScope = overrides.scope != null
      ? overrides.scope
      : (pncpJobModalTabRef.current === 'descartados'
        ? 'hidden'
        : (pncpResultScopeRef.current || pncpResultScope || 'list'));
    const effectiveScope = normalizePncpResultScope(rawScope);
    const effectivePage = fromPoll
      ? Math.max(1, Number(pncpJobResultsPageRef.current || 1) || 1)
      : Math.max(1, Number(page) || 1);
    const effectiveTam = Math.max(
      5,
      Math.min(100, Number(
        overrides.tam != null
          ? overrides.tam
          : (pncpJobResultsPageSizeRef.current || pncpJobResultsPageSize || 25)
      ) || 25)
    );
    const effectiveOrdenacao = String(
      overrides.ordenacao
      || pncpJobResultsOrdenacaoRef.current
      || pncpJobResultsOrdenacao
      || 'relevancia_desc'
    );
    // Intenção do usuário grava nos refs *antes* do await, para o poll não vencer a corrida.
    if (!fromPoll) {
      pncpJobResultsPageRef.current = effectivePage;
      pncpJobResultsPageSizeRef.current = effectiveTam;
      pncpJobResultsOrdenacaoRef.current = effectiveOrdenacao;
      if (overrides.scope != null) pncpResultScopeRef.current = effectiveScope;
    }
    // Token anti-corrida: resposta antiga (ex.: poll em list) não sobrescreve Descartados.
    const loadSeq = ++pncpResultsLoadSeqRef.current;
    let response;
    try {
      response = await axios.get(`/api/licitacoes/pncp/search/deep/${jobId}/results`, {
        params: {
          pagina: effectivePage,
          tam: effectiveTam,
          ordenacao: effectiveOrdenacao,
          scope: effectiveScope,
        },
      });
    } catch (error) {
      if (loadSeq === pncpResultsLoadSeqRef.current) throw error;
      return null;
    }
    // Outra carga mais nova já partiu (troca de aba / novo poll).
    if (loadSeq !== pncpResultsLoadSeqRef.current) return null;
    // Preferências da UI mudaram no meio do request — descarta payload incompatível
    // (ex.: poll da pág. 1 não pode sobrescrever a pág. 3 que o usuário acabou de abrir).
    const desiredScope = getDesiredPncpResultScope();
    if (effectiveScope !== desiredScope) return null;
    if (effectivePage !== Math.max(1, Number(pncpJobResultsPageRef.current || 1) || 1)) return null;
    if (effectiveTam !== Math.max(5, Math.min(100, Number(pncpJobResultsPageSizeRef.current || 25) || 25))) return null;
    if (effectiveOrdenacao !== String(pncpJobResultsOrdenacaoRef.current || 'relevancia_desc')) return null;

    const payload = response.data || {};
    const total = Number(payload.total || 0);
    const visCounts = payload.visibility_counts || null;
    // NÃO reescrever pageSize/ordenacao a partir do payload — preferência é do usuário.
    setPncpJobResultsPage(effectivePage);
    const loadedItems = (Array.isArray(payload.items) ? payload.items : []).map(item => (
      item && typeof item === 'object' && effectiveScope === 'hidden'
        ? { ...item, __from_hidden_scope: true, __visibility_db: item.__visibility_db || 'hidden' }
        : item
    ));
    setPncpSearchResults(prev => ({
      ...prev,
      // Lista vazia legítima (0 itens no scope) deve limpar; não reaproveitar itens da outra aba.
      items: loadedItems,
      // total = contagem do scope atual (list / pipeline / hidden).
      total: (effectiveScope === 'hidden' || effectiveScope === 'pipeline')
        ? total
        : (total || Number(visCounts?.list ?? visCounts?.visible ?? prev.total ?? 0)),
      pagina: Number(payload.pagina || effectivePage),
      // Mantém o tamanho escolhido pelo usuário; payload só confirma a página servida.
      tamanhoPagina: effectiveTam,
      totalPaginas: Number(payload.totalPaginas || 1),
      summary: payload.summary || prev.summary || null,
      // Contagens canônicas do banco (não da página de 25 itens).
      visibility_counts: visCounts || prev.visibility_counts || null,
      collection: payload.collection || prev.collection || null,
      list_by_term: payload.list_by_term || payload.collection?.list_by_term || prev.list_by_term || null,
      list_total: Number(
        payload.list_total
        ?? payload.collection?.list_total
        ?? visCounts?.list
        ?? (effectiveScope === 'list' ? total : prev.list_total)
        ?? prev.list_total
        ?? 0
      ),
    }));
    // Migra descarte legado (localStorage) → visibility=hidden no job, para sumir da lista e ir à aba Descartados.
    if (effectiveScope === 'list' && pncpHiddenIds.length > 0 && loadedItems.length > 0) {
      const syncKey = String(jobId);
      const legacyToSync = loadedItems.filter(it => it && pncpHiddenIds.includes(it.id) && it.__visibility_db !== 'hidden');
      if (legacyToSync.length > 0 && !pncpLegacyDiscardSyncedRef.current.has(syncKey)) {
        pncpLegacyDiscardSyncedRef.current.add(syncKey);
        Promise.allSettled(legacyToSync.map(it => axios.patch(
          `/api/licitacoes/pncp/search/deep/${jobId}/results/visibility`,
          { item: it, item_id: it.id, result_key: it.__result_key || undefined, visibility: 'hidden' }
        ))).then((results) => {
          const anyOk = results.some(r => r.status === 'fulfilled');
          if (anyOk) {
            loadPncpJobResults(jobId, effectivePage, { scope: effectiveScope, tam: effectiveTam }).catch(() => null);
          }
        }).catch(() => null);
      }
    }
    // Card do job = lista ativa (sem descartados).
    const canonicalTotal = Number(visCounts?.list ?? payload.list_total ?? (effectiveScope === 'hidden' ? undefined : total) ?? 0);
    if (jobId && Number.isFinite(canonicalTotal) && canonicalTotal >= 0 && visCounts) {
      setPncpSearchJobs(prev => prev.map(job => (
        String(job.id) === String(jobId)
          ? {
              ...job,
              total: canonicalTotal,
              summary: payload.summary
                ? { ...(job.summary || {}), ...payload.summary, count: canonicalTotal }
                : job.summary,
            }
          : job
      )));
    }
    return payload;
  };

  const loadPncpSearchJobs = async () => {
    try {
      const response = await axios.get('/api/licitacoes/pncp/search/jobs');
      const jobs = Array.isArray(response.data) ? response.data : [];
      setPncpSearchJobs(jobs);
      setPncpSearchJobsCount(getCurrentPncpSearchJobsCount(jobs));
      return jobs;
    } catch (error) {
      console.error('Error loading PNCP jobs:', error);
      return [];
    }
  };

  const openPncpSearchJob = async (jobId, { refreshJobs = true, openModal = true } = {}) => {
    if (!jobId) return;
    try {
      const response = await axios.get(`/api/licitacoes/pncp/search/deep/${jobId}`);
      setActivePncpSearchJobId(jobId);
      setPncpResultLocalQuery('');
      setPncpResultScope('list');
      pncpResultScopeRef.current = 'list';
      setPncpJobModalTab('resultados');
      pncpJobModalTabRef.current = 'resultados';
      setPncpJobResultsPage(1);
      pncpJobResultsPageRef.current = 1;
      // Ordenação inicial do job (ou default); o user pode mudar depois sem o poll resetar.
      const initialOrdenacao = response.data?.filters?.ordenacao || 'relevancia_desc';
      setPncpJobResultsOrdenacao(initialOrdenacao);
      pncpJobResultsOrdenacaoRef.current = initialOrdenacao;
      setPncpJobFiltersEditing(false);
      seedPncpJobFilterDraft(response.data?.filters || {});
      applyPncpJobSnapshot(response.data, { resetScope: true });
      setPncpSearchJobs(prev => {
        const next = {
          id: jobId,
          nome: response.data?.filters?.q || response.data?.nome,
          status: response.data?.status,
          filters: response.data?.filters || {},
          terms: response.data?.terms || [],
          negative_terms: response.data?.negative_terms || [],
          progress: response.data?.progress || {},
          total: Number(response.data?.total || 0),
          summary: response.data?.summary || null,
          error: response.data?.error || null,
          watchlist_id: response.data?.watchlist_id || null,
          started_at: response.data?.started_at,
          updated_at: response.data?.updated_at,
          completed_at: response.data?.completed_at,
          archive_at: response.data?.archive_at || null,
          days_until_archive: response.data?.days_until_archive,
          archive_days: response.data?.archive_days || 15,
          term_runs: response.data?.term_runs || response.data?.query_plan?.term_runs || [],
        };
        const exists = prev.some(j => String(j.id) === String(jobId));
        if (!exists) return [next, ...prev].slice(0, 20);
        return prev.map(j => String(j.id) === String(jobId) ? { ...j, ...next } : j);
      });
      // Abre o popup imediatamente com o snapshot do job; a paginação do banco
      // (que pode esperar o gate do PNCP para enriquecer valores) atualiza depois.
      if (openModal) setPncpJobModalOpen(true);
      await loadPncpJobResults(jobId, 1).catch(err => console.warn('Erro ao paginar resultados do job:', err?.message));
      try {
        localStorage.setItem('pncp_active_search_job_id', jobId);
      } catch {}
      if (refreshJobs) loadPncpSearchJobs();
    } catch (error) {
      console.error('Error opening PNCP job:', error);
      if (error.response?.status === 404) {
        setActivePncpSearchJobId(null);
        setPncpJobModalOpen(false);
        try {
          localStorage.removeItem('pncp_active_search_job_id');
        } catch {}
      }
    }
  };

  const closePncpSearchJobModal = () => {
    setPncpJobModalOpen(false);
    setPncpJobFiltersEditing(false);
    setPncpJobHeaderExpanded(false);
    // Nunca deixe o botão "Iniciar busca" preso ao lifecycle do job/modal.
    setPncpSearchLoading(false);
  };

  const applyPncpJobFiltersAndRerun = async () => {
    if (!activePncpSearchJobId) return;
    setPncpJobFiltersSaving(true);
    try {
      await axios.post(`/api/licitacoes/pncp/search/deep/${activePncpSearchJobId}/filters`, {
        filters: {
          ...pncpJobFilterDraft,
          usar_ia: pncpJobFilterDraft.usar_ia ? 'true' : 'false',
          // mantém o q original do job se o draft não tiver
          q: activePncpSearchJob?.filters?.q || activePncpSearchJob?.nome || pncpSearchFilters.q || '',
        },
      });
      setPncpJobFiltersEditing(false);
      await openPncpSearchJob(activePncpSearchJobId, { refreshJobs: true, openModal: true });
      await loadPncpSearchJobs();
    } catch (error) {
      alert(`Erro ao reaplicar filtros: ${error.response?.data?.error || error.message}`);
    } finally {
      setPncpJobFiltersSaving(false);
    }
  };

  const cancelPncpSearchJob = async (jobId) => {
    if (!jobId) return;
    try {
      await axios.post(`/api/licitacoes/pncp/search/deep/${jobId}/cancel`);
      await loadPncpSearchJobs();
      if (activePncpSearchJobId === jobId && pncpJobModalOpen) {
        await openPncpSearchJob(jobId, { refreshJobs: false, openModal: true });
      }
    } catch (error) {
      console.error('Error cancelling PNCP job:', error);
    }
  };

  // Reexecuta mantendo resultados já encontrados (UPSERT no backend).
  const rerunPncpSearchJob = async (jobId) => {
    if (!jobId) return;
    try {
      setPncpSearchLoading(true);
      await axios.post(`/api/licitacoes/pncp/search/deep/${jobId}/rerun`);
      await loadPncpSearchJobs();
      if (String(activePncpSearchJobId) === String(jobId)) {
        await openPncpSearchJob(jobId, { refreshJobs: false, openModal: pncpJobModalOpen });
      }
    } catch (error) {
      const msg = error.response?.data?.error || error.message;
      alert(`Não foi possível rodar de novo: ${msg}`);
    } finally {
      setPncpSearchLoading(false);
    }
  };

  const requestDeletePncpSearchJob = (jobId) => {
    if (!jobId) return;
    const job = pncpSearchJobs.find(j => String(j.id) === String(jobId))
      || (String(activePncpSearchJobId) === String(jobId) ? activePncpSearchJob : null);
    setPncpDeleteJobConfirm({
      id: jobId,
      nome: job?.nome || job?.filters?.q || 'Pesquisa PNCP',
      total: Number(job?.total || 0),
      terms: Array.isArray(job?.terms) ? job.terms : [],
      status: job?.status || null,
      live: isPncpJobLive(job?.status),
      watchlist: Boolean(job?.watchlist_id),
    });
  };

  const closeDeletePncpSearchJobConfirm = () => {
    if (pncpDeleteJobBusy) return;
    setPncpDeleteJobConfirm(null);
  };

  const confirmDeletePncpSearchJob = async () => {
    const jobId = pncpDeleteJobConfirm?.id;
    if (!jobId) return;
    setPncpDeleteJobBusy(true);
    try {
      await axios.delete(`/api/licitacoes/pncp/search/deep/${jobId}`);
      setPncpDeleteJobConfirm(null);
      if (String(activePncpSearchJobId) === String(jobId)) {
        setActivePncpSearchJobId(null);
        setPncpJobModalOpen(false);
        setPncpSearchResults({ items: [], total: 0, pagina: 1, totalPaginas: 0, termosUsados: [], termosNegativos: [], fonteIA: null });
        try {
          localStorage.removeItem('pncp_active_search_job_id');
        } catch {}
      }
      await loadPncpSearchJobs();
    } catch (error) {
      console.error('Error deleting PNCP job:', error);
      alert(`Erro ao excluir: ${error.response?.data?.error || error.message}`);
    } finally {
      setPncpDeleteJobBusy(false);
    }
  };

  // Alias usado pelos botões do card/modal (abre o diálogo, não exclui direto).
  const deletePncpSearchJob = requestDeletePncpSearchJob;

  const convertPncpSearchJobToWatchlist = (jobId) => {
    if (!jobId) return;
    const job = pncpSearchJobs.find(item => String(item.id) === String(jobId))
      || (String(activePncpSearchJobId) === String(jobId) ? activePncpSearchJob : null);
    const contextLabel = job?.filters?.q || pncpSearchFilters.q || 'Busca PNCP';
    setPncpWatchlistDialog({
      source: 'job',
      jobId,
      defaultName: job?.nome || contextLabel || 'Busca PNCP',
      contextLabel,
      alreadySubscribed: Boolean(job?.watchlist_id),
      initialWhatsappEnabled: Boolean(job?.whatsapp_enabled || job?.alerts_enabled),
      initialWhatsappNumber: job?.whatsapp_number || '',
      initialWhatsappNumbers: job?.whatsapp_numbers || null,
      initialWhatsappMinScore: job?.whatsapp_min_score,
      initialWhatsappScoreBand: job?.whatsapp_score_band,
    });
  };

  const closePncpWatchlistDialog = () => {
    if (!pncpWatchlistSaving) setPncpWatchlistDialog(null);
  };

  const confirmPncpWatchlist = async (values) => {
    const draft = pncpWatchlistDialog;
    if (!draft) return;
    setPncpWatchlistSaving(true);
    try {
      if (draft.source === 'job') {
        await axios.post(`/api/licitacoes/pncp/search/deep/${draft.jobId}/watchlist`, values);
        setPncpWatchlistDialog(null);
        await loadPncpSearchJobs();
        // Mantém na aba de buscas — o card *é* a assinatura; não força ir para watchlists.
        if (String(activePncpSearchJobId) === String(draft.jobId)) {
          await openPncpSearchJob(draft.jobId, { refreshJobs: false, openModal: pncpJobModalOpen });
        }
      } else {
        const term = String(pncpSearchFilters.q || '').trim();
        await axios.post('/api/licitacoes/editais/watchlist', {
          ...values,
          palavras_chave: Array.from(new Set([term, ...pncpAcceptedPositiveTerms])).filter(Boolean),
          termos_negativos: Array.from(new Set([...(splitTermsInput(pncpSearchFilters.negative_terms || '')), ...pncpAcceptedNegativeTerms])).filter(Boolean),
          usar_ia: pncpSearchFilters.usar_ia,
          filtros: {
            tipos_documento: pncpSearchFilters.tipos_documento,
            status: pncpSearchFilters.status,
            modalidade_licitacao_id: pncpSearchFilters.modalidade_licitacao_id,
            tipo_id: pncpSearchFilters.tipo_id,
            modo_disputa_id: pncpSearchFilters.modo_disputa_id,
            uf: pncpSearchFilters.uf,
            esfera_id: pncpSearchFilters.esfera_id,
            orgao_cnpj: pncpSearchFilters.orgao_cnpj || pncpOrgaoLookupQuery,
            unidade_codigo: pncpSearchFilters.unidade_codigo || pncpUasgLookupQuery,
            ordenacao: pncpSearchFilters.ordenacao,
          },
        });
        setPncpWatchlistDialog(null);
        await loadPncpSearchJobs();
        setLicitacaoSubview('editais_watchlist');
      }
    } catch (error) {
      alert(`Erro: ${error.response?.data?.error || error.message}`);
    } finally {
      setPncpWatchlistSaving(false);
    }
  };

  const addPncpCustomTerms = () => {
    const terms = splitTermsInput(pncpCustomTermInput);
    if (!terms.length) return;
    setPncpAcceptedPositiveTerms(prev => Array.from(new Set([...prev, ...terms])));
    setPncpCustomTermInput('');
  };

  const postPncpSearchJobTerms = async (jobId, payload) => {
    if (!jobId) throw new Error('Nenhuma busca selecionada.');
    try {
      return await axios.post(`/api/licitacoes/pncp/search/deep-terms/${jobId}`, payload);
    } catch (error) {
      if (error.response?.status === 404) {
        setActivePncpSearchJobId(null);
        try {
          localStorage.removeItem('pncp_active_search_job_id');
        } catch {}
        await loadPncpSearchJobs();
        throw new Error('Essa busca nao foi encontrada no backend atual. Reabra uma busca recente ou reinicie o backend local para carregar a rota nova.');
      }
      throw error;
    }
  };

  // Converte o texto digitado em chip local (vírgula) antes de anexar ao job.
  const commitPncpActiveJobTermDraft = () => {
    const draft = String(pncpActiveJobTermInput || '').trim().replace(/[,;]+$/, '');
    if (!draft) return [];
    const parts = splitTermsInput(draft);
    if (!parts.length) return [];
    setPncpActiveJobPendingTerms(prev => Array.from(new Set([...prev, ...parts])));
    setPncpActiveJobTermInput('');
    return parts;
  };

  const removePncpActiveJobPendingTerm = (term) => {
    setPncpActiveJobPendingTerms(prev => prev.filter(item => item !== term));
  };

  const addTermsToActivePncpJob = async (extraTerms = []) => {
    const draftParts = splitTermsInput(String(pncpActiveJobTermInput || '').trim().replace(/[,;]+$/, ''));
    const terms = Array.from(new Set([
      ...pncpActiveJobPendingTerms,
      ...draftParts,
      ...(Array.isArray(extraTerms) ? extraTerms : []),
    ].map(t => String(t || '').trim()).filter(t => t.length >= 2)));
    if (!activePncpSearchJobId || !terms.length) return;
    const existing = (activePncpSearchJob?.terms || []).map(t => normalizeText(t));
    const toAdd = terms.filter(t => !existing.includes(normalizeText(t)));
    setPncpActiveJobPendingTerms([]);
    setPncpActiveJobTermInput('');
    if (!toAdd.length) return;

    const nextTerms = Array.from(new Set([...(activePncpSearchJob?.terms || []), ...toAdd])).slice(0, 12);
    // Otimista: chip aparece na hora (antes o backend não gravava terms e sumia no refresh).
    setPncpSearchJobs(prev => prev.map(job => (
      String(job.id) === String(activePncpSearchJobId)
        ? {
            ...job,
            terms: nextTerms,
            progress: {
              ...(job.progress || {}),
              terms_total: Math.max(Number(job.progress?.terms_total || 0), nextTerms.length),
            },
          }
        : job
    )));
    try {
      const response = await postPncpSearchJobTerms(activePncpSearchJobId, { terms: toAdd });
      const payload = response?.data || {};
      if (payload.terms) {
        setPncpSearchJobs(prev => prev.map(job => (
          String(job.id) === String(activePncpSearchJobId)
            ? {
                ...job,
                terms: payload.terms || job.terms,
                negative_terms: payload.negative_terms || job.negative_terms,
                status: payload.status || job.status,
                progress: payload.progress || job.progress,
                total: payload.total != null ? Number(payload.total) : job.total,
              }
            : job
        )));
      }
      await openPncpSearchJob(activePncpSearchJobId, { refreshJobs: true, openModal: true });
    } catch (error) {
      await loadPncpSearchJobs();
      alert(`Erro: ${error.response?.data?.error || error.message}`);
    }
  };

  const runPncpSearch = async (page = 1, overrides = {}) => {
    // Loading só cobre o POST de criação — o job roda em background nos cards.
    // Antes, loading ficava true até o job terminar no modal; fechar o popup
    // deixava "Iniciar busca" travado em "Iniciando…" até recarregar a página.
    setPncpSearchLoading(true);
    const effectiveFilters = { ...pncpSearchFilters, ...overrides };
    try {
      const response = await axios.post('/api/licitacoes/pncp/search/deep-start', {
        filters: {
          q: effectiveFilters.q,
          tipos_documento: effectiveFilters.tipos_documento,
          status: effectiveFilters.status,
          modalidade_licitacao_id: effectiveFilters.modalidade_licitacao_id || undefined,
          semantic: 'true',
          negative_terms: effectiveFilters.negative_terms || undefined,
          tipo_id: effectiveFilters.tipo_id || undefined,
          modo_disputa_id: effectiveFilters.modo_disputa_id || undefined,
          uf: effectiveFilters.uf || undefined,
          esfera_id: effectiveFilters.esfera_id || undefined,
          orgao_cnpj: effectiveFilters.orgao_cnpj || (String(pncpOrgaoLookupQuery || '').trim().length >= 2 ? pncpOrgaoLookupQuery : undefined),
          unidade_codigo: effectiveFilters.unidade_codigo || (String(pncpUasgLookupQuery || '').trim().length >= 2 ? pncpUasgLookupQuery : undefined),
          ordenacao: effectiveFilters.ordenacao,
          usar_ia: effectiveFilters.usar_ia ? 'true' : 'false',
        },
        terms: [effectiveFilters.q, ...pncpAcceptedPositiveTerms].filter(Boolean),
        accepted_positive_terms: pncpAcceptedPositiveTerms,
        accepted_negative_terms: pncpAcceptedNegativeTerms,
        suggested_positive_terms: pncpSuggestedTerms.positivos || [],
        suggested_negative_terms: pncpSuggestedTerms.negativos || [],
      });
      const jobId = response.data?.job_id;
      setActivePncpSearchJobId(jobId || null);
      if (jobId) {
        try {
          localStorage.setItem('pncp_active_search_job_id', jobId);
        } catch {}
      }
      if (jobId) {
        const optimisticJob = {
          id: jobId,
          nome: effectiveFilters.q || 'Busca PNCP',
          status: response.data?.reused ? response.data.status || 'queued' : 'queued',
          filters: effectiveFilters,
          terms: [effectiveFilters.q, ...pncpAcceptedPositiveTerms].filter(Boolean),
          negative_terms: pncpAcceptedNegativeTerms,
          progress: {
            current_term: '',
            terms_done: 0,
            terms_total: [effectiveFilters.q, ...pncpAcceptedPositiveTerms].filter(Boolean).length,
            items_collected: 0,
          },
          total: 0,
          updated_at: new Date().toISOString(),
        };
        setPncpSearchJobs(prev => [optimisticJob, ...prev.filter(job => String(job.id) !== String(jobId))].slice(0, 20));
      }
      setPncpResultScope('list');
      setShowPncpHidden(false);
      await loadPncpSearchJobs();
      if (jobId) {
        setTimeout(() => openPncpSearchJob(jobId, { openModal: true }), response.data?.reused ? 100 : 600);
      }
    } catch (error) {
      console.error('Error searching PNCP:', error);
      alert(`Erro ao iniciar busca: ${error.response?.data?.error || error.message}`);
    } finally {
      setPncpSearchLoading(false);
    }
  };

  useEffect(() => {
    pncpOutcomeFiltersRef.current = pncpOutcomeFilters;
  }, [pncpOutcomeFilters]);

  const sortPncpOutcomeItems = (items, ordenacao) => {
    const value = (item) => Number(item.valor_homologado || item.valor_estimado || 0);
    const date = (item) => new Date(item.data_publicacao || item.data_assinatura || item.data_resultado || 0).getTime();
    const arr = [...items];
    if (ordenacao === 'valor_desc') arr.sort((a, b) => value(b) - value(a));
    else if (ordenacao === 'valor_asc') arr.sort((a, b) => value(a) - value(b));
    else if (ordenacao === 'data_asc') arr.sort((a, b) => date(a) - date(b));
    else if (ordenacao !== 'relevancia') arr.sort((a, b) => date(b) - date(a));
    return arr;
  };

  const mergePncpOutcomeItems = (items) => {
    const merged = new Map();
    items.forEach((item, index) => {
      const purchaseKey = item.orgao_cnpj && item.ano && item.sequencial
        ? `${String(item.orgao_cnpj).replace(/\D/g, '')}/${item.ano}/${Number(item.sequencial)}`
        : null;
      const key = purchaseKey || item.pncp_key || item.url || `row-${index}`;
      const current = merged.get(key);
      if (!current) {
        merged.set(key, item);
        return;
      }
      const fornecedores = [...(current.fornecedores || []), ...(item.fornecedores || [])]
        .filter((row, supplierIndex, rows) => rows.findIndex(candidate => (
          (row?.ni && candidate?.ni === row.ni) || (!row?.ni && row?.nome && candidate?.nome === row.nome)
        )) === supplierIndex);
      merged.set(key, {
        ...current,
        ...item,
        has_result: current.has_result === true || item.has_result === true,
        has_contract: current.has_contract === true || item.has_contract === true,
        has_ata: current.has_ata === true || item.has_ata === true,
        fornecedores,
      });
    });
    return [...merged.values()];
  };

  const summarizePncpOutcomeItems = (items) => items.reduce((acc, item) => {
    const value = Number(item.valor_homologado || item.valor_estimado || 0);
    acc.total_value += Number.isFinite(value) ? value : 0;
    return acc;
  }, { count: items.length, total_value: 0 });

  const pncpOutcomeItemKey = (item) => (item.doc_ids
    ? `${item.doc_ids.cnpj}/${item.doc_ids.ano}/${Number(item.doc_ids.sequencial)}`
    : item.pncp_key || item.numero_controle_pncp || null);

  const PNCP_OUTCOME_FETCH_TAM = 50; // máximo do backend; menos idas ao PNCP
  const PNCP_OUTCOME_VIEW_TAM = 20; // paginação só no cliente (sem re-fetch)
  const PNCP_OUTCOME_MAX_PAGES_PER_TIPO = 100; // teto de segurança (~5k docs)
  const PNCP_OUTCOME_STORAGE_KEY = 'pncp_outcome_search_v1';
  // Retomadas de rate-limit (como o job de editais): não desiste até o total
  // prometido ou cancelamento do usuário (Limpar / nova Busca).
  const PNCP_OUTCOME_MAX_THROTTLE_PAUSES = 40;

  const readPncpOutcomeCheckpoint = () => {
    try {
      const raw = sessionStorage.getItem(PNCP_OUTCOME_STORAGE_KEY);
      if (!raw) return null;
      const data = JSON.parse(raw);
      if (!data || typeof data !== 'object') return null;
      return data;
    } catch {
      return null;
    }
  };

  const writePncpOutcomeCheckpoint = (snapshot) => {
    try {
      if (!snapshot) {
        sessionStorage.removeItem(PNCP_OUTCOME_STORAGE_KEY);
        return;
      }
      // Cap de itens no storage para não estourar a cota (~5MB).
      const items = Array.isArray(snapshot.items) ? snapshot.items.slice(0, 2500) : [];
      sessionStorage.setItem(PNCP_OUTCOME_STORAGE_KEY, JSON.stringify({
        ...snapshot,
        items,
        updatedAt: Date.now(),
      }));
    } catch (err) {
      // quota / private mode — segue só em memória
      console.warn('[resultados] checkpoint não persistiu:', err?.message || err);
    }
  };

  const clearPncpOutcomeCheckpoint = () => {
    try { sessionStorage.removeItem(PNCP_OUTCOME_STORAGE_KEY); } catch {}
  };

  const publishPncpOutcomeResults = (merged, {
    total,
    pagina,
    complete = false,
    keepPage = false,
    status = null,
  } = {}) => {
    const viewTam = PNCP_OUTCOME_VIEW_TAM;
    const totalPaginas = Math.max(1, Math.ceil(merged.length / viewTam));
    setPncpOutcomeResults(prev => {
      const desired = keepPage
        ? (prev.pagina || 1)
        : Math.max(1, Number(pagina) || 1);
      const clampedPage = Math.min(desired, totalPaginas);
      return {
        items: merged,
        total: Number(total) || merged.length,
        pagina: clampedPage,
        tamanhoPagina: viewTam,
        totalPaginas,
        summary: summarizePncpOutcomeItems(merged),
        requires_query: false,
        complete: Boolean(complete),
        status: status || prev.status || (complete ? 'done' : 'running'),
      };
    });
  };

  // Paginação local: não chama o PNCP de novo.
  const setPncpOutcomeClientPage = useCallback((page) => {
    setPncpOutcomeResults(prev => {
      const viewTam = prev.tamanhoPagina || PNCP_OUTCOME_VIEW_TAM;
      const totalPaginas = Math.max(1, Math.ceil((prev.items || []).length / viewTam));
      const next = Math.max(1, Math.min(totalPaginas, Number(page) || 1));
      if (next === prev.pagina) return prev;
      return { ...prev, pagina: next, totalPaginas };
    });
  }, []);

  // Busca completa e progressiva, com o mesmo espírito dos jobs de editais:
  //  - puxa TODAS as páginas (priority interactive no gate)
  //  - em 429/reset: pausa, mantém o parcial, retoma a MESMA página
  //  - checkpoint em sessionStorage (sobrevive refresh / troca de aba)
  //  - só marca complete quando o total prometido foi coberto (ou PNCP esgotou)
  const runPncpOutcomeSearch = useCallback(async (overrides = {}, options = {}) => {
    const resume = Boolean(options.resume);
    const token = ++pncpOutcomeSearchTokenRef.current;
    const checkpoint = resume ? readPncpOutcomeCheckpoint() : null;
    const effectiveFilters = resume && checkpoint?.filters
      ? { ...checkpoint.filters, ...overrides }
      : { ...pncpOutcomeFiltersRef.current, ...overrides };
    const tipo = effectiveFilters.tipo || 'todos';
    const ordenacao = effectiveFilters.ordenacao || 'data_desc';
    setPncpOutcomeError('');
    const hasCriteria = Boolean(
      String(effectiveFilters.q || '').trim()
      || String(effectiveFilters.fornecedor || '').trim()
      || String(effectiveFilters.fornecedor_ni || '').trim()
      || String(effectiveFilters.orgao_cnpj || '').trim()
      || String(effectiveFilters.uf || '').trim()
      || (tipo && tipo !== 'todos')
    );
    if (!hasCriteria) {
      pncpOutcomeActiveQueryRef.current = null;
      clearPncpOutcomeCheckpoint();
      setPncpOutcomeLoading(false);
      setPncpOutcomePhase(null);
      setPncpOutcomeResults({
        items: [],
        total: 0,
        pagina: 1,
        totalPaginas: 1,
        tamanhoPagina: PNCP_OUTCOME_VIEW_TAM,
        summary: null,
        requires_query: true,
        complete: false,
        status: null,
      });
      return;
    }

    const filtersSnapshot = {
      q: String(effectiveFilters.q || '').trim(),
      fornecedor: String(effectiveFilters.fornecedor || '').trim(),
      fornecedor_ni: String(effectiveFilters.fornecedor_ni || '').trim(),
      orgao_cnpj: String(effectiveFilters.orgao_cnpj || '').trim(),
      uf: String(effectiveFilters.uf || '').trim(),
      tipo,
      ordenacao,
    };
    pncpOutcomeActiveQueryRef.current = filtersSnapshot;
    // Restaura filtros na UI ao retomar de um checkpoint.
    if (resume && checkpoint?.filters) {
      setPncpOutcomeFilters(prev => ({ ...prev, ...filtersSnapshot }));
      pncpOutcomeFiltersRef.current = { ...pncpOutcomeFiltersRef.current, ...filtersSnapshot };
    }
    // Busca nova (não-resume): descarta checkpoint antigo para não misturar cursores.
    if (!resume) clearPncpOutcomeCheckpoint();

    const tipos = tipo === 'todos' ? ['contrato', 'ata', 'resultado'] : [tipo];
    let merged = resume && Array.isArray(checkpoint?.items)
      ? mergePncpOutcomeItems(checkpoint.items)
      : [];
    let reportedTotal = resume ? Number(checkpoint?.reportedTotal || 0) : 0;
    let lastGateGapMs = Number(checkpoint?.gateGapMs || 950);
    // Em resume, mantém o contador de pausas; em busca nova, zera.
    let throttlePauses = resume ? Number(checkpoint?.throttlePauses || 0) : 0;
    // Cursor por tipo: nextPage / total prometido / done.
    const cursors = {};
    tipos.forEach(t => {
      const saved = checkpoint?.cursors?.[t];
      cursors[t] = {
        nextPage: Math.max(1, Number(saved?.nextPage) || 1),
        total: Math.max(0, Number(saved?.total) || 0),
        totalPages: Math.max(0, Number(saved?.totalPages) || 0),
        itemsSeen: Math.max(0, Number(saved?.itemsSeen) || 0),
        done: Boolean(saved?.done),
      };
    });
    const attempted = new Set(
      Array.isArray(checkpoint?.attemptedKeys) ? checkpoint.attemptedKeys : []
    );

    setPncpOutcomeLoading(true);
    if (!resume || !merged.length) {
      setPncpOutcomeResults({
        items: merged,
        total: reportedTotal,
        pagina: 1,
        totalPaginas: Math.max(1, Math.ceil(merged.length / PNCP_OUTCOME_VIEW_TAM)),
        tamanhoPagina: PNCP_OUTCOME_VIEW_TAM,
        summary: merged.length ? summarizePncpOutcomeItems(merged) : null,
        requires_query: false,
        complete: false,
        status: 'running',
      });
    } else {
      publishPncpOutcomeResults(merged, {
        total: Math.max(reportedTotal, merged.length),
        keepPage: true,
        complete: false,
        status: 'running',
      });
    }

    const persistCheckpoint = (status = 'running') => {
      writePncpOutcomeCheckpoint({
        filters: filtersSnapshot,
        items: merged,
        cursors,
        reportedTotal,
        gateGapMs: lastGateGapMs,
        throttlePauses,
        attemptedKeys: [...attempted].slice(-2000),
        complete: status === 'done',
        status,
      });
    };

    const pushState = (opts = {}) => {
      const sorted = sortPncpOutcomeItems(merged, pncpOutcomeFiltersRef.current.ordenacao || ordenacao);
      merged = sorted;
      publishPncpOutcomeResults(merged, {
        total: Math.max(reportedTotal, merged.length),
        pagina: opts.pagina || 1,
        complete: Boolean(opts.complete),
        keepPage: opts.keepPage !== false && !opts.resetPage,
        status: opts.status || (opts.complete ? 'done' : 'running'),
      });
      persistCheckpoint(opts.complete ? 'done' : (opts.status || 'running'));
    };

    const sleepMs = (ms) => new Promise(resolve => setTimeout(resolve, ms));

    const waitWhileCancelled = async (ms, label) => {
      const until = Date.now() + Math.max(0, ms);
      while (Date.now() < until) {
        if (pncpOutcomeSearchTokenRef.current !== token) return false;
        const left = until - Date.now();
        if (label) {
          setPncpOutcomePhase({
            stage: 'paused_rate_limit',
            label,
            loaded: merged.length,
            total: reportedTotal || undefined,
            resumeInMs: left,
          });
        }
        await sleepMs(Math.min(1000, Math.max(200, left)));
      }
      return pncpOutcomeSearchTokenRef.current === token;
    };

    // Uma página do PNCP com retry/backoff no mesmo espírito do deep job.
    const fetchOutcomePage = async (tipoDoc, page) => {
      let attempt = 0;
      for (;;) {
        if (pncpOutcomeSearchTokenRef.current !== token) return null;
        try {
          const response = await axios.get('/api/licitacoes/pncp/resultados/search', {
            params: {
              q: effectiveFilters.q || undefined,
              fornecedor: effectiveFilters.fornecedor || undefined,
              fornecedor_ni: effectiveFilters.fornecedor_ni || undefined,
              orgao_cnpj: effectiveFilters.orgao_cnpj || undefined,
              uf: effectiveFilters.uf || undefined,
              tipo: tipoDoc,
              ordenacao,
              pagina: page,
              tam: PNCP_OUTCOME_FETCH_TAM,
              enrich: 'false',
              live_only: tipoDoc === 'resultado' ? undefined : 'true',
            },
            // 503 de rate-limit é esperado; não joga no interceptor genérico.
            validateStatus: (s) => (s >= 200 && s < 300) || s === 503 || s === 502,
          });
          const data = response.data || {};
          if (data.gate?.gap_ms) lastGateGapMs = Number(data.gate.gap_ms) || lastGateGapMs;

          if (response.status === 503 || data.rate_limited) {
            throttlePauses += 1;
            if (throttlePauses > PNCP_OUTCOME_MAX_THROTTLE_PAUSES) {
              throw new Error(data.error || 'PNCP limitou as requisições por tempo demais');
            }
            const retryAfter = Math.min(
              6 * 60 * 1000,
              Math.max(
                15_000,
                Number(data.retry_after_ms)
                  || Number(data.gate?.paused_for_ms)
                  || Math.round(lastGateGapMs * 20)
                  || 45_000
              )
            );
            const mins = Math.max(1, Math.ceil(retryAfter / 60000));
            pushState({ keepPage: true, status: 'paused_rate_limit' });
            setPncpOutcomeError('');
            const ok = await waitWhileCancelled(
              retryAfter,
              `PNCP limitou as requisições — pausado ~${mins} min, retoma sozinho (parcial salvo)`
            );
            if (!ok) return null;
            attempt += 1;
            continue; // mesma página
          }

          if (response.status >= 400) {
            // Erro transitório (rede/502): backoff e tenta de novo a mesma página.
            attempt += 1;
            if (attempt > 6) {
              throw new Error(data.error || data.details || `HTTP ${response.status}`);
            }
            const backoff = Math.min(60_000, 2000 * (2 ** Math.min(attempt, 4)));
            pushState({ keepPage: true, status: 'paused_rate_limit' });
            const ok = await waitWhileCancelled(
              backoff,
              `Falha temporária no PNCP — nova tentativa em ${Math.ceil(backoff / 1000)}s (parcial salvo)`
            );
            if (!ok) return null;
            continue;
          }

          return data;
        } catch (error) {
          if (pncpOutcomeSearchTokenRef.current !== token) return null;
          const payload = error?.response?.data || {};
          const isThrottle = payload.rate_limited
            || error?.response?.status === 503
            || /429|rate.?limit|reset|econnreset|timed?\s*out/i.test(String(error?.message || payload.details || ''));
          attempt += 1;
          throttlePauses += isThrottle ? 1 : 0;
          if (throttlePauses > PNCP_OUTCOME_MAX_THROTTLE_PAUSES || attempt > 8) {
            throw error;
          }
          const retryAfter = Math.min(
            6 * 60 * 1000,
            Math.max(
              isThrottle ? 20_000 : 3_000,
              Number(payload.retry_after_ms)
                || Number(payload.gate?.paused_for_ms)
                || (isThrottle ? 45_000 : 2000 * (2 ** Math.min(attempt, 4)))
            )
          );
          pushState({ keepPage: true, status: 'paused_rate_limit' });
          setPncpOutcomeError('');
          const ok = await waitWhileCancelled(
            retryAfter,
            isThrottle
              ? `PNCP limitou as requisições — pausado ~${Math.max(1, Math.ceil(retryAfter / 60000))} min, retoma sozinho`
              : `Erro de rede — nova tentativa em ${Math.ceil(retryAfter / 1000)}s (parcial salvo)`
          );
          if (!ok) return null;
        }
      }
    };

    const enrichPending = async ({ maxRounds = 12, phaseLabel = true } = {}) => {
      const listPending = () => merged.filter(item => item.doc_type === 'contrato' && item.doc_ids
        && !item.fornecedor_nome && !attempted.has(pncpOutcomeItemKey(item)));
      let pendingItems = listPending();
      let rounds = 0;
      const totalToEnrich = pendingItems.length;
      while (pendingItems.length && rounds < maxRounds && pncpOutcomeSearchTokenRef.current === token) {
        if (phaseLabel) {
          setPncpOutcomePhase({
            stage: 'enriching',
            label: `Completando fornecedores e valores… ${totalToEnrich - pendingItems.length}/${Math.max(totalToEnrich, pendingItems.length)}`,
            loaded: merged.length,
            total: reportedTotal || undefined,
          });
        }
        const batch = pendingItems.slice(0, 8);
        let payload = null;
        try {
          const response = await axios.post('/api/licitacoes/pncp/resultados/enrich', {
            contratos: batch.map(item => ({
              ...item.doc_ids,
              pncp_key: item.pncp_key,
              titulo: item.titulo,
              descricao: item.descricao,
              uf: item.uf,
              orgao_nome: item.orgao_nome,
              modalidade: item.modalidade,
              data_publicacao: item.data_publicacao,
            })),
          });
          payload = response.data || {};
        } catch {
          // Enrich é best-effort: se o gate falhar, tenta de novo mais tarde.
          const ok = await waitWhileCancelled(5000, 'Aguardando gate do PNCP para enriquecer…');
          if (!ok) return;
          rounds += 1;
          continue;
        }
        if (pncpOutcomeSearchTokenRef.current !== token) return;
        if (payload.gate?.gap_ms) lastGateGapMs = Number(payload.gate.gap_ms) || lastGateGapMs;
        const enriched = payload.enriched || {};
        Object.keys(enriched).forEach(key => attempted.add(key));
        merged = merged.map(item => {
          const key = pncpOutcomeItemKey(item);
          return key && enriched[key] ? { ...item, ...enriched[key] } : item;
        });
        pushState({ keepPage: true, status: 'running' });
        pendingItems = listPending();
        rounds += 1;
        if (!Object.keys(enriched).length) {
          const pauseMs = Number(payload.gate_paused_ms || payload.gate?.paused_for_ms || 0);
          if (pauseMs > 0) {
            // Como o job de editais: espera o gate em vez de desistir.
            const ok = await waitWhileCancelled(
              Math.min(6 * 60 * 1000, Math.max(pauseMs + 2000, 8000)),
              `PNCP em pausa — enriquecimento retoma em ~${Math.max(1, Math.ceil(pauseMs / 60000))} min`
            );
            if (!ok) return;
          } else {
            await sleepMs(1500);
          }
        }
      }
    };

    try {
      for (const tipoDoc of tipos) {
        if (pncpOutcomeSearchTokenRef.current !== token) return;
        const cursor = cursors[tipoDoc];
        if (cursor.done) continue;

        while (
          cursor.nextPage <= PNCP_OUTCOME_MAX_PAGES_PER_TIPO
          && (!cursor.totalPages || cursor.nextPage <= cursor.totalPages)
          && pncpOutcomeSearchTokenRef.current === token
        ) {
          // Cobre o total prometido: se já vimos tudo que o índice anunciou, para.
          if (cursor.total > 0 && cursor.itemsSeen >= cursor.total) {
            cursor.done = true;
            break;
          }

          setPncpOutcomePhase({
            stage: 'searching',
            label: tipoDoc === 'contrato' ? 'Consultando contratos no PNCP…'
              : tipoDoc === 'ata' ? 'Consultando atas no PNCP…'
                : 'Consultando resultados homologados…',
            loaded: merged.length,
            total: reportedTotal || undefined,
            detail: cursor.total
              ? `${Math.min(cursor.itemsSeen + PNCP_OUTCOME_FETCH_TAM, cursor.total)}/${cursor.total}`
              : `pág. ${cursor.nextPage}`,
          });

          const data = await fetchOutcomePage(tipoDoc, cursor.nextPage);
          if (pncpOutcomeSearchTokenRef.current !== token) return;
          if (!data) return; // cancelado durante wait

          const pageItems = Array.isArray(data.items) ? data.items : [];
          const pageTotal = Number(data.total) || 0;
          if (pageTotal > 0) {
            // Total prometido pelo índice: nunca encolhe sob o usuário (pode oscilar).
            cursor.total = Math.max(cursor.total, pageTotal);
            reportedTotal = tipos.reduce((acc, t) => acc + (Number(cursors[t]?.total) || 0), 0);
            cursor.totalPages = Math.max(
              1,
              Math.min(
                PNCP_OUTCOME_MAX_PAGES_PER_TIPO,
                Number(data.totalPaginas) || Math.ceil(cursor.total / PNCP_OUTCOME_FETCH_TAM) || 1
              )
            );
          }

          if (!pageItems.length) {
            cursor.done = true;
            break;
          }

          cursor.itemsSeen += pageItems.length;
          merged = mergePncpOutcomeItems([...merged, ...pageItems]);
          cursor.nextPage += 1;
          pushState({
            keepPage: true,
            resetPage: merged.length === pageItems.length,
            status: 'running',
          });

          // Página curta = fim da coleção nesse tipo.
          if (pageItems.length < PNCP_OUTCOME_FETCH_TAM) {
            cursor.done = true;
            break;
          }
          if (cursor.total > 0 && cursor.itemsSeen >= cursor.total) {
            cursor.done = true;
            break;
          }

          // Folga entre páginas (além do gap do gate) — igual deep job de editais.
          const pagePause = Math.min(1500, Math.max(250, Math.round(lastGateGapMs * 0.4)));
          if (pagePause > 0 && pncpOutcomeSearchTokenRef.current === token) {
            await sleepMs(pagePause);
          }
        }
        // Só marca done se não foi cancelado no meio (Limpar / nova busca).
        if (pncpOutcomeSearchTokenRef.current === token && !cursor.done) {
          // Saiu por teto de páginas: considera coberto o que deu.
          cursor.done = true;
        }
        if (pncpOutcomeSearchTokenRef.current !== token) return;
        persistCheckpoint('running');
      }

      if (pncpOutcomeSearchTokenRef.current !== token) return;
      // Enriquecimento só depois das páginas (não disputa o gate durante a varredura).
      await enrichPending({ maxRounds: 100, phaseLabel: true });
      if (pncpOutcomeSearchTokenRef.current !== token) return;

      const allDone = tipos.every(t => cursors[t]?.done);
      pushState({ complete: allDone, keepPage: true, status: allDone ? 'done' : 'running' });
      if (allDone) {
        writePncpOutcomeCheckpoint({
          filters: filtersSnapshot,
          items: merged,
          cursors,
          reportedTotal: Math.max(reportedTotal, merged.length),
          gateGapMs: lastGateGapMs,
          throttlePauses,
          attemptedKeys: [...attempted].slice(-2000),
          complete: true,
          status: 'done',
        });
        setPncpOutcomePhase({
          stage: 'done',
          label: `Busca concluída · ${merged.length.toLocaleString('pt-BR')} de ${Math.max(reportedTotal, merged.length).toLocaleString('pt-BR')} item(ns)`,
        });
        setPncpOutcomeError('');
      }
    } catch (error) {
      if (pncpOutcomeSearchTokenRef.current !== token) return;
      console.error('Error searching PNCP outcomes:', error);
      // Nunca joga fora o parcial — grava checkpoint para retomar.
      persistCheckpoint('paused_rate_limit');
      pushState({ complete: false, keepPage: true, status: 'paused_rate_limit' });
      setPncpOutcomeError(
        error?.response?.data?.error
          || error.message
          || 'Erro ao buscar resultados/contratos PNCP.'
      );
      setPncpOutcomePhase({
        stage: 'paused_rate_limit',
        label: merged.length
          ? `Pausado com ${merged.length.toLocaleString('pt-BR')} item(ns) salvos — clique em Buscar para retomar`
          : 'Falha ao consultar o PNCP — tente de novo em instantes',
        loaded: merged.length,
        total: reportedTotal || undefined,
      });
    } finally {
      if (pncpOutcomeSearchTokenRef.current === token) setPncpOutcomeLoading(false);
    }
  }, []);

  const openPncpOutcomeDossier = useCallback(async (item) => {
    setPncpOutcomeDossierTarget(item || null);
    setPncpOutcomeDossier(null);
    setPncpOutcomeDossierError('');
    const cnpj = String(item?.orgao_cnpj || '').replace(/\D/g, '');
    const ano = String(item?.ano || '').trim();
    const sequencial = String(item?.sequencial || '').trim();
    if (!cnpj || !ano || !sequencial) {
      setPncpOutcomeDossierError('Este registro não contém os identificadores necessários para abrir o dossiê no PNCP.');
      return;
    }
    setPncpOutcomeDossierLoading(true);
    try {
      const response = await axios.get(`/api/licitacoes/pncp/compra/${cnpj}/${ano}/${sequencial}/dossier`, {
        params: { q: pncpOutcomeFiltersRef.current.q || undefined },
      });
      setPncpOutcomeDossier(response.data);
    } catch (error) {
      console.error('Error loading PNCP dossier:', error);
      setPncpOutcomeDossierError(error.response?.data?.error || error.message || 'Não foi possível carregar o dossiê PNCP.');
    } finally {
      setPncpOutcomeDossierLoading(false);
    }
  }, []);

  const closePncpOutcomeDossier = useCallback(() => {
    setPncpOutcomeDossierTarget(null);
    setPncpOutcomeDossier(null);
    setPncpOutcomeDossierError('');
    setPncpOutcomeDossierLoading(false);
  }, []);

  // Ao abrir a aba: restaura checkpoint (parcial + total prometido) e retoma
  // sozinho se a busca ainda não cobriu tudo — igual o job de editais.
  useEffect(() => {
    if (!authStatus.authenticated || activeView !== 'Licitações' || licitacaoSubview !== 'resultados') return;
    // Já tem estado vivo nesta sessão (ex.: usuário só trocou de sub-aba).
    if (pncpOutcomeLoading || (pncpOutcomeResults.items?.length && !pncpOutcomeResults.requires_query)) {
      // Se ficou pausado/incompleto e não está rodando, retoma.
      if (
        !pncpOutcomeLoading
        && pncpOutcomeResults.items?.length
        && !pncpOutcomeResults.complete
        && pncpOutcomeResults.status !== 'done'
      ) {
        runPncpOutcomeSearch({}, { resume: true });
      }
      return;
    }
    const checkpoint = readPncpOutcomeCheckpoint();
    if (checkpoint?.items?.length || (checkpoint && checkpoint.complete === false && checkpoint.filters)) {
      if (checkpoint.filters) {
        setPncpOutcomeFilters(prev => ({ ...prev, ...checkpoint.filters }));
        pncpOutcomeFiltersRef.current = { ...pncpOutcomeFiltersRef.current, ...checkpoint.filters };
        pncpOutcomeActiveQueryRef.current = checkpoint.filters;
      }
      const items = Array.isArray(checkpoint.items) ? checkpoint.items : [];
      setPncpOutcomeResults({
        items,
        total: Math.max(Number(checkpoint.reportedTotal) || 0, items.length),
        pagina: 1,
        totalPaginas: Math.max(1, Math.ceil(items.length / 20)),
        tamanhoPagina: 20,
        summary: items.length ? summarizePncpOutcomeItems(items) : null,
        requires_query: false,
        complete: Boolean(checkpoint.complete),
        status: checkpoint.status || (checkpoint.complete ? 'done' : 'paused_rate_limit'),
      });
      if (!checkpoint.complete) {
        setPncpOutcomePhase({
          stage: 'paused_rate_limit',
          label: 'Retomando busca salva…',
          loaded: items.length,
          total: Number(checkpoint.reportedTotal) || undefined,
        });
        runPncpOutcomeSearch({}, { resume: true });
      } else {
        setPncpOutcomePhase({
          stage: 'done',
          label: `Busca concluída · ${items.length.toLocaleString('pt-BR')} item(ns)`,
        });
      }
      return;
    }
    setPncpOutcomeResults(prev => {
      if (prev.items?.length || prev.requires_query === false || pncpOutcomeActiveQueryRef.current) return prev;
      return {
        items: [],
        total: 0,
        pagina: 1,
        totalPaginas: 1,
        tamanhoPagina: 20,
        summary: null,
        requires_query: true,
        complete: false,
        status: null,
      };
    });
  }, [authStatus.authenticated, activeView, licitacaoSubview]);

  useEffect(() => {
    if (!authStatus.authenticated || activeView !== 'Licitações') return;
    loadPncpSearchJobs();
  }, [authStatus.authenticated, activeView]);

  useEffect(() => {
    try {
      if (activePncpSearchJobId) {
        localStorage.setItem('pncp_active_search_job_id', activePncpSearchJobId);
      } else {
        localStorage.removeItem('pncp_active_search_job_id');
      }
    } catch {}
  }, [activePncpSearchJobId]);

  // Atualiza cards enquanto houver jobs vivos (mesmo com o popup fechado).
  useEffect(() => {
    if (!authStatus.authenticated || activeView !== 'Licitações' || licitacaoSubview !== 'editais') return;
    const hasLive = pncpSearchJobs.some(job => isPncpJobLive(job.status));
    if (!hasLive) return undefined;
    const timer = setInterval(() => {
      loadPncpSearchJobs();
    }, 4000);
    return () => clearInterval(timer);
  }, [authStatus.authenticated, activeView, licitacaoSubview, pncpSearchJobs.map(j => `${j.id}:${j.status}`).join('|')]);

  useEffect(() => {
    const q = String(pncpSearchFilters.q || '').trim();
    if (!authStatus.authenticated || q.length < 3 || !pncpSearchFilters.usar_ia) {
      setPncpSuggestedTerms({ positivos: [], negativos: [], fonte: null });
      return;
    }
    let cancelled = false;
    const timer = setTimeout(async () => {
      setPncpSuggestionLoading(true);
      try {
        const response = await axios.get('/api/licitacoes/termos-correlatos', { params: { q } });
        if (!cancelled) {
          setPncpSuggestedTerms({
            positivos: Array.isArray(response.data?.positivos) ? response.data.positivos.slice(0, 8) : [],
            negativos: Array.isArray(response.data?.negativos) ? response.data.negativos.slice(0, 8) : [],
            fonte: response.data?.fonte || null,
          });
        }
      } catch (error) {
        if (!cancelled) setPncpSuggestedTerms({ positivos: [], negativos: [], fonte: null });
      } finally {
        if (!cancelled) setPncpSuggestionLoading(false);
      }
    }, 650);
    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
  }, [authStatus.authenticated, pncpSearchFilters.q, pncpSearchFilters.usar_ia]);

  useEffect(() => {
    if (!pncpJobModalOpen) return undefined;
    const onKey = (event) => {
      if (event.key === 'Escape') closePncpSearchJobModal();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [pncpJobModalOpen]);

  useEffect(() => {
    if (!pncpDeleteJobConfirm) return undefined;
    const onKey = (event) => {
      if (event.key === 'Escape' && !pncpDeleteJobBusy) closeDeletePncpSearchJobConfirm();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [pncpDeleteJobConfirm, pncpDeleteJobBusy]);

  // Poll detalhado só com o popup aberto — resultados e progresso ao vivo.
  // Não mexe em pncpSearchLoading: esse flag é só do POST "Iniciar busca".
  // Scope/página vêm de refs (aba Descartados não pode ser sobrescrita por poll em "list").
  useEffect(() => {
    if (!activePncpSearchJobId || !pncpJobModalOpen) return undefined;
    let stopped = false;
    const tick = async () => {
      try {
        const response = await axios.get(`/api/licitacoes/pncp/search/deep/${activePncpSearchJobId}`);
        if (stopped) return;
        applyPncpJobSnapshot(response.data);
        // Live feed: reusa página / tamanho / classificação atuais — não reseta a vista.
        await loadPncpJobResults(activePncpSearchJobId, pncpJobResultsPageRef.current || 1, {
          fromPoll: true,
          scope: getDesiredPncpResultScope(),
        });
        if (stopped) return;
        const polledRuns = response.data?.term_runs
          || response.data?.query_plan?.term_runs
          || null;
        setPncpSearchJobs(prev => prev.map(jobRow => {
          if (String(jobRow.id) !== String(activePncpSearchJobId)) return jobRow;
          const nextRuns = Array.isArray(polledRuns) && polledRuns.length
            ? polledRuns
            : (jobRow.term_runs || []);
          return {
            ...jobRow,
            status: response.data?.status || jobRow.status,
            progress: response.data?.progress || jobRow.progress,
            total: Number(response.data?.total ?? jobRow.total ?? 0),
            terms: response.data?.terms || jobRow.terms,
            negative_terms: response.data?.negative_terms || jobRow.negative_terms,
            filters: response.data?.filters || jobRow.filters,
            summary: response.data?.summary || jobRow.summary,
            error: response.data?.error || null,
            watchlist_id: response.data?.watchlist_id ?? jobRow.watchlist_id,
            started_at: response.data?.started_at || jobRow.started_at,
            updated_at: response.data?.updated_at || jobRow.updated_at,
            completed_at: response.data?.completed_at || jobRow.completed_at,
            archive_at: response.data?.archive_at ?? jobRow.archive_at,
            days_until_archive: response.data?.days_until_archive ?? jobRow.days_until_archive,
            archive_days: response.data?.archive_days || jobRow.archive_days || 15,
            term_runs: nextRuns,
            query_plan: {
              ...(jobRow.query_plan || {}),
              ...(response.data?.query_plan || {}),
              term_runs: nextRuns,
              list_by_term: response.data?.list_by_term || response.data?.query_plan?.list_by_term || jobRow.query_plan?.list_by_term,
              list_total: response.data?.list_total ?? response.data?.query_plan?.list_total ?? jobRow.query_plan?.list_total,
            },
            list_by_term: response.data?.list_by_term || response.data?.query_plan?.list_by_term || jobRow.list_by_term,
            list_total: response.data?.list_total ?? response.data?.total ?? jobRow.list_total,
          };
        }));
        const status = response.data?.status;
        if (['completed', 'failed', 'cancelled'].includes(status)) {
          loadPncpSearchJobs();
          return;
        }
        setTimeout(tick, status === 'paused_rate_limit' ? 15000 : 1800);
      } catch (error) {
        // Erro de poll não deve travar o formulário de nova busca.
        if (!stopped) {
          console.warn('PNCP job poll failed:', error?.message || error);
        }
      }
    };
    tick();
    return () => {
      stopped = true;
    };
  }, [activePncpSearchJobId, pncpJobModalOpen]);

  const savePncpWatchlist = () => {
    const term = String(pncpSearchFilters.q || '').trim();
    if (!term) {
      alert('Informe um termo de busca antes de salvar a watchlist.');
      return;
    }
    setPncpWatchlistDialog({ source: 'search', defaultName: term, contextLabel: term });
  };

  // Descartar item: some da lista ativa, não conta mais, vai para aba Descartados.
  const hidePncpItem = async (itemOrId) => {
    const item = itemOrId && typeof itemOrId === 'object' ? itemOrId : { id: itemOrId };
    const itemId = item.id;
    if (!itemId || pncpVisibilityBusyId === itemId) return;
    const alreadyLocal = pncpHiddenIds.some(id => String(id) === String(itemId));
    const alreadyDb = item.__visibility_db === 'hidden' || item.__visibility === 'hidden';
    if (!alreadyLocal) {
      const newHidden = [...pncpHiddenIds, itemId];
      setPncpHiddenIds(newHidden);
      localStorage.setItem('pncp_hidden_ids', JSON.stringify(newHidden));
    }
    // Otimista: some da página atual e ajusta contagens (só se ainda estava na lista).
    if (!alreadyDb) {
      setPncpSearchResults(prev => {
        const wasOnPage = (prev.items || []).some(i => String(i.id) === String(itemId));
        const nextItems = (prev.items || []).filter(i => String(i.id) !== String(itemId));
        const prevVis = prev.visibility_counts || {};
        const prevHidden = Number(prevVis.hidden || 0);
        const prevList = Number(prevVis.list ?? prevVis.all ?? prev.total ?? 0);
        const nextHidden = prevHidden + 1;
        const nextList = Math.max(0, prevList - 1);
        return {
          ...prev,
          items: nextItems,
          total: Math.max(0, Number(prev.total || 0) - (wasOnPage && pncpResultScope !== 'hidden' ? 1 : 0)),
          list_total: nextList,
          visibility_counts: {
            ...prevVis,
            hidden: nextHidden,
            list: nextList,
            all: Number(prevVis.all || 0) || (nextList + nextHidden),
          },
        };
      });
      if (activePncpSearchJobId) {
        setPncpSearchJobs(prev => prev.map(job => (
          String(job.id) === String(activePncpSearchJobId)
            ? {
                ...job,
                total: Math.max(0, Number(job.total || 0) - 1),
                summary: job.summary
                  ? { ...job.summary, count: Math.max(0, Number(job.summary.count || job.total || 0) - 1) }
                  : job.summary,
              }
            : job
        )));
      }
    }
    if (activePncpSearchJobId) {
      setPncpVisibilityBusyId(itemId);
      try {
        const response = await axios.patch(
          `/api/licitacoes/pncp/search/deep/${activePncpSearchJobId}/results/visibility`,
          { item, item_id: itemId, result_key: item.__result_key || undefined, visibility: 'hidden' }
        );
        const visCounts = response.data?.visibility_counts;
        if (visCounts) {
          setPncpSearchResults(prev => ({
            ...prev,
            visibility_counts: visCounts,
            list_total: Number(visCounts.list ?? prev.list_total ?? 0),
            total: pncpResultScope === 'hidden'
              ? Number(visCounts.hidden ?? prev.total ?? 0)
              : Number(visCounts.list ?? prev.total ?? 0),
            summary: response.data?.summary || prev.summary,
          }));
          setPncpSearchJobs(prev => prev.map(job => (
            String(job.id) === String(activePncpSearchJobId)
              ? {
                  ...job,
                  total: Number(visCounts.list ?? job.total ?? 0),
                  summary: response.data?.summary
                    ? { ...(job.summary || {}), ...response.data.summary }
                    : job.summary,
                }
              : job
          )));
        }
      } catch (error) {
        console.warn('Falha ao persistir descarte PNCP:', error?.message || error);
      } finally {
        setPncpVisibilityBusyId(null);
      }
    }
  };

  // Restaurar item descartado → volta para a lista ativa
  const restorePncpItem = async (itemOrId) => {
    const item = itemOrId && typeof itemOrId === 'object' ? itemOrId : { id: itemOrId };
    const itemId = item.id;
    if (!itemId) return;
    const newHidden = pncpHiddenIds.filter(id => String(id) !== String(itemId));
    setPncpHiddenIds(newHidden);
    localStorage.setItem('pncp_hidden_ids', JSON.stringify(newHidden));
    // Otimista na aba Descartados: some dali.
    if (pncpResultScope === 'hidden' || pncpJobModalTab === 'descartados') {
      setPncpSearchResults(prev => {
        const nextItems = (prev.items || []).filter(i => String(i.id) !== String(itemId));
        const prevVis = prev.visibility_counts || {};
        const nextHidden = Math.max(0, Number(prevVis.hidden || 0) - 1);
        const nextList = Number(prevVis.list ?? prevVis.all ?? 0) + 1;
        return {
          ...prev,
          items: nextItems,
          total: Math.max(0, Number(prev.total || 0) - 1),
          list_total: nextList,
          visibility_counts: {
            ...prevVis,
            hidden: nextHidden,
            list: nextList,
            all: Number(prevVis.all || 0) || (nextList + nextHidden),
          },
        };
      });
    }
    if (activePncpSearchJobId) {
      setPncpVisibilityBusyId(itemId);
      try {
        const response = await axios.patch(
          `/api/licitacoes/pncp/search/deep/${activePncpSearchJobId}/results/visibility`,
          { item, item_id: itemId, result_key: item.__result_key || undefined, visibility: 'visible' }
        );
        const visCounts = response.data?.visibility_counts;
        if (visCounts) {
          setPncpSearchResults(prev => ({
            ...prev,
            visibility_counts: visCounts,
            list_total: Number(visCounts.list ?? prev.list_total ?? 0),
            total: (pncpResultScope === 'hidden' || pncpJobModalTab === 'descartados')
              ? Number(visCounts.hidden ?? prev.total ?? 0)
              : Number(visCounts.list ?? prev.total ?? 0),
            summary: response.data?.summary || prev.summary,
          }));
          setPncpSearchJobs(prev => prev.map(job => (
            String(job.id) === String(activePncpSearchJobId)
              ? {
                  ...job,
                  total: Number(visCounts.list ?? job.total ?? 0),
                  summary: response.data?.summary
                    ? { ...(job.summary || {}), ...response.data.summary }
                    : job.summary,
                }
              : job
          )));
        }
      } catch (error) {
        console.warn('Falha ao restaurar descarte PNCP:', error?.message || error);
      } finally {
        setPncpVisibilityBusyId(null);
      }
    }
  };

  // Restaurar todos os descartados do job
  const restoreAllPncpItems = async () => {
    setPncpHiddenIds([]);
    localStorage.removeItem('pncp_hidden_ids');
    if (!activePncpSearchJobId) return;
    setPncpVisibilityBusyId('__all__');
    try {
      const response = await axios.post(
        `/api/licitacoes/pncp/search/deep/${activePncpSearchJobId}/results/restore-discarded`
      );
      const visCounts = response.data?.visibility_counts;
      if (visCounts) {
        setPncpSearchResults(prev => ({
          ...prev,
          visibility_counts: visCounts,
          list_total: Number(visCounts.list ?? prev.list_total ?? 0),
          items: (pncpResultScope === 'hidden' || pncpJobModalTab === 'descartados') ? [] : prev.items,
          total: (pncpResultScope === 'hidden' || pncpJobModalTab === 'descartados')
            ? 0
            : Number(visCounts.list ?? prev.total ?? 0),
          summary: response.data?.summary || prev.summary,
        }));
        setPncpSearchJobs(prev => prev.map(job => (
          String(job.id) === String(activePncpSearchJobId)
            ? {
                ...job,
                total: Number(visCounts.list ?? job.total ?? 0),
                summary: response.data?.summary
                  ? { ...(job.summary || {}), ...response.data.summary }
                  : job.summary,
              }
            : job
        )));
      }
      // Recarrega a aba atual para refletir o servidor.
      if (pncpJobModalTab === 'descartados' || pncpResultScope === 'hidden') {
        await loadPncpJobResults(activePncpSearchJobId, 1, { scope: 'hidden' });
      } else {
        await loadPncpJobResults(activePncpSearchJobId, pncpJobResultsPage || 1, { scope: 'list' });
      }
    } catch (error) {
      console.warn('Falha ao restaurar todos os descartados:', error?.message || error);
    } finally {
      setPncpVisibilityBusyId(null);
    }
  };

  const mapPncpImportItemsToDraft = (items = []) => {
    return (Array.isArray(items) ? items : [])
      .map(entry => {
        const descricao = String(
          entry?.descricao
          || entry?.descricaoItem
          || entry?.objetoCompra
          || entry?.nomeItem
          || ''
        ).trim();
        return { ...entry, __descricao_resolvida: descricao };
      })
      .filter(entry => String(entry.__descricao_resolvida || '').trim())
      .map((entry, index) => ({
        id: `pncp-item-${Date.now()}-${index}-${Math.random().toString(16).slice(2, 6)}`,
        numero_item: String(entry?.numero_item || entry?.numeroItem || '').trim() || null,
        descricao: String(entry.__descricao_resolvida || '').trim(),
        modelo_produto: null,
        quantidade: Number.isFinite(Number(entry?.quantidade)) ? Number(entry.quantidade) : null,
        unidade: String(entry?.unidade || entry?.unidadeMedida || '').trim() || null,
        valor_referencia: Number.isFinite(Number(entry?.valor_referencia ?? entry?.valor_unitario_estimado ?? entry?.valorUnitarioEstimado))
          ? Number(entry.valor_referencia ?? entry.valor_unitario_estimado ?? entry.valorUnitarioEstimado)
          : null,
        custo_total_item: Number.isFinite(Number(entry?.custo_total_item ?? entry?.valor_total ?? entry?.valorTotal))
          ? Number(entry.custo_total_item ?? entry.valor_total ?? entry.valorTotal)
          : null,
        requirements: [],
      }));
  };

  const fetchAllPncpItemsForImport = async (item) => {
    const cnpj = String(item?.orgao?.cnpj || '').replace(/\D/g, '');
    const ano = String(item?.ano || '').trim();
    const sequencial = String(item?.numero_sequencial || '').trim();
    if (!cnpj || !ano || !sequencial) {
      return [];
    }

    const pageSize = 100;
    const maxPages = 20;
    const allItems = [];

    for (let page = 1; page <= maxPages; page += 1) {
      const response = await axios.get(`/api/licitacoes/pncp/compra/${cnpj}/${ano}/${sequencial}/itens`, {
        params: {
          pagina: page,
          tamanhoPagina: pageSize,
        },
      });
      const pageItems = Array.isArray(response.data?.data)
        ? response.data.data
        : Array.isArray(response.data)
          ? response.data
          : [];

      if (pageItems.length === 0) {
        break;
      }
      allItems.push(...pageItems);
      if (pageItems.length < pageSize) {
        break;
      }
    }

    return allItems;
  };

  // Importar licitação do PNCP para criar uma oportunidade
  const importPncpLicitacao = async (item) => {
    setPncpImportingId(item.id);
    try {
      const pickPncpDate = (source, keys = []) => {
        for (const key of keys) {
          const value = source?.[key];
          if (value) return value;
        }
        return null;
      };

      const propostaInicio = pickPncpDate(item, [
        'data_inicio_proposta',
        'dataInicioProposta',
        'data_inicio_recebimento_proposta',
        'dataInicioRecebimentoProposta',
        'data_abertura_proposta',
        'dataAberturaProposta',
        'data_sessao',
      ]) || item.data_publicacao;

      const propostaFim = pickPncpDate(item, [
        'data_fim_proposta',
        'dataFimProposta',
        'data_envio_proposta_limite',
        'dataEnvioPropostaLimite',
        'data_fim_recebimento_proposta',
        'dataFimRecebimentoProposta',
        'data_encerramento_proposta',
        'dataEncerramentoProposta',
      ]) || item.data_fim_vigencia;
      // Mapear situação PNCP para status da oportunidade
      const pncpSituacaoNome = (item.situacao?.nome || '').toLowerCase();
      const statusFromPncp = pncpSituacaoNome.includes('suspens') ? 'suspenso'
        : (pncpSituacaoNome.includes('revogad') || pncpSituacaoNome.includes('anuladoo') || pncpSituacaoNome.includes('cancel')) ? 'cancelado'
        : 'ativo';
      const queryText = normalizeText(pncpSearchFilters.q || '').trim();
      const shouldImportAllItems = queryText.length < 3;

      let importedItemsDraft = [];
      if (!shouldImportAllItems && Array.isArray(item.itens_pertinentes) && item.itens_pertinentes.length > 0) {
        importedItemsDraft = mapPncpImportItemsToDraft(item.itens_pertinentes);
      } else {
        const allPncpItems = await fetchAllPncpItemsForImport(item);
        importedItemsDraft = mapPncpImportItemsToDraft(allPncpItems);
      }
      const estimatedValue = Number(item.valor_itens_pertinentes) > 0
        ? Number(item.valor_itens_pertinentes)
        : (item.valor_total_estimado ?? item.valor_global ?? '');

      setNewOpportunityForm(prev => ({
        ...prev,
        // Importação PNCP entra em Monitoramento de Edital (não PCA).
        fase: '6. Monitoramento de Edital',
        status: statusFromPncp,
        titulo: item.titulo || `${item.tipo?.nome || 'Edital'} - ${item.orgao?.nome || 'Órgão'}`,
        orgao_nome: item.orgao?.nome || '',
        orgao_cnpj: item.orgao?.cnpj || '',
        orgao_codigo: item.orgao?.id || item.orgao?.cnpj || '',
        uasg_codigo: item.unidade?.codigo || '',
        uasg_nome: item.unidade?.nome || '',
        modalidade: item.modalidade?.nome || '',
        numero_edital: item.numero_sequencial || '',
        numero_compra: item.numero_controle_pncp || '',
        data_publicacao: toDateInputValue(item.data_publicacao),
        data_sessao: toDateTimeLocalValue(propostaInicio),
        data_envio_proposta_limite: toDateTimeLocalValue(propostaFim),
        data_assinatura_ata_limite: toDateTimeLocalValue(item.data_assinatura_ata_limite),
        data_entrega_limite: toDateTimeLocalValue(item.data_entrega_limite || item.data_fim_vigencia),
        valor_oportunidade: toPtBrDecimalInput(estimatedValue),
        links_pncp: item.url || '',
        metadados: {
          pncp_id: item.id,
          pncp_numero_controle: item.numero_controle_pncp,
          pncp_situacao: item.situacao?.nome,
          pncp_tipo: item.tipo?.nome,
          pncp_esfera: item.esfera?.nome,
          pncp_municipio: item.municipio?.nome,
          pncp_uf: item.uf,
          pncp_score: item.score,
          pncp_score_label: item.score_label,
          pncp_fase_lei_14133: item.legal_stage?.label,
          pncp_criterio_julgamento: item.criterio_julgamento,
          pncp_match_reasons: item.match_reasons || [],
        },
      }));
      setNewOpportunityItemsDraft(importedItemsDraft);
      setNewOpportunityItemRequirementForm({});
      setExpandedDraftChecklist({});
      setChecklistModalItemId(null);
      setIsPncpImportDraft(true);
      setNewOpportunityFormSubview('editais');
      setLicitacaoSubview('editais');
      setShowNewOpportunityForm(true);
      setPncpSearchExpanded(false);
    } catch (error) {
      console.error('Error importing PNCP items:', error);
    } finally {
      setPncpImportingId(null);
    }
  };

  const openOpportunity = async (opportunity) => {
    setSelectedOpportunity(opportunity);
    try {
      const [requirementsResponse, contactsResponse, itemsResponse, commentsResponse] = await Promise.all([
        axios.get(`/api/licitacoes/opportunities/${opportunity.id}/requirements`),
        axios.get(`/api/licitacoes/opportunities/${opportunity.id}/contacts`),
        axios.get(`/api/licitacoes/opportunities/${opportunity.id}/items`),
        axios.get(`/api/licitacoes/opportunities/${opportunity.id}/comments`),
      ]);
      const requirements = Array.isArray(requirementsResponse.data) ? requirementsResponse.data : [];
      setSelectedCommercialRequirements(requirements.filter(item => item.tipo === 'comercial'));
      setSelectedLinkedContacts(contactsResponse.data || []);
      setSelectedComments(Array.isArray(commentsResponse.data) ? commentsResponse.data : []);
      setItemRequirementCostInputMap({});
      setItemQuantityInputMap({});
      setItemReferenceInputMap({});
      setItemChecklistAiMap({});
      setChecklistSectionCollapsed({});

      const items = Array.isArray(itemsResponse.data) ? itemsResponse.data : [];
      setSelectedItems(items);

      const requirementsByItem = {};
      await Promise.all(items.map(async (item) => {
        const itemRequirementsResponse = await axios.get(`/api/licitacoes/opportunities/${opportunity.id}/items/${item.id}/requirements`);
        requirementsByItem[item.id] = Array.isArray(itemRequirementsResponse.data) ? itemRequirementsResponse.data : [];
      }));
      setItemRequirementsMap(requirementsByItem);
    } catch (error) {
      console.error('Error loading licitação details:', error);
      setSelectedCommercialRequirements([]);
      setSelectedItems([]);
      setItemRequirementsMap({});
      setSelectedLinkedContacts([]);
      setSelectedComments([]);
      setItemRequirementCostInputMap({});
      setItemQuantityInputMap({});
      setItemReferenceInputMap({});
      setItemChecklistAiMap({});
    }
  };

  const addComment = async () => {
    if (!selectedOpportunity || !newCommentText.trim()) {
      return;
    }
    try {
      const response = await axios.post(`/api/licitacoes/opportunities/${selectedOpportunity.id}/comments`, {
        content: newCommentText.trim(),
        author: 'Admin',
      });
      setSelectedComments(prev => [response.data, ...prev]);
      setNewCommentText('');
    } catch (error) {
      console.error('Error adding comment:', error);
    }
  };

  const deleteComment = async (commentId) => {
    if (!selectedOpportunity) {
      return;
    }
    try {
      await axios.delete(`/api/licitacoes/opportunities/${selectedOpportunity.id}/comments/${commentId}`);
      setSelectedComments(prev => prev.filter(comment => comment.id !== commentId));
    } catch (error) {
      console.error('Error deleting comment:', error);
    }
  };

  const selectedOpportunityIdRef = useRef(null);
  selectedOpportunityIdRef.current = selectedOpportunity?.id ?? null;

  const updateSelectedOpportunity = useCallback(async (changes) => {
    const id = selectedOpportunityIdRef.current;
    if (id == null) return;
    setSelectedOpportunity((prev) => (prev && prev.id === id ? { ...prev, ...changes } : prev));
    setLicitacaoOpportunities(prev => prev.map(item => (item.id === id ? { ...item, ...changes } : item)));
    try {
      const response = await axios.put(`/api/licitacoes/opportunities/${id}`, changes);
      setSelectedOpportunity(prev => (prev && prev.id === id ? response.data : prev));
      setLicitacaoOpportunities(prev => prev.map(item => (item.id === id ? response.data : item)));
    } catch (error) {
      console.error('Error updating licitação opportunity:', error);
    }
  }, []);

  useEffect(() => {
    if (!selectedOpportunity || !hasItemsDrivingOpportunityValue) {
      return;
    }
    const currentValue = parseCurrency(selectedOpportunity.valor_oportunidade);
    const nextValue = Number(itemsParticipationTotal.toFixed(2));
    setSelectedOpportunityValueInput(toPtBrDecimalInput(nextValue));
    if (currentValue === nextValue) {
      return;
    }
    updateSelectedOpportunity({ valor_oportunidade: nextValue });
  }, [
    selectedOpportunity?.id,
    selectedOpportunity?.valor_oportunidade,
    hasItemsDrivingOpportunityValue,
    itemsParticipationTotal,
    updateSelectedOpportunity,
  ]);

  const deleteSelectedOpportunity = async () => {
    if (!selectedOpportunity) {
      return;
    }

    const confirmed = window.confirm('Tem certeza que deseja excluir esta licitação? Esta ação não pode ser desfeita.');
    if (!confirmed) {
      return;
    }

    const opportunityId = selectedOpportunity.id;
    try {
      await axios.delete(`/api/licitacoes/opportunities/${opportunityId}`);
      setLicitacaoOpportunities(prev => prev.filter(item => String(item.id) !== String(opportunityId)));
      setSelectedOpportunity(null);
      setSelectedCommercialRequirements([]);
      setSelectedItems([]);
      setItemRequirementsMap({});
      setItemChecklistAiMap({});
      setSelectedLinkedContacts([]);
      setSelectedComments([]);
      setContactLinkQuery('');
    } catch (error) {
      console.error('Error deleting licitação opportunity:', error);
    }
  };

  const commitSelectedOpportunityValue = () => {
    if (!selectedOpportunity) {
      return;
    }
    if (hasItemsDrivingOpportunityValue) {
      return;
    }
    const nextValue = parseCurrency(selectedOpportunityValueInput);
    const currentValue = parseCurrency(selectedOpportunity.valor_oportunidade);
    if (nextValue === currentValue) {
      return;
    }
    updateSelectedOpportunity({ valor_oportunidade: nextValue });
  };

  const addRequirement = async () => {
    if (!selectedOpportunity || !newRequirementForm.titulo.trim()) {
      return;
    }
    try {
      const response = await axios.post(`/api/licitacoes/opportunities/${selectedOpportunity.id}/requirements`, {
        tipo: 'comercial',
        titulo: newRequirementForm.titulo,
      });
      setSelectedCommercialRequirements(prev => [...prev, response.data]);
      setNewRequirementForm({ titulo: '' });
    } catch (error) {
      console.error('Error adding requirement:', error);
    }
  };

  const updateRequirement = async (requirementId, changes) => {
    if (!selectedOpportunity) {
      return;
    }
    try {
      const response = await axios.put(
        `/api/licitacoes/opportunities/${selectedOpportunity.id}/requirements/${requirementId}`,
        changes
      );
      setSelectedCommercialRequirements(prev => prev.map(item => (item.id === requirementId ? response.data : item)));
    } catch (error) {
      console.error('Error updating requirement:', error);
    }
  };

  const deleteRequirement = async (requirementId) => {
    if (!selectedOpportunity) {
      return;
    }
    try {
      await axios.delete(`/api/licitacoes/opportunities/${selectedOpportunity.id}/requirements/${requirementId}`);
      setSelectedCommercialRequirements(prev => prev.filter(item => item.id !== requirementId));
    } catch (error) {
      console.error('Error deleting requirement:', error);
    }
  };

  const addItem = async () => {
    if (!selectedOpportunity || !newItemForm.descricao.trim()) {
      return;
    }
    try {
      const quantidade = parseCurrency(newItemForm.quantidade);
      const valorReferencia = parseCurrency(newItemForm.valor_referencia);
      const custoTotalItem = quantidade !== null && valorReferencia !== null
        ? Number((quantidade * valorReferencia).toFixed(2))
        : null;
      const response = await axios.post(`/api/licitacoes/opportunities/${selectedOpportunity.id}/items`, {
        ...newItemForm,
        quantidade,
        valor_referencia: valorReferencia,
        custo_total_item: custoTotalItem,
      });
      setSelectedItems(prev => [...prev, response.data]);
      setNewItemForm({ numero_item: '', descricao: '', modelo_produto: '', quantidade: '', unidade: '', valor_referencia: '', custo_total_item: '' });
    } catch (error) {
      console.error('Error adding item:', error);
    }
  };

  const itemWriteSeqRef = useRef({});
  const itemWriteDebounceRef = useRef({});
  const selectedItemsRef = useRef([]);
  selectedItemsRef.current = selectedItems;

  const updateItem = (itemId, changes, options = {}) => {
    if (!selectedOpportunity) {
      return;
    }
    const keys = Object.keys(changes || {});
    if (!keys.length) return;

    // Otimista: UI responde na hora
    setSelectedItems((prev) => prev.map((item) => (item.id === itemId ? { ...item, ...changes } : item)));

    const textOnly = keys.every((k) => k === 'descricao' || k === 'modelo_produto' || k === 'numero_item' || k === 'unidade');
    const immediate = options.immediate === true || !textOnly;
    const writeKey = String(itemId);

    const persist = async () => {
      const seq = (itemWriteSeqRef.current[writeKey] || 0) + 1;
      itemWriteSeqRef.current[writeKey] = seq;
      const latest = selectedItemsRef.current.find((it) => it.id === itemId);
      const payload = latest
        ? {
            descricao: latest.descricao,
            modelo_produto: latest.modelo_produto,
            numero_item: latest.numero_item,
            quantidade: latest.quantidade,
            unidade: latest.unidade,
            valor_referencia: latest.valor_referencia,
            valor_proposta: latest.valor_proposta,
            custo_total_item: latest.custo_total_item,
            prazo_entrega_dias: latest.prazo_entrega_dias,
            status_participacao: latest.status_participacao,
            ...changes,
          }
        : changes;
      try {
        const response = await axios.put(
          `/api/licitacoes/opportunities/${selectedOpportunity.id}/items/${itemId}`,
          payload
        );
        if (itemWriteSeqRef.current[writeKey] !== seq) return;
        setSelectedItems((prev) => prev.map((item) => {
          if (item.id !== itemId) return item;
          const local = selectedItemsRef.current.find((it) => it.id === itemId);
          if (!local) return response.data;
          // Não deixa resposta atrasada apagar o que o usuário já digitou
          return {
            ...response.data,
            descricao: local.descricao,
            modelo_produto: local.modelo_produto,
            numero_item: local.numero_item,
            unidade: local.unidade,
            quantidade: local.quantidade,
            valor_referencia: local.valor_referencia,
          };
        }));
      } catch (error) {
        if (itemWriteSeqRef.current[writeKey] === seq) {
          console.error('Error updating item:', error);
        }
      }
    };

    if (itemWriteDebounceRef.current[writeKey]) {
      clearTimeout(itemWriteDebounceRef.current[writeKey]);
      itemWriteDebounceRef.current[writeKey] = null;
    }
    if (immediate) {
      void persist();
      return;
    }
    itemWriteDebounceRef.current[writeKey] = setTimeout(() => {
      itemWriteDebounceRef.current[writeKey] = null;
      void persist();
    }, 400);
  };

  const setItemNumericInput = (type, itemId, value) => {
    const normalized = String(value || '').replace(/\./g, ',');
    if (type === 'quantidade') {
      setItemQuantityInputMap(prev => ({ ...prev, [itemId]: normalized }));
      return;
    }
    setItemReferenceInputMap(prev => ({ ...prev, [itemId]: normalized }));
  };

  const commitItemNumericInput = (type, item) => {
    if (!item || !item.id) {
      return;
    }
    const itemId = item.id;
    const quantityInput = itemQuantityInputMap[itemId];
    const referenceInput = itemReferenceInputMap[itemId];

    if (type === 'quantidade' && quantityInput === undefined) {
      return;
    }
    if (type === 'valor_referencia' && referenceInput === undefined) {
      return;
    }

    const nextQuantidade = parseCurrency(type === 'quantidade' ? quantityInput : (quantityInput ?? item.quantidade));
    const nextReferencia = parseCurrency(type === 'valor_referencia' ? referenceInput : (referenceInput ?? item.valor_referencia));
    const currentQuantidade = parseCurrency(item.quantidade);
    const currentReferencia = parseCurrency(item.valor_referencia);

    const nextCustoTotal = nextQuantidade !== null && nextReferencia !== null
      ? Number((nextQuantidade * nextReferencia).toFixed(2))
      : null;

    const shouldUpdate = nextQuantidade !== currentQuantidade || nextReferencia !== currentReferencia;
    if (shouldUpdate) {
      updateItem(itemId, {
        quantidade: nextQuantidade,
        valor_referencia: nextReferencia,
        custo_total_item: nextCustoTotal,
      });
    }

    if (type === 'quantidade') {
      setItemQuantityInputMap(prev => {
        const next = { ...prev };
        delete next[itemId];
        return next;
      });
      return;
    }

    setItemReferenceInputMap(prev => {
      const next = { ...prev };
      delete next[itemId];
      return next;
    });
  };

  const deleteItem = async (itemId) => {
    if (!selectedOpportunity) {
      return;
    }
    try {
      await axios.delete(`/api/licitacoes/opportunities/${selectedOpportunity.id}/items/${itemId}`);
      setSelectedItems(prev => prev.filter(item => item.id !== itemId));
      setItemRequirementsMap(prev => {
        const next = { ...prev };
        delete next[itemId];
        return next;
      });
      setItemQuantityInputMap(prev => {
        const next = { ...prev };
        delete next[itemId];
        return next;
      });
      setItemReferenceInputMap(prev => {
        const next = { ...prev };
        delete next[itemId];
        return next;
      });
    } catch (error) {
      console.error('Error deleting item:', error);
    }
  };

  const addItemRequirement = async (itemId) => {
    if (!selectedOpportunity) {
      return;
    }
    const form = newItemRequirementForm[itemId] || { requisito: '' };
    if (!String(form.requisito || '').trim()) {
      return;
    }
    try {
      const response = await axios.post(`/api/licitacoes/opportunities/${selectedOpportunity.id}/items/${itemId}/requirements`, {
        requisito: form.requisito,
        secao: form.secao || null,
        status: form.status || 'verificar',
        observacao: form.observacao || null,
        valor_ofertado: form.custo_subitem ? parseCurrency(form.custo_subitem) : null,
        ordem: (itemRequirementsMap[itemId] || []).length,
      });
      setItemRequirementsMap(prev => ({
        ...prev,
        [itemId]: [...(prev[itemId] || []), response.data],
      }));
      setNewItemRequirementForm(prev => ({
        ...prev,
        [itemId]: {
          requisito: '',
          secao: form.secao || '',
          status: 'verificar',
          observacao: '',
          custo_subitem: '',
        },
      }));
    } catch (error) {
      console.error('Error adding item requirement:', error);
    }
  };

  // Mantém ref espelhando o map para flush debounced com o valor mais recente
  itemRequirementsMapRef.current = itemRequirementsMap;

  /**
   * Atualiza requisito do checklist.
   * - Sempre otimista no estado local (digitação fluida).
   * - Texto (requisito/observacao): debounced PUT; respostas antigas são ignoradas.
   * - Status/custo/seção: PUT imediato.
   * Isso evita o bug clássico de “comer letras” por race no axios.
   */
  const updateItemRequirement = (itemId, requirementId, changes, options = {}) => {
    if (!selectedOpportunity) {
      return;
    }
    const keys = Object.keys(changes || {});
    if (!keys.length) return;

    // 1) UI imediata
    setItemRequirementsMap((prev) => ({
      ...prev,
      [itemId]: (prev[itemId] || []).map((row) => (
        row.id === requirementId ? { ...row, ...changes } : row
      )),
    }));

    const writeKey = `${itemId}:${requirementId}`;
    const textOnly = keys.every((k) => k === 'requisito' || k === 'observacao');
    const immediate = options.immediate === true || !textOnly;

    const persist = async () => {
      const seq = (itemReqWriteSeqRef.current[writeKey] || 0) + 1;
      itemReqWriteSeqRef.current[writeKey] = seq;
      // No flush, manda o snapshot local mais recente do requisito (não só o "changes" antigo)
      const latest = (itemRequirementsMapRef.current[itemId] || []).find((r) => r.id === requirementId);
      const payload = latest
        ? {
            requisito: latest.requisito,
            observacao: latest.observacao,
            status: latest.status,
            secao: latest.secao,
            valor_ofertado: latest.valor_ofertado,
            valor_referencia: latest.valor_referencia,
            ordem: latest.ordem,
            ...changes,
          }
        : changes;
      try {
        const response = await axios.put(
          `/api/licitacoes/opportunities/${selectedOpportunity.id}/items/${itemId}/requirements/${requirementId}`,
          payload
        );
        // Resposta velha? descarta (evita sobrescrever o que o usuário já digitou)
        if (itemReqWriteSeqRef.current[writeKey] !== seq) {
          return;
        }
        setItemRequirementsMap((prev) => ({
          ...prev,
          [itemId]: (prev[itemId] || []).map((row) => {
            if (row.id !== requirementId) return row;
            // Preserva campos de texto locais se o usuário digitou depois deste request
            const local = (itemRequirementsMapRef.current[itemId] || []).find((r) => r.id === requirementId);
            if (!local) return response.data;
            return {
              ...response.data,
              requisito: local.requisito,
              observacao: local.observacao,
              status: local.status,
              secao: local.secao ?? response.data.secao,
              valor_ofertado: local.valor_ofertado,
            };
          }),
        }));
      } catch (error) {
        if (itemReqWriteSeqRef.current[writeKey] === seq) {
          console.error('Error updating item requirement:', error);
        }
      }
    };

    if (itemReqDebounceRef.current[writeKey]) {
      clearTimeout(itemReqDebounceRef.current[writeKey]);
      itemReqDebounceRef.current[writeKey] = null;
    }
    if (immediate) {
      void persist();
      return;
    }
    itemReqDebounceRef.current[writeKey] = setTimeout(() => {
      itemReqDebounceRef.current[writeKey] = null;
      void persist();
    }, 400);
  };

  const setItemRequirementCostInput = (itemId, requirementId, value) => {
    const key = `${itemId}:${requirementId}`;
    setItemRequirementCostInputMap(prev => ({
      ...prev,
      [key]: String(value || '').replace(/\./g, ','),
    }));
  };

  const commitItemRequirementCost = (itemId, requirementId, currentValue) => {
    const key = `${itemId}:${requirementId}`;
    const inputValue = itemRequirementCostInputMap[key];
    if (inputValue === undefined) {
      return;
    }
    const nextValue = parseCurrency(inputValue);
    const currentNumeric = parseCurrency(currentValue);
    if (nextValue !== currentNumeric) {
      updateItemRequirement(itemId, requirementId, { valor_ofertado: nextValue });
    }
    setItemRequirementCostInputMap(prev => {
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const deleteItemRequirement = async (itemId, requirementId) => {
    if (!selectedOpportunity) {
      return;
    }
    try {
      await axios.delete(`/api/licitacoes/opportunities/${selectedOpportunity.id}/items/${itemId}/requirements/${requirementId}`);
      setItemRequirementsMap(prev => ({
        ...prev,
        [itemId]: (prev[itemId] || []).filter(item => item.id !== requirementId),
      }));
      setItemRequirementCostInputMap(prev => {
        const next = { ...prev };
        delete next[`${itemId}:${requirementId}`];
        return next;
      });
    } catch (error) {
      console.error('Error deleting item requirement:', error);
    }
  };

  const emptyItemChecklistAiState = () => ({
    open: false,
    messages: [],
    proposal: null,
    loading: false,
    error: null,
    applyMode: 'replace',
    draftText: '',
    applying: false,
    // Fluxo guiado: extract → evaluate → ready (aplicar)
    phase: 'extract',
  });

  const patchItemChecklistAi = (itemId, patch) => {
    setItemChecklistAiMap(prev => {
      const current = prev[itemId] || emptyItemChecklistAiState();
      const next = typeof patch === 'function' ? patch(current) : { ...current, ...patch };
      return { ...prev, [itemId]: next };
    });
  };

  const toggleItemChecklistAi = (itemId) => {
    patchItemChecklistAi(itemId, (current) => ({
      ...current,
      open: !current.open,
    }));
  };

  const sendItemChecklistAi = async (itemId, options = {}) => {
    if (!selectedOpportunity) return;
    const state = itemChecklistAiMap[itemId] || emptyItemChecklistAiState();
    const text = String(state.draftText || '').trim();
    const intent = options.intent
      || (state.phase === 'evaluate' || state.phase === 'ready' ? 'evaluate' : 'extract');

    // Avaliar: modelo do item basta. Extrair/revisar: texto OU checklist/prévia existente (para pedir revisão sem colar de novo)
    const itemRow = (selectedItems || []).find((it) => String(it.id) === String(itemId));
    const modeloItem = String(itemRow?.modelo_produto || '').trim();
    const hasLiveOrProposal = (itemRequirementsMap[itemId] || []).length > 0
      || !!(state.proposal?.requirements?.length);
    if (!text && !(intent === 'evaluate' && modeloItem) && !(intent === 'extract' && hasLiveOrProposal)) return;
    if (state.loading) return;

    const liveForSeed = itemRequirementsMap[itemId] || [];
    const hasExistingChecklist = liveForSeed.length > 0 || !!(state.proposal?.requirements?.length);

    let contentForAi = text;
    let contentForUi = text;
    if (intent === 'extract') {
      contentForAi = [
        hasExistingChecklist
          ? 'INTENÇÃO: REVISAR/EXTRAIR requisitos (passo 1).'
          : 'INTENÇÃO: EXTRAIR requisitos do edital abaixo.',
        'NÃO avalie conformidade com produto agora. status de novos/alterados sem julgamento de modelo = verificar (pode manter status ok/nao_ok já existentes se o texto do requisito não mudou).',
        'Ignore comparação de produto neste passo (isso é o passo 2).',
        hasExistingChecklist
          ? 'Já existe checklist/prévia: pode REVISAR, ADICIONAR, REMOVER, reordenar ou reextrair conforme o pedido/texto do usuário. Mantenha ids dos requisitos que permanecerem. mode_hint replace se reextrair tudo; patch se só ajustar; append se só acrescentar.'
          : 'Gere a lista completa a partir do texto.',
        '',
        text || (hasExistingChecklist
          ? '(sem texto novo — revise a prévia/checklist atual conforme o histórico da conversa)'
          : ''),
      ].filter(Boolean).join('\n');
      contentForUi = text || (hasExistingChecklist ? 'Revisar checklist/prévia atual' : text);
    } else if (intent === 'evaluate') {
      const refParts = [];
      if (modeloItem) refParts.push(`Modelo no campo do item: ${modeloItem}`);
      if (text) refParts.push(text);
      contentForAi = [
        'INTENÇÃO: AVALIAR conformidade da prévia/checklist já extraída.',
        'NÃO reextrair o edital. NÃO inventar requisitos novos (a menos que eu peça explicitamente).',
        'Mantenha seções, textos e ordem; preencha status (ok/nao_ok/verificar) e observacao curta.',
        'Use a referência de produto abaixo (modelo, ficha colada e/ou URL).',
        '',
        refParts.join('\n\n') || '(sem referência — use só o que souber do modelo do item)',
      ].join('\n');
      contentForUi = text
        ? (modeloItem ? `Avaliar com: ${modeloItem}\n${text}` : `Avaliar com:\n${text}`)
        : `Avaliar com modelo do item: ${modeloItem}`;
    }

    const userMessage = { role: 'user', content: contentForUi };
    // Histórico enviado à API usa o prompt com intenção (última msg user enriquecida)
    const historyForApi = [
      ...(state.messages || []).map((m) => ({ role: m.role, content: m.content })),
      { role: 'user', content: contentForAi },
    ];
    const nextMessagesUi = [...(state.messages || []), userMessage];
    patchItemChecklistAi(itemId, {
      messages: nextMessagesUi,
      draftText: '',
      loading: true,
      error: null,
      open: true,
      phase: intent === 'evaluate' ? 'evaluate' : 'extract',
    });

    // Sem prévia: manda o checklist gravado (com ids) — avaliar só status; extrair/revisar pode editar a lista
    let proposalPayload = state.proposal || null;
    if (!proposalPayload && liveForSeed.length) {
      proposalPayload = {
        mode_hint: intent === 'evaluate' ? 'patch' : 'replace',
        modelo_produto: modeloItem || null,
        requirements: liveForSeed.map((r, index) => ({
          id: r.id,
          secao: r.secao || null,
          requisito: r.requisito,
          status: r.status || 'verificar',
          observacao: r.observacao || '',
          ordem: r.ordem != null ? r.ordem : index,
        })),
      };
    }

    try {
      const response = await axios.post(
        `/api/licitacoes/opportunities/${selectedOpportunity.id}/items/${itemId}/requirements/ai/chat`,
        {
          messages: historyForApi,
          proposal: proposalPayload,
          include_current_checklist: true,
          intent,
          modelo_produto_hint: modeloItem || null,
        },
        { timeout: 120000 }
      );
      const data = response.data || {};
      const proposal = data.proposal || null;
      const modeHint = proposal?.mode_hint;
      const hasIds = (proposal?.requirements || []).some((r) => r.id != null);
      const applyMode = intent === 'evaluate' && (hasIds || proposalPayload?.mode_hint === 'patch')
        ? 'patch'
        : (['replace', 'append', 'patch'].includes(modeHint) ? modeHint : (state.applyMode || 'replace'));
      const sourcesNote = Array.isArray(data.sources) && data.sources.length
        ? data.sources
          .map((s) => (s.ok ? `✓ ${s.url} (${s.chars} chars)` : `✗ ${s.url}: ${s.error || 'falha'}`))
          .join('\n')
        : '';
      let assistantContent = data.assistant_message || 'Prévia gerada.';
      if (sourcesNote) {
        assistantContent = `${assistantContent}\n\nFontes:\n${sourcesNote}`;
      }
      const reqCount = Array.isArray(proposal?.requirements) ? proposal.requirements.length : 0;
      // Caminho usual: após extrair lista com sucesso, sugere modo produto (usuário ainda pode aplicar/ficar na lista)
      let nextPhase = intent === 'evaluate' ? 'evaluate' : 'extract';
      if (intent === 'extract' && reqCount > 0) nextPhase = 'evaluate';
      if (intent === 'extract' && reqCount === 0) nextPhase = 'extract';

      patchItemChecklistAi(itemId, {
        messages: [...nextMessagesUi, { role: 'assistant', content: assistantContent }],
        proposal,
        applyMode,
        loading: false,
        error: null,
        phase: nextPhase,
      });
    } catch (error) {
      console.error('Error checklist AI chat:', error);
      const detail = error?.response?.data?.detail || error?.response?.data?.error || error.message;
      patchItemChecklistAi(itemId, {
        messages: nextMessagesUi,
        loading: false,
        error: detail || 'Falha ao consultar a IA',
      });
    }
  };

  const updateItemChecklistAiProposalReq = (itemId, index, changes) => {
    patchItemChecklistAi(itemId, (current) => {
      const proposal = current.proposal;
      if (!proposal || !Array.isArray(proposal.requirements)) return current;
      const requirements = proposal.requirements.map((req, i) => (
        i === index ? { ...req, ...changes } : req
      ));
      return { ...current, proposal: { ...proposal, requirements } };
    });
  };

  const removeItemChecklistAiProposalReq = (itemId, index) => {
    patchItemChecklistAi(itemId, (current) => {
      const proposal = current.proposal;
      if (!proposal || !Array.isArray(proposal.requirements)) return current;
      return {
        ...current,
        proposal: {
          ...proposal,
          requirements: proposal.requirements.filter((_, i) => i !== index),
        },
      };
    });
  };

  const discardItemChecklistAiProposal = (itemId) => {
    patchItemChecklistAi(itemId, { proposal: null, error: null, phase: 'extract' });
  };

  const applyItemChecklistAiProposal = async (itemId) => {
    if (!selectedOpportunity) return;
    const state = itemChecklistAiMap[itemId] || emptyItemChecklistAiState();
    const proposal = state.proposal;
    if (!proposal || !Array.isArray(proposal.requirements) || !proposal.requirements.length) return;
    if (state.applying) return;

    const mode = ['replace', 'append', 'patch'].includes(state.applyMode)
      ? state.applyMode
      : (proposal.mode_hint || 'replace');

    patchItemChecklistAi(itemId, { applying: true, error: null });
    try {
      const payload = {
        mode,
        requirements: proposal.requirements.map((req, index) => ({
          id: req.id || undefined,
          secao: req.secao || null,
          requisito: req.requisito,
          status: req.status || 'verificar',
          observacao: req.observacao || null,
          valor_ofertado: req.valor_ofertado != null ? req.valor_ofertado : null,
          ordem: req.ordem != null ? req.ordem : index,
        })),
      };
      if (proposal.modelo_produto) {
        payload.modelo_produto = proposal.modelo_produto;
      }
      const response = await axios.post(
        `/api/licitacoes/opportunities/${selectedOpportunity.id}/items/${itemId}/requirements/bulk`,
        payload
      );
      const data = response.data || {};
      setItemRequirementsMap(prev => ({
        ...prev,
        [itemId]: Array.isArray(data.requirements) ? data.requirements : [],
      }));
      if (data.item) {
        setSelectedItems(prev => prev.map(item => (item.id === itemId ? { ...item, ...data.item } : item)));
      } else if (proposal.modelo_produto) {
        setSelectedItems(prev => prev.map(item => (
          item.id === itemId ? { ...item, modelo_produto: proposal.modelo_produto } : item
        )));
      }
      const appliedList = Array.isArray(data.requirements) ? data.requirements : payload.requirements;
      const hadEvaluation = appliedList.some((r) => r.status === 'ok' || r.status === 'nao_ok');
      // Não força ordem: permanece no modo atual (lista ou produto)
      const stayPhase = state.phase === 'extract' ? 'extract' : 'evaluate';
      patchItemChecklistAi(itemId, {
        applying: false,
        proposal: null,
        error: null,
        phase: stayPhase,
        applyMode: hadEvaluation ? (state.applyMode || 'replace') : 'patch',
        messages: [
          ...(state.messages || []),
          {
            role: 'assistant',
            content: hadEvaluation
              ? `Aplicado ao checklist (${mode}): ${payload.requirements.length} requisito(s) com avaliação. Pode reavaliar no modo produto ou revisar a lista no modo lista.`
              : `Aplicado ao checklist (${mode}): ${payload.requirements.length} requisito(s). Pode aplicar de novo após revisar a lista, ou usar o modo produto para marcar OK/X/?.`,
          },
        ],
      });
    } catch (error) {
      console.error('Error applying checklist AI proposal:', error);
      const detail = error?.response?.data?.error || error.message;
      patchItemChecklistAi(itemId, {
        applying: false,
        error: detail || 'Falha ao aplicar a prévia',
      });
    }
  };

  const getItemChecklistStatus = (itemId) => {
    const requirements = itemRequirementsMap[itemId] || [];
    const okCount = requirements.filter(item => item.status === 'ok').length;
    const totalCount = requirements.length;
    if (requirements.length === 0) {
      return { label: 'Sem checklist', counts: '0/0', className: 'bg-cardAlt text-muted border-border' };
    }
    const pending = requirements.some(item => item.status !== 'ok');
    if (pending) {
      return { label: 'Com pendências', counts: `${okCount}/${totalCount}`, className: 'bg-status-warning/10 text-status-warning border-status-warning/20' };
    }
    return { label: 'Checklist completo', counts: `${okCount}/${totalCount}`, className: 'bg-status-success/10 text-status-success border-status-success/20' };
  };

